import React, { useRef, useState, useEffect } from 'react';
import { CardData, CardType, Position } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
}

export const Canvas: React.FC<CanvasProps> = ({ cards, onCardsChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);

  // Background pattern calculations
  const patternSize = 40 * scale;
  const dotSize = 2 * scale;

  const handleWheel = (e: WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const s = Math.exp(-e.deltaY * 0.01);
      setScale(prev => Math.min(Math.max(0.1, prev * s), 4));
    } else {
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    // Middle click or Space+Click (simulated here just by clicking background) starts pan
    if (e.button === 0 || e.button === 1) {
      setIsPanning(true);
      setLastMousePos({ x: e.clientX, y: e.clientY });
      setSelectedCardId(null); // Deselect cards
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
    }
  };

  const handleMouseUp = () => {
    setIsPanning(false);
  };

  const updateCardPosition = (id: string, x: number, y: number) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
  };

  const handleDeleteCard = (id: string) => {
    onCardsChange(cards.filter(c => c.id !== id));
    if (selectedCardId === id) {
      setSelectedCardId(null);
    }
  };

  const bringToFront = (id: string) => {
    setSelectedCardId(id);
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  // Keyboard deletion logic
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!selectedCardId) return;

      const target = e.target as HTMLElement;
      // Don't delete if user is typing in an input
      if (
        target.tagName === 'INPUT' || 
        target.tagName === 'TEXTAREA' || 
        target.isContentEditable
      ) {
        return;
      }

      if (e.key === 'Delete' || e.key === 'Backspace') {
        handleDeleteCard(selectedCardId);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardId, cards]);

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardId === card.id,
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      default:
        return <PostCard {...commonProps} />;
    }
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#f3f4f6] relative overflow-hidden cursor-grab active:cursor-grabbing"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* Dot Grid Background */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-20"
        style={{
          backgroundImage: `radial-gradient(#9ca3af ${dotSize}px, transparent 0)`,
          backgroundSize: `${patternSize}px ${patternSize}px`,
          backgroundPosition: `${pan.x}px ${pan.y}px`,
        }}
      />

      {/* World Transform Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
        }}
      >
        {cards.map(renderCard)}
      </div>

      {/* Scale Indicator */}
      <div className="absolute bottom-6 right-6 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-mono border border-gray-200 shadow-sm pointer-events-none">
        {Math.round(scale * 100)}%
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CardData } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title: string;
  accentColor?: string;
  icon?: React.ReactNode;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, // Not used here anymore, but kept for interface compatibility if passed
  zoomScale,
  children,
  title,
  icon
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isFullscreen) return; // Disable dragging in fullscreen
    e.stopPropagation();
    onSelect(card.id);
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX, y: e.clientY };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale]);

  // Fullscreen logic
  useEffect(() => {
    const handleFullscreenChange = () => {
      const isFs = document.fullscreenElement === containerRef.current;
      setIsFullscreen(isFs);
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!document.fullscreenElement && containerRef.current) {
      containerRef.current.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
    } else if (document.fullscreenElement) {
      document.exitFullscreen();
    }
  };

  return (
    <div
      ref={containerRef}
      className={`absolute flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] ${
        isFullscreen 
          ? 'fixed inset-0 z-[9999] w-full h-full rounded-none' 
          : `${isSelected ? 'shadow-[0_20px_40px_-12px_rgba(0,0,0,0.12)] z-50 scale-[1.005]' : 'shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)]'}`
      }`}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        minHeight: card.height,
        borderRadius: '24px',
      } : {}}
      onClick={(e) => {
