import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { CardData } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title: string;
  accentColor?: string;
  icon?: React.ReactNode;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, 
  zoomScale,
  children,
  title,
  icon
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isFullscreen) return; // Disable dragging in fullscreen
    e.stopPropagation();
    onSelect(card.id);
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX, y: e.clientY };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale]);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFullscreen(!isFullscreen);
  };

  // The card content component
  const cardContent = (
    <div
      ref={containerRef}
      className={`flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] ${
        isFullscreen 
          ? 'fixed inset-0 z-[9999] w-full h-full rounded-none' 
          : `absolute ${isSelected ? 'shadow-[0_20px_40px_-12px_rgba(0,0,0,0.12)] z-50 scale-[1.005]' : 'shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)]'}`
      }`}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        minHeight: card.height,
        borderRadius: '24px',
      } : {}}
      onClick={(e) => {
        e.stopPropagation();
        onSelect(card.id);
      }}
    >
      {/* Header - Native iOS feel */}
      <div 
        className={`flex items-center justify-between px-5 pt-5 pb-2 ${!isFullscreen ? 'cursor-grab active:cursor-grabbing' : ''} rounded-t-[24px]`}
        onMouseDown={handleMouseDown}
      >
        <div className="flex items-center gap-2.5 text-gray-900 select-none">
          {/* Icons are subtle, secondary indicators */}
          <span className="text-gray-400">{icon}</span>
          {/* Title is bold but small, system font */}
          <span className="text-[13px] font-semibold tracking-tight text-gray-500">{title}</span>
        </div>

        {/* Fullscreen Toggle Button */}
        <button 
          onClick={toggleFullscreen} 
          className="w-6 h-6 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:bg-gray-200 hover:text-gray-600 transition-colors"
        >
          {isFullscreen ? <Minimize2 size={14} /> : <Maximize2 size={14} />}
        </button>
      </div>

      {/* Content Area */}
      <div className={`flex-1 px-5 pb-5 ${isFullscreen ? 'overflow-y-auto' : 'overflow-visible'}`}>
        {children}
      </div>
    </div>
  );

  // If fullscreen, render into document.body to break out of the Canvas transform context
  if (isFullscreen) {
    return createPortal(cardContent, document.body);
  }

  return cardContent;
};

