                 {comments.length > 0 && (
                   <span className="absolute top-1.5 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
                 )}
               </button>
             ) : (
               <button 
                onClick={(e) => { e.stopPropagation(); setViewMode('edit'); }}
                className="px-4 py-2 rounded-full text-[13px] font-medium bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center gap-2"
               >
                 <Pencil size={14} />
                 Edit Content
               </button>
             )}
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

