export const PostCard: React.FC<PostCardProps> = (props) => {
  const { card } = props;
  const [sku] = useState(card.content?.sku || `P-${Math.random().toString(36).substr(2, 4).toUpperCase()}`);
  const [viewMode, setViewMode] = useState<'edit' | 'comments'>('edit');
  const [title, setTitle] = useState(card.content?.title || "Untitled Post");
  const [date, setDate] = useState(card.content?.date || "");
  const [caption, setCaption] = useState(card.content?.caption || "");

  const [references, setReferences] = useState<MediaItem[]>(card.content?.references || [{ id: '1', type: 'empty' }, { id: '2', type: 'empty' }]);
  const [finalAssets, setFinalAssets] = useState<MediaItem[]>(card.content?.finalAssets || [{ id: '1', type: 'empty' }]);

  const [taskLists, setTaskLists] = useState<TaskList[]>(card.content?.taskLists || [
    { id: 'l1', title: 'Production', color: 'yellow', items: [{ id: 't1', text: 'Briefing', done: true }, { id: 't2', text: 'Copywriting', done: false }] }
  ]);

  const [comments, setComments] = useState<Comment[]>(card.content?.comments || []);
  const [newComment, setNewComment] = useState("");

  const addTaskList = () => {
    const newList: TaskList = { id: Date.now().toString(), title: 'New List', color: 'gray', items: [] };
    setTaskLists([...taskLists, newList]);
  };

  const handlePostComment = () => {
    if (!newComment.trim()) return;
    const c: Comment = { id: Date.now().toString(), user: 'You', avatar: 'ME', text: newComment, timestamp: 'Just now' };
    setComments([...comments, c]);
    setNewComment("");
  };

  return (
    <BaseCard 
      {...props} 
      title={sku} // Minimal SKU title
      icon={<FileImage size={16} className="text-gray-400"/>} 
    >
      <div className="flex flex-col h-full">
        {viewMode === 'edit' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 ease-out">

            {/* Title Block */}
            <div className="space-y-1">
              <input 
                className="w-full font-bold text-[28px] leading-tight text-gray-900 bg-transparent border-none focus:ring-0 p-0 placeholder-gray-300" 
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="Post Title"
                onClick={(e) => e.stopPropagation()} 
              />
              <input 
                type="date" 
                className="text-[13px] font-medium text-gray-500 bg-transparent border-none p-0 focus:ring-0"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                onClick={(e) => e.stopPropagation()}
              />
            </div>

            {/* References */}
            <div>
              <div className="flex items-center justify-between mb-3">
                <span className="text-[13px] font-semibold text-gray-400">References</span>
                <button onClick={(e) => { e.stopPropagation(); setReferences([...references, { id: Date.now().toString(), type: 'empty' }]); }} className="text-[#007AFF] hover:bg-blue-50 p-1 rounded-full"><Plus size={16}/></button>
              </div>
              <div className="grid grid-cols-4 gap-3">
                {references.map((item, i) => (
                  <MediaCube 
                    key={item.id} 
                    item={item} 
                    index={i} 
                    onRemove={() => setReferences(references.filter(r => r.id !== item.id))}
                    onUpdate={(updated) => setReferences(references.map(r => r.id === item.id ? updated : r))}
                  />
                ))}
              </div>
            </div>

            {/* Caption */}
            <div>
               <span className="text-[13px] font-semibold text-gray-400 mb-2 block">Caption</span>
               <textarea 
                className="w-full text-[15px] leading-relaxed text-gray-900 bg-transparent border-none p-0 resize-none focus:ring-0 placeholder-gray-300"
                rows={4}
                placeholder="Type caption here..."
                value={caption}
                onChange={(e) => setCaption(e.target.value)}
                onClick={(e) => e.stopPropagation()}
              />
            </div>

            {/* Checklists */}
            <div>
               {taskLists.map(list => (
                  <TaskListBlock 
                    key={list.id} 
                    list={list} 
                    onUpdate={(updated) => setTaskLists(taskLists.map(l => l.id === list.id ? updated : l))}
                    onDelete={() => setTaskLists(taskLists.filter(l => l.id !== list.id))}
                  />
                ))}
               <button 
                 onClick={(e) => { e.stopPropagation(); addTaskList(); }}
                 className="flex items-center gap-2 text-[15px] text-gray-400 hover:text-[#007AFF] transition-colors mt-2"
               >
                 <Plus size={16} /> Add Checklist
               </button>
            </div>

            {/* Final Assets */}
            <div className="pt-4 border-t border-gray-100">
              <span className="text-[13px] font-semibold text-gray-400 mb-3 block">Final Assets</span>
              <div className="grid grid-cols-4 gap-3">
                {finalAssets.map((item, i) => (
                  <MediaCube 
                    key={item.id} 
                    item={item} 
                    index={i} 
                    onRemove={() => setFinalAssets(finalAssets.filter(r => r.id !== item.id))}
                    onUpdate={(updated) => setFinalAssets(finalAssets.map(r => r.id === item.id ? updated : r))}
                  />
                ))}
                {finalAssets.length < 4 && (
                   <button 
                    onClick={(e) => { e.stopPropagation(); setFinalAssets([...finalAssets, { id: Date.now().toString(), type: 'empty' }]); }}
                    className="aspect-square rounded-xl border border-dashed border-gray-300 flex items-center justify-center text-gray-400 hover:border-[#007AFF] hover:text-[#007AFF] transition-colors"
                   >
                     <Plus size={20} />
                   </button>
                )}
              </div>
            </div>
          </div>
        )}

        {viewMode === 'comments' && (
          <div className="flex flex-col h-[400px] animate-in slide-in-from-right-8 duration-300 ease-out">
             <div className="flex-1 overflow-y-auto space-y-4 p-1">
                {comments.length === 0 && (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400">
                    <MessageSquare size={32} className="mb-3 opacity-20"/>
                    <p className="text-[15px] font-medium text-gray-400">No comments</p>
                  </div>
                )}
                {comments.map(c => (
                  <div key={c.id} className="flex gap-3 text-[15px]">
                    <div className="w-8 h-8 rounded-full bg-gray-200 text-gray-500 text-xs flex items-center justify-center font-bold flex-shrink-0">
                      {c.avatar}
                    </div>
                    <div>
                      <div className="flex items-baseline gap-2 mb-0.5">
                        <span className="font-semibold text-gray-900">{c.user}</span>
                        <span className="text-[13px] text-gray-400">{c.timestamp}</span>
                      </div>
                      <p className="text-gray-700 leading-normal">{c.text}</p>
                    </div>
                  </div>
                ))}
             </div>
             <div className="pt-4 mt-auto border-t border-gray-100 flex gap-3 items-center">
                <input 
                  className="flex-1 bg-[#F2F2F7] rounded-full px-4 py-2.5 text-[15px] focus:ring-0 border-none placeholder-gray-400"
                  placeholder="Add a comment..."
                  value={newComment}
                  onChange={(e) => setNewComment(e.target.value)}
                  onKeyDown={(e) => { if(e.key === 'Enter') handlePostComment(); }}
                  onClick={(e) => e.stopPropagation()}
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); handlePostComment(); }}
                  className="w-9 h-9 rounded-full bg-[#007AFF] text-white flex items-center justify-center hover:bg-[#0071E3] active:scale-95 transition-all"
                >
                  <Send size={16} />
                </button>
             </div>
          </div>
        )}

        {/* Action Bar - iOS Tab Bar feel */}
        <div className="mt-8 pt-4 border-t border-gray-100 flex items-center justify-between">
          <div className="flex items-center -space-x-2 pl-2">
             <div className="w-8 h-8 rounded-full bg-gray-200 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">JD</div>
             <div className="w-8 h-8 rounded-full bg-gray-300 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">SS</div>
             <button className="w-8 h-8 rounded-full bg-[#F2F2F7] border-2 border-white flex items-center justify-center text-gray-400 hover:bg-gray-200">
               <UserPlus size={14} />
             </button>
          </div>

          <div>
             {viewMode === 'edit' ? (
               <button 
                onClick={(e) => { e.stopPropagation(); setViewMode('comments'); }}
                className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center relative"
               >
                 <MessageSquare size={18} />
                 {comments.length > 0 && (
                   <span className="absolute top-1.5 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
                 )}
               </button>
             ) : (
               <button 
                onClick={(e) => { e.stopPropagation(); setViewMode('edit'); }}
                className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center"
               >
                 <Pencil size={18} />
               </button>
             )}
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

export enum CardType {
  POST = 'POST',
  STRATEGY_AI = 'STRATEGY_AI',
  ANALYTICS = 'ANALYTICS',
  PERSONA = 'PERSONA'
}

export interface Position {
  x: number;
  y: number;
}

export interface TaskItem {
  id: string;
  text: string;
  done: boolean;
}

export interface TaskList {
  id: string;
  title: string;
  color: 'yellow' | 'blue' | 'red' | 'green' | 'gray';
  items: TaskItem[];
}

export interface MediaItem {
  id: string;
  type: 'image' | 'link' | 'video' | 'empty';
  url?: string;
  thumbnail?: string;
}

export interface Comment {
  id: string;
  user: string;
  avatar: string; // Initials
  text: string;
  timestamp: string;
}

export interface PostCardContent {
  sku?: string;
  title?: string;
  date?: string;
  caption?: string;
  references?: MediaItem[];
  finalAssets?: MediaItem[];
  taskLists?: TaskList[];
  comments?: Comment[];
  assignees?: string[];
}

export interface CardData {
  id: string;
  type: CardType;
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex: number;
  // Generic data bucket, type-casted in components based on CardType
  content: PostCardContent | any;
}

export interface Workspace {
  id: string;
  name: string;
  cards: CardData[];
  color?: string; // Hex color for the tab
}

export interface AppState {
  workspaces: Workspace[];
  activeWorkspaceId: string;
  scale: number;
  pan: Position;
}

import React, { useState, useRef, useEffect } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Layout,
  ChevronDown,
  Check
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'Summer Campaign',
    color: '#007AFF',
    cards: [
      { id: 'card-post-1', type: CardType.POST, x: 400, y: 150, width: 360, height: 400, zIndex: 1, content: { title: 'Launch Teaser', date: '2024-06-01' } },
      { id: 'card-ai-1', type: CardType.STRATEGY_AI, x: 820, y: 150, width: 340, height: 300, zIndex: 2, content: {} }
    ]
  },
  {
    id: 'ws-2',
    name: 'Evergreen Content',
    color: '#34C759',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [showColorPicker, setShowColorPicker] = useState<string | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setShowColorPicker(null);
    window.addEventListener('click', handleClickOutside);
    return () => window.removeEventListener('click', handleClickOutside);
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
    setShowColorPicker(null);
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : 360,
      height: 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  return (
    <div className="w-full h-screen flex flex-col overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Main Canvas Area */}
      <div className="flex-1 relative overflow-hidden">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />

        {/* Floating Toolbar - Top Center */}
        <div className="absolute top-6 left-1/2 -translate-x-1/2 ios-glass rounded-full px-2 py-1.5 flex items-center gap-1 z-30 shadow-[0_8px_32px_rgba(0,0,0,0.12)]">
          <ToolbarButton 
            icon={<FileImage size={22} strokeWidth={2}/>} 
            label="Post" 
            onClick={() => addCard(CardType.POST)}
            activeColor="text-purple-600 bg-purple-50"
          />
          <ToolbarButton 
            icon={<Sparkles size={22} strokeWidth={2}/>} 
            label="AI" 
            onClick={() => addCard(CardType.STRATEGY_AI)} 
            activeColor="text-indigo-600 bg-indigo-50"
          />
          <ToolbarButton 
            icon={<BarChart2 size={22} strokeWidth={2}/>} 
            label="Data" 
            onClick={() => addCard(CardType.ANALYTICS)}
            activeColor="text-emerald-600 bg-emerald-50"
          />
          <div className="w-px h-5 bg-gray-300 mx-1"></div>
          <div className="px-3 flex items-center gap-2 text-sm font-semibold text-gray-500">
             <Layout size={16} />
             <span>Orbit</span>
          </div>
        </div>
      </div>

      {/* Bottom Spreadsheet Navigation */}
      <div className="h-[48px] bg-white border-t border-gray-200 shadow-[0_-4px_20px_rgba(0,0,0,0.05)] z-40 flex items-center px-2 relative">
        <div className="flex items-end gap-1 overflow-x-auto no-scrollbar h-full w-full pt-1">
          {workspaces.map(ws => {
            const isActive = activeWorkspaceId === ws.id;
            return (
              <div key={ws.id} className="relative group">
                <button
                  onClick={() => setActiveWorkspaceId(ws.id)}
                  className={`
                    relative h-9 px-4 min-w-[120px] max-w-[200px] flex items-center gap-2 rounded-t-lg transition-all duration-200 select-none
                    ${isActive 
                      ? 'bg-[#F2F2F7] text-gray-900 font-medium' 
                      : 'bg-transparent text-gray-500 hover:bg-gray-50 hover:text-gray-700'
                    }
                  `}
                >
                  <div 
                    className="w-2.5 h-2.5 rounded-full shadow-sm"
                    style={{ backgroundColor: ws.color || '#8E8E93' }}
                  />
                  <span className="truncate text-[13px]">{ws.name}</span>

                  {isActive && (
                    <div 
                      onClick={(e) => {
                        e.stopPropagation();
                        setShowColorPicker(showColorPicker === ws.id ? null : ws.id);
                      }}
                      className="ml-auto p-0.5 rounded-md hover:bg-black/5 text-gray-400 cursor-pointer"
                    >
                      <ChevronDown size={12} />
                    </div>
                  )}
                </button>

                {/* Active Indicator Line */}
                {isActive && (
                  <div 
                    className="absolute bottom-0 left-0 right-0 h-[3px] rounded-t-full" 
                    style={{ backgroundColor: ws.color || '#007AFF' }}
                  />
                )}

                {/* Color Picker Popover */}
                {showColorPicker === ws.id && (
                  <div 
                    onClick={(e) => e.stopPropagation()}
                    className="absolute bottom-12 left-0 bg-white/90 backdrop-blur-xl border border-white/20 p-2 rounded-xl shadow-[0_10px_40px_-10px_rgba(0,0,0,0.2)] grid grid-cols-4 gap-2 w-32 animate-in fade-in slide-in-from-bottom-2 duration-200"
                  >
                    {TAB_COLORS.map(c => (
                      <button
                        key={c}
                        onClick={() => updateWorkspaceColor(ws.id, c)}
                        className="w-6 h-6 rounded-full border border-black/5 flex items-center justify-center transition-transform hover:scale-110 active:scale-95"
                        style={{ backgroundColor: c }}
                      >
                        {ws.color === c && <Check size={12} className="text-white drop-shadow-md" />}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}

          <button 
            onClick={addWorkspace}
            className="h-8 w-8 ml-1 mb-1 rounded-full flex items-center justify-center text-gray-400 hover:bg-gray-100 hover:text-[#007AFF] transition-colors"
          >
            <Plus size={20} />
          </button>
        </div>
      </div>
    </div>
  );
}

const ToolbarButton = ({ icon, label, onClick, activeColor }: { icon: React.ReactNode, label: string, onClick: () => void, activeColor: string }) => (
  <button 
    onClick={onClick}
    className="group relative w-12 h-12 rounded-full flex items-center justify-center text-gray-500 hover:bg-black/5 transition-all duration-200 active:scale-90"
  >
    {icon}
    {/* Tooltip */}
    <span className="absolute -bottom-9 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur text-black/80 text-[11px] font-medium py-1 px-2.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none shadow-sm border border-black/5">
      {label}
    </span>
  </button>
);

