import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { CardData, CardType } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title: string;
  accentColor?: string;
  icon?: React.ReactNode;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, 
  zoomScale,
  children,
  title,
  icon
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isFullscreen) return; // Disable dragging in fullscreen
    e.stopPropagation();
    onSelect(card.id);
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX, y: e.clientY };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale]);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFullscreen(!isFullscreen);
  };

  const getSelectionStyles = () => {
    if (isFullscreen) return 'fixed inset-0 z-[9999] w-full h-full rounded-none bg-white';

    // Define colors per card type matching the toolbar icons
    const colors = {
      [CardType.POST]: { ring: 'ring-purple-500', hover: 'hover:ring-purple-300' },
      [CardType.STRATEGY_AI]: { ring: 'ring-indigo-500', hover: 'hover:ring-indigo-300' },
      [CardType.ANALYTICS]: { ring: 'ring-emerald-500', hover: 'hover:ring-emerald-300' },
      [CardType.PERSONA]: { ring: 'ring-orange-500', hover: 'hover:ring-orange-300' },
    }[card.type] || { ring: 'ring-gray-400', hover: 'hover:ring-gray-300' };

    const base = "flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)]";

    // Position handling is done via style prop for non-fullscreen, so we just handle class
    const positionClass = isFullscreen ? '' : 'absolute';

    if (isSelected) {
      // Selected: Strong shadow, scale up slightly, specific colored ring
      return `${base} ${positionClass} shadow-[0_20px_40px_-12px_rgba(0,0,0,0.12)] z-50 scale-[1.005] ring-2 ring-offset-0 ${colors.ring}`;
    } else {
      // Idle: Standard shadow. Hover: Lift shadow, light colored ring hint
      return `${base} ${positionClass} shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)] hover:ring-2 hover:ring-offset-0 ${colors.hover}`;
    }
  };

  // The card content component
  const cardContent = (
    <div
      ref={containerRef}
      className={getSelectionStyles()}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        minHeight: card.height,
        borderRadius: '24px',
      } : {}}
      onClick={(e) => {
        e.stopPropagation();
        onSelect(card.id);
      }}
    >
      {/* Header - Native iOS feel */}
      <div 
        className={`flex items-center justify-between px-5 pt-5 pb-2 ${!isFullscreen ? 'cursor-grab active:cursor-grabbing' : ''} rounded-t-[24px]`}
        onMouseDown={handleMouseDown}
      >
        <div className="flex items-center gap-2.5 text-gray-900 select-none">
          {/* Icons are subtle, secondary indicators */}
          <span className="text-gray-400">{icon}</span>
          {/* Title is bold but small, system font */}
          <span className="text-[13px] font-semibold tracking-tight text-gray-500">{title}</span>
        </div>

        {/* Fullscreen Toggle Button */}
        <button 
          onClick={toggleFullscreen} 
          className="w-6 h-6 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:bg-gray-200 hover:text-gray-600 transition-colors"
        >
          {isFullscreen ? <Minimize2 size={14} /> : <Maximize2 size={14} />}
        </button>
      </div>

      {/* Content Area */}
      <div className={`flex-1 px-5 pb-5 ${isFullscreen ? 'overflow-y-auto' : 'overflow-visible'}`}>
        {children}
      </div>
    </div>
  );

  // If fullscreen, render into document.body to break out of the Canvas transform context
  if (isFullscreen) {
    return createPortal(cardContent, document.body);
  }

  return cardContent;
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { CardData, CardType } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title: string;
  accentColor?: string;
  icon?: React.ReactNode;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, 
  zoomScale,
  children,
  title,
  icon
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isFullscreen) return;

    // IMPORTANT: Stop propagation to ensure the Canvas doesn't receive this event.
    // This prevents the "whole board dragging" issue when interacting with a card.
    e.stopPropagation();

    // Select the card immediately on click
    onSelect(card.id);

    const target = e.target as HTMLElement;

    // Check if the user is interacting with inputs, buttons, or scrollbars
    // If so, we do NOT want to initiate a drag operation.
    const isInteractive = 
      target.tagName === 'INPUT' || 
      target.tagName === 'TEXTAREA' || 
      target.tagName === 'BUTTON' || 
      target.closest('button') ||
      target.closest('.no-drag'); // Class to manually opt-out of dragging

    if (!isInteractive) {
      setIsDragging(true);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    }
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale]);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFullscreen(!isFullscreen);
  };

  const getSelectionStyles = () => {
    if (isFullscreen) return 'fixed inset-0 z-[9999] w-full h-full rounded-none bg-white overflow-auto';

    const colors = {
      [CardType.POST]: { ring: 'ring-purple-500', hover: 'hover:ring-purple-300' },
      [CardType.STRATEGY_AI]: { ring: 'ring-indigo-500', hover: 'hover:ring-indigo-300' },
      [CardType.ANALYTICS]: { ring: 'ring-emerald-500', hover: 'hover:ring-emerald-300' },
      [CardType.PERSONA]: { ring: 'ring-orange-500', hover: 'hover:ring-orange-300' },
    }[card.type] || { ring: 'ring-gray-400', hover: 'hover:ring-gray-300' };

    // Added 'cursor-grab active:cursor-grabbing' to give visual feedback that the whole card is draggable
    const base = "flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] cursor-grab active:cursor-grabbing";

    const positionClass = isFullscreen ? '' : 'absolute';

    if (isSelected) {
      return `${base} ${positionClass} shadow-[0_20px_40px_-12px_rgba(0,0,0,0.12)] z-50 scale-[1.005] ring-2 ring-offset-0 ${colors.ring}`;
    } else {
      return `${base} ${positionClass} shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)] hover:ring-2 hover:ring-offset-0 ${colors.hover}`;
    }
  };

  const cardContent = (
    <div
      ref={containerRef}
      className={getSelectionStyles()}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        minHeight: card.height,
        borderRadius: '24px',
      } : {}}
      onMouseDown={handleMouseDown} // Drag handler is now on the main container
      onClick={(e) => {
        e.stopPropagation();
        // Selection is also handled in onMouseDown, but keeping this ensures click-to-focus works even if logic changes
      }}
    >
      {/* Header - Native iOS feel */}
      <div 
        className={`flex items-center justify-between px-5 pt-5 pb-2 rounded-t-[24px] select-none`}
      >
        <div className="flex items-center gap-2.5 text-gray-900">
          <span className="text-gray-400">{icon}</span>
          <span className="text-[13px] font-semibold tracking-tight text-gray-500">{title}</span>
        </div>

        <button 
          onClick={toggleFullscreen} 
          className="w-6 h-6 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:bg-gray-200 hover:text-gray-600 transition-colors"
        >
          {isFullscreen ? <Minimize2 size={14} /> : <Maximize2 size={14} />}
        </button>
      </div>

      {/* Content Area */}
      <div className={`flex-1 px-5 pb-5 ${isFullscreen ? 'overflow-y-auto' : 'overflow-visible'}`}>
        {children}
      </div>
    </div>
  );

  if (isFullscreen) {
    return createPortal(cardContent, document.body);
  }

  return cardContent;
};

import React, { useState, useRef, useEffect } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Layout,
  ChevronDown,
  Check
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'Summer Campaign',
    color: '#007AFF',
    cards: [
      { id: 'card-post-1', type: CardType.POST, x: 400, y: 150, width: 360, height: 400, zIndex: 1, content: { title: 'Launch Teaser', date: '2024-06-01' } },
      { id: 'card-ai-1', type: CardType.STRATEGY_AI, x: 820, y: 150, width: 340, height: 300, zIndex: 2, content: {} }
    ]
  },
  {
    id: 'ws-2',
    name: 'Evergreen Content',
    color: '#34C759',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      // Position: centered horizontally relative to button, above the button
      setColorPickerState({
        id,
        x: rect.left + rect.width / 2,
        y: rect.top
      });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : 360,
      height: 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  const tools = [
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create content for Instagram/LinkedIn', 
      icon: <FileImage size={20} />, 
      color: 'bg-purple-500',
      action: () => addCard(CardType.POST)
    },
    { 
      id: 'ai', 
      label: 'Strategy Oracle', 
      desc: 'Generate campaign angles with AI', 
      icon: <Sparkles size={20} />, 
      color: 'bg-indigo-500',
      action: () => addCard(CardType.STRATEGY_AI)
    },
    { 
      id: 'analytics', 
      label: 'Analytics', 
      desc: 'Visualize live performance data', 
      icon: <BarChart2 size={20} />, 
      color: 'bg-emerald-500',
      action: () => addCard(CardType.ANALYTICS)
    },
    { 
      id: 'persona', 
      label: 'Persona', 
      desc: 'Target audience profile card', 
      icon: <Users size={20} />, 
      color: 'bg-orange-500',
      action: () => addCard(CardType.PERSONA)
    }
  ];

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Main Canvas Area - Full Screen Overlay */}
      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />
      </div>

      {/* Side Drawer / Floating Button */}
      <div 
        className={`fixed top-0 left-0 h-full z-50 flex flex-col transition-all duration-500 ease-[cubic-bezier(0.32,0.72,0,1)] ${isDrawerOpen ? 'w-80 pointer-events-auto' : 'w-24 pointer-events-none'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
        onMouseLeave={() => setIsDrawerOpen(false)}
      >
        {/* Invisible Hover Zone on the edge when closed */}
        {!isDrawerOpen && <div className="absolute inset-y-0 left-0 w-6 pointer-events-auto" />}

        {/* The Drawer Background */}
        <div className={`absolute inset-0 bg-white/80 backdrop-blur-2xl border-r border-white/50 shadow-[4px_0_24px_rgba(0,0,0,0.04)] transition-opacity duration-300 ${isDrawerOpen ? 'opacity-100' : 'opacity-0'}`} />

        {/* Floating Button / Header */}
        <div className="relative z-10 p-6 pointer-events-auto">
          <button 
            className={`w-12 h-12 rounded-full bg-white shadow-lg flex items-center justify-center text-gray-700 transition-all duration-300 ${isDrawerOpen ? 'bg-transparent shadow-none -ml-2' : 'hover:scale-110'}`}
          >
             <div className={`w-10 h-10 rounded-xl bg-gray-900 text-white flex items-center justify-center shadow-lg transition-transform duration-500 ${isDrawerOpen ? 'rotate-90' : 'rotate-0'}`}>
                <Layout size={20} strokeWidth={2.5} />
             </div>
          </button>
        </div>

        {/* Menu Content */}
        <div className={`relative z-10 flex-1 px-6 pb-6 overflow-y-auto transition-all duration-300 ${isDrawerOpen ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-4'}`}>

            <div className="mb-8 ml-2">
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight mb-1">Tools</h2>
              <p className="text-sm text-gray-500 font-medium">Drag or click to add</p>
            </div>

            <div className="space-y-3">
              {tools.map((tool, idx) => (
                <button
                  key={tool.id}
                  onClick={() => { tool.action(); }}
                  className="w-full group flex items-start gap-4 p-4 rounded-2xl bg-white/50 hover:bg-white border border-transparent hover:border-black/5 hover:shadow-lg hover:-translate-y-0.5 transition-all duration-200 text-left"
                  style={{ transitionDelay: `${idx * 50}ms` }}
                >
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white shadow-md flex-shrink-0 ${tool.color} group-hover:scale-110 transition-transform duration-300`}>
                    {tool.icon}
                  </div>
                  <div>
                    <div className="font-bold text-gray-900 text-[15px] leading-tight mb-0.5">{tool.label}</div>
                    <p className="text-[13px] text-gray-500 leading-snug">{tool.desc}</p>
                  </div>
                </button>
              ))}
            </div>
        </div>
      </div>

      {/* Bottom Spreadsheet Navigation (Floating Overlay) */}
      <div className="absolute bottom-0 left-0 right-0 z-40 flex items-end px-6 pb-6 pointer-events-none">
        <div className="flex items-center gap-3 overflow-visible w-full pointer-events-auto overflow-x-auto no-scrollbar pb-1 px-1">
          {workspaces.map(ws => {
            const isActive = activeWorkspaceId === ws.id;
            return (
              <div key={ws.id} className="relative group flex-shrink-0">
                <button
                  onClick={() => setActiveWorkspaceId(ws.id)}
                  className={`
                    relative h-11 px-5 min-w-[140px] max-w-[220px] flex items-center gap-3 rounded-2xl transition-all duration-300 select-none
                    ${isActive 
                      ? 'bg-white text-gray-900 font-bold shadow-xl scale-100 ring-1 ring-black/5' 
                      : 'bg-white/80 backdrop-blur-md text-gray-500 hover:text-gray-900 shadow-sm hover:shadow-md hover:-translate-y-0.5 scale-[0.98]'
                    }
                  `}
                >
                  <div 
                    className={`w-3 h-3 rounded-full shadow-sm transition-transform duration-300 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`}
                    style={{ backgroundColor: ws.color || '#8E8E93' }}
                  />
                  <span className="truncate text-[14px] tracking-tight">{ws.name}</span>

                  {isActive && (
                    <div 
                      onClick={(e) => toggleColorPicker(e, ws.id)}
                      className="ml-auto p-1.5 -mr-1 rounded-full hover:bg-black/10 text-gray-400 cursor-pointer transition-colors"
                    >
                      <ChevronDown size={12} strokeWidth={3} />
                    </div>
                  )}
                </button>
              </div>
            );
          })}

          <button 
            onClick={addWorkspace}
            className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-white/80 backdrop-blur-md shadow-lg flex items-center justify-center text-gray-400 hover:text-[#007AFF] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"
          >
            <Plus size={22} strokeWidth={2.5} />
          </button>
        </div>
      </div>

      {/* Fixed Color Picker Menu */}
      {colorPickerState && (
        <div 
          onClick={(e) => e.stopPropagation()}
          className="fixed bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] grid grid-cols-4 gap-2 w-36 animate-in fade-in zoom-in-95 duration-200 z-[100]"
          style={{
            left: colorPickerState.x,
            top: colorPickerState.y - 12,
            transform: 'translate(-50%, -100%)' // Center horizontally, place above
          }}
        >
          {TAB_COLORS.map(c => (
            <button
              key={c}
              onClick={() => updateWorkspaceColor(colorPickerState.id, c)}
              className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5"
              style={{ backgroundColor: c }}
            >
              {workspaces.find(w => w.id === colorPickerState.id)?.color === c && (
                <Check size={12} className="text-white drop-shadow-md" />
              )}
            </button>
          ))}
          <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white/80 backdrop-blur-xl border-r border-b border-white/40 rotate-45 transform"></div>
        </div>
      )}
    </div>
  );
}

