const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      // Position: centered horizontally relative to button, above the button
      setColorPickerState({
        id,
        x: rect.left + rect.width / 2,
        y: rect.top
      });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : 360,
      height: 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  const tools = [
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create content for Instagram/LinkedIn', 
      icon: <FileImage size={20} />, 
      color: 'bg-purple-500',
      action: () => addCard(CardType.POST)
    },
    { 
      id: 'ai', 
      label: 'Strategy Oracle', 
      desc: 'Generate campaign angles with AI', 
      icon: <Sparkles size={20} />, 
      color: 'bg-indigo-500',
      action: () => addCard(CardType.STRATEGY_AI)
    },
    { 
      id: 'analytics', 
      label: 'Analytics', 
      desc: 'Visualize live performance data', 
      icon: <BarChart2 size={20} />, 
      color: 'bg-emerald-500',
      action: () => addCard(CardType.ANALYTICS)
    },
    { 
      id: 'persona', 
      label: 'Persona', 
      desc: 'Target audience profile card', 
      icon: <Users size={20} />, 
      color: 'bg-orange-500',
      action: () => addCard(CardType.PERSONA)
    }
  ];

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Main Canvas Area - Full Screen Overlay */}
      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />
      </div>

      {/* Side Drawer / Floating Button */}
      <div 
        className={`fixed top-0 left-0 h-full z-50 flex flex-col transition-all duration-500 ease-[cubic-bezier(0.32,0.72,0,1)] ${isDrawerOpen ? 'w-80 pointer-events-auto' : 'w-24 pointer-events-none'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
        onMouseLeave={() => setIsDrawerOpen(false)}
      >
        {/* Invisible Hover Zone on the edge when closed */}
        {!isDrawerOpen && <div className="absolute inset-y-0 left-0 w-6 pointer-events-auto" />}

        {/* The Drawer Background */}
        <div className={`absolute inset-0 bg-white/80 backdrop-blur-2xl border-r border-white/50 shadow-[4px_0_24px_rgba(0,0,0,0.04)] transition-opacity duration-300 ${isDrawerOpen ? 'opacity-100' : 'opacity-0'}`} />

        {/* Floating Button / Header */}
        <div className="relative z-10 p-6 pointer-events-auto">
          <button 
            className={`
              w-14 h-14 rounded-full flex items-center justify-center text-white shadow-[0_8px_40px_-10px_rgba(100,50,255,0.4)]
              transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)]
              bg-gradient-to-tr from-blue-600 via-purple-600 to-pink-500
              ${isDrawerOpen ? 'rotate-45 scale-90' : 'hover:scale-110 hover:rotate-90'}
            `}
          >
             <Plus size={32} strokeWidth={3} />
          </button>
        </div>

        {/* Menu Content */}
        <div className={`relative z-10 flex-1 px-6 pb-6 overflow-y-auto transition-all duration-300 ${isDrawerOpen ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-4'}`}>

            <div className="mb-8 ml-2">
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight mb-1">Tools</h2>
              <p className="text-sm text-gray-500 font-medium">Drag or click to add</p>
            </div>

            <div className="space-y-3">
              {tools.map((tool, idx) => (
                <button
                  key={tool.id}
                  onClick={() => { tool.action(); }}
                  className="w-full group flex items-start gap-4 p-4 rounded-2xl bg-white/50 hover:bg-white border border-transparent hover:border-black/5 hover:shadow-lg hover:-translate-y-0.5 transition-all duration-200 text-left"
                  style={{ transitionDelay: `${idx * 50}ms` }}
                >
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white shadow-md flex-shrink-0 ${tool.color} group-hover:scale-110 transition-transform duration-300`}>
                    {tool.icon}
                  </div>
                  <div>
                    <div className="font-bold text-gray-900 text-[15px] leading-tight mb-0.5">{tool.label}</div>
                    <p className="text-[13px] text-gray-500 leading-snug">{tool.desc}</p>
                  </div>
                </button>
              ))}
            </div>
        </div>
      </div>

      {/* Bottom Spreadsheet Navigation (Floating Overlay) */}
      <div className="absolute bottom-0 left-0 right-0 z-40 flex items-end px-6 pb-6 pointer-events-none">
        <div className="flex items-center gap-3 overflow-visible w-full pointer-events-auto overflow-x-auto no-scrollbar pb-1 px-1">
          {workspaces.map(ws => {
            const isActive = activeWorkspaceId === ws.id;
            return (
              <div key={ws.id} className="relative group flex-shrink-0">
                <button
                  onClick={() => setActiveWorkspaceId(ws.id)}
                  className={`
                    relative h-11 px-5 min-w-[140px] max-w-[220px] flex items-center gap-3 rounded-2xl transition-all duration-300 select-none
                    ${isActive 
                      ? 'bg-white text-gray-900 font-bold shadow-xl scale-100 ring-1 ring-black/5' 
                      : 'bg-white/80 backdrop-blur-md text-gray-500 hover:text-gray-900 shadow-sm hover:shadow-md hover:-translate-y-0.5 scale-[0.98]'
                    }
                  `}
                >
                  <div 
                    className={`w-3 h-3 rounded-full shadow-sm transition-transform duration-300 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`}
                    style={{ backgroundColor: ws.color || '#8E8E93' }}
                  />
                  <span className="truncate text-[14px] tracking-tight">{ws.name}</span>

                  {isActive && (
                    <div 
                      onClick={(e) => toggleColorPicker(e, ws.id)}
                      className="ml-auto p-1.5 -mr-1 rounded-full hover:bg-black/10 text-gray-400 cursor-pointer transition-colors"
                    >
                      <ChevronDown size={12} strokeWidth={3} />
                    </div>
                  )}
                </button>
              </div>
            );
          })}

          <button 
            onClick={addWorkspace}
            className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-white/80 backdrop-blur-md shadow-lg flex items-center justify-center text-gray-400 hover:text-[#007AFF] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"
          >
            <Plus size={22} strokeWidth={2.5} />
          </button>
        </div>
      </div>

      {/* Fixed Color Picker Menu */}
      {colorPickerState && (
        <div 
          onClick={(e) => e.stopPropagation()}
          className="fixed bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] grid grid-cols-4 gap-2 w-36 animate-in fade-in zoom-in-95 duration-200 z-[100]"
          style={{
            left: colorPickerState.x,
            top: colorPickerState.y - 12,
            transform: 'translate(-50%, -100%)' // Center horizontally, place above
          }}
        >
          {TAB_COLORS.map(c => (
            <button
              key={c}
              onClick={() => updateWorkspaceColor(colorPickerState.id, c)}
              className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5"
              style={{ backgroundColor: c }}
            >
              {workspaces.find(w => w.id === colorPickerState.id)?.color === c && (
                <Check size={12} className="text-white drop-shadow-md" />
              )}
            </button>
          ))}
          <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white/80 backdrop-blur-xl border-r border-b border-white/40 rotate-45 transform"></div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Search,
  X,
  ChevronDown,
  Check,
  Globe,
  MessageSquare,
  HardDrive
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'Summer Campaign',
    color: '#007AFF',
    cards: [
      { id: 'card-post-1', type: CardType.POST, x: 400, y: 150, width: 360, height: 400, zIndex: 1, content: { title: 'Launch Teaser', date: '2024-06-01' } },
      { id: 'card-ai-1', type: CardType.STRATEGY_AI, x: 820, y: 150, width: 340, height: 300, zIndex: 2, content: {} }
    ]
  },
  {
    id: 'ws-2',
    name: 'Evergreen Content',
    color: '#34C759',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      // Position: centered horizontally relative to button, above the button
      setColorPickerState({
        id,
        x: rect.left + rect.width / 2,
        y: rect.top
      });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : 360,
      height: 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
    // Optionally close drawer after adding
    // setIsDrawerOpen(false);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  // --- Menu Data Configuration ---

  const frequentTools = [
    { 
      id: 'ai', 
      label: 'Ask AI', 
      desc: 'Prompt an AI language model', 
      icon: <Sparkles size={24} />, 
      iconColor: 'text-pink-600',
      bg: 'bg-pink-50',
      action: () => addCard(CardType.STRATEGY_AI)
    },
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create social content', 
      icon: <FileImage size={24} />, 
      iconColor: 'text-purple-600',
      bg: 'bg-purple-50',
      action: () => addCard(CardType.POST)
    },
  ];

  const integrationTools = [
    { 
      id: 'analytics', 
      label: 'Analytics', 
      desc: 'Visualize live performance data', 
      icon: <BarChart2 size={20} />, 
      color: 'bg-emerald-100 text-emerald-600',
      tag: 'DATA',
      action: () => addCard(CardType.ANALYTICS)
    },
    { 
      id: 'persona', 
      label: 'Persona', 
      desc: 'Target audience profile card', 
      icon: <Users size={20} />, 
      color: 'bg-orange-100 text-orange-600',
      tag: 'STRATEGY',
      action: () => addCard(CardType.PERSONA)
    },
    // Mock Integrations for visual completeness
    { id: 'drive', label: 'Google Drive', desc: 'Manage files in Drive', icon: <HardDrive size={20} />, color: 'bg-blue-100 text-blue-600', tag: 'MCP', action: () => {} },
    { id: 'slack', label: 'Slack', desc: 'Send channel messages', icon: <MessageSquare size={20} />, color: 'bg-purple-100 text-purple-600', tag: 'MCP', action: () => {} },
    { id: 'web', label: 'Browser', desc: 'Embed web content', icon: <Globe size={20} />, color: 'bg-gray-100 text-gray-600', tag: 'MCP', action: () => {} },
  ];

  const filterItem = (item: any) => 
    item.label.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.desc.toLowerCase().includes(searchTerm.toLowerCase());

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Main Canvas Area */}
      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />
      </div>

      {/* Floating Trigger Button (Visible when drawer is closed) */}
      <div className={`fixed top-6 left-6 z-40 transition-all duration-300 ${isDrawerOpen ? 'opacity-0 scale-75 pointer-events-none' : 'opacity-100 scale-100'}`}>
        <button 
          onClick={() => setIsDrawerOpen(true)}
          className="w-14 h-14 rounded-full flex items-center justify-center text-white shadow-[0_8px_40px_-10px_rgba(100,50,255,0.4)]
            hover:scale-110 active:scale-95 transition-all duration-300
            bg-gradient-to-tr from-blue-600 via-purple-600 to-pink-500"
        >
            <Plus size={32} strokeWidth={3} />
        </button>
      </div>

      {/* Side Drawer Overlay */}
      <div className={`fixed inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`}>

        {/* Drawer Content */}
        <div className="w-[340px] h-full bg-white shadow-2xl flex flex-col border-r border-gray-200">

          {/* Header & Search */}
          <div className="p-5 border-b border-gray-100 bg-white z-10">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                autoFocus={isDrawerOpen}
                type="text" 
                placeholder="Search all nodes" 
                className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2.5 text-[15px] focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none placeholder-gray-400"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          {/* Scrollable List */}
          <div className="flex-1 overflow-y-auto overflow-x-hidden">
            <div className="p-5 space-y-8">

              {/* Frequently Used Section */}
              {(!searchTerm || frequentTools.some(filterItem)) && (
                <div className="space-y-3">
                  <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Frequently Used</h3>
                  <div className="grid grid-cols-2 gap-3">
                    {frequentTools.filter(filterItem).map(tool => (
                      <button 
                        key={tool.id}
                        onClick={tool.action}
                        className="flex flex-col items-start p-4 rounded-2xl bg-white border border-gray-200 hover:border-gray-300 hover:shadow-md transition-all active:scale-[0.98] text-left group"
                      >
                        <div className={`w-10 h-10 rounded-xl ${tool.bg} ${tool.iconColor} flex items-center justify-center mb-3 group-hover:scale-110 transition-transform`}>
                          {tool.icon}
                        </div>
                        <div className="font-semibold text-gray-900 text-[14px] leading-tight mb-1">{tool.label}</div>
                        <div className="text-[12px] text-gray-500 leading-snug line-clamp-2">{tool.desc}</div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Integrations / All Tools Section */}
              {(!searchTerm || integrationTools.some(filterItem)) && (
                <div className="space-y-3">
                   <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Integrations</h3>
                   <div className="space-y-1">
                      {integrationTools.filter(filterItem).map(tool => (
                        <button
                          key={tool.id}
                          onClick={tool.action}
                          className="w-full flex items-center gap-4 p-3 rounded-xl hover:bg-gray-50 transition-colors group text-left"
                        >
                          <div className={`w-10 h-10 rounded-xl ${tool.color} flex items-center justify-center shadow-sm border border-black/5 flex-shrink-0 group-hover:scale-105 transition-transform`}>
                            {tool.icon}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between mb-0.5">
                               <span className="font-semibold text-gray-900 text-[14px]">{tool.label}</span>
                               {tool.tag && (
                                 <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-md ${tool.tag === 'MCP' ? 'bg-blue-100 text-blue-600' : 'bg-green-100 text-green-600'}`}>
                                   {tool.tag}
                                 </span>
                               )}
                            </div>
                            <p className="text-[13px] text-gray-500 truncate">{tool.desc}</p>
                          </div>
                          <div className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity">
                            <Plus size={16} />
                          </div>
                        </button>
                      ))}
                   </div>
                </div>
              )}

              {searchTerm && !frequentTools.some(filterItem) && !integrationTools.some(filterItem) && (
                <div className="text-center py-10 text-gray-400">
                  <p>No tools found</p>
                </div>
              )}

            </div>
          </div>
        </div>

        {/* External Close Button */}
        <div className="pt-5 pl-4">
          <button 
            onClick={() => setIsDrawerOpen(false)}
            className="w-10 h-10 bg-white rounded-xl shadow-lg border border-gray-100 flex items-center justify-center text-gray-500 hover:text-gray-900 hover:scale-110 active:scale-95 transition-all"
          >
            <X size={20} />
          </button>
        </div>
      </div>


      {/* Bottom Spreadsheet Navigation (Floating Overlay) */}
      <div className="absolute bottom-0 left-0 right-0 z-40 flex items-end px-6 pb-6 pointer-events-none">
        <div className="flex items-center gap-3 overflow-visible w-full pointer-events-auto overflow-x-auto no-scrollbar pb-1 px-1">
          {workspaces.map(ws => {
            const isActive = activeWorkspaceId === ws.id;
            return (
              <div key={ws.id} className="relative group flex-shrink-0">
                <button
                  onClick={() => setActiveWorkspaceId(ws.id)}
                  className={`
                    relative h-11 px-5 min-w-[140px] max-w-[220px] flex items-center gap-3 rounded-2xl transition-all duration-300 select-none
                    ${isActive 
                      ? 'bg-white text-gray-900 font-bold shadow-xl scale-100 ring-1 ring-black/5' 
                      : 'bg-white/80 backdrop-blur-md text-gray-500 hover:text-gray-900 shadow-sm hover:shadow-md hover:-translate-y-0.5 scale-[0.98]'
                    }
                  `}
                >
                  <div 
                    className={`w-3 h-3 rounded-full shadow-sm transition-transform duration-300 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`}
                    style={{ backgroundColor: ws.color || '#8E8E93' }}
                  />
                  <span className="truncate text-[14px] tracking-tight">{ws.name}</span>

                  {isActive && (
                    <div 
                      onClick={(e) => toggleColorPicker(e, ws.id)}
                      className="ml-auto p-1.5 -mr-1 rounded-full hover:bg-black/10 text-gray-400 cursor-pointer transition-colors"
                    >
                      <ChevronDown size={12} strokeWidth={3} />
                    </div>
                  )}
                </button>
              </div>
            );
          })}

          <button 
            onClick={addWorkspace}
            className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-white/80 backdrop-blur-md shadow-lg flex items-center justify-center text-gray-400 hover:text-[#007AFF] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"
          >
            <Plus size={22} strokeWidth={2.5} />
          </button>
        </div>
      </div>

      {/* Fixed Color Picker Menu */}
      {colorPickerState && (
        <div 
          onClick={(e) => e.stopPropagation()}
          className="fixed bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] grid grid-cols-4 gap-2 w-36 animate-in fade-in zoom-in-95 duration-200 z-[100]"
          style={{
            left: colorPickerState.x,
            top: colorPickerState.y - 12,
            transform: 'translate(-50%, -100%)' // Center horizontally, place above
          }}
        >
          {TAB_COLORS.map(c => (
            <button
              key={c}
