    { id: 'drive', label: 'Google Drive', desc: 'Manage files in Drive', icon: <HardDrive size={20} />, color: 'bg-blue-100 text-blue-600', tag: 'MCP', action: () => {} },
    { id: 'slack', label: 'Slack', desc: 'Send channel messages', icon: <MessageSquare size={20} />, color: 'bg-purple-100 text-purple-600', tag: 'MCP', action: () => {} },
    { id: 'web', label: 'Browser', desc: 'Embed web content', icon: <Globe size={20} />, color: 'bg-gray-100 text-gray-600', tag: 'MCP', action: () => {} },
