  );
}

import React, { useState, useRef } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, TaskList, TaskItem, MediaItem, Comment } from '../../types';
import { 
  FileImage, Paperclip, MessageSquare, Plus, Trash2, 
  Link as LinkIcon, Image as ImageIcon, X, Send, UserPlus, Pencil, Video
} from 'lucide-react';

interface PostCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
}

// --- Helper Components ---

interface MediaCubeProps {
  item: MediaItem;
  index: number;
  onRemove: () => void;
  onUpdate: (i: MediaItem) => void;
  onFilesSelected: (files: File[]) => void;
}

const MediaCube: React.FC<MediaCubeProps> = ({ item, index, onRemove, onUpdate, onFilesSelected }) => {
  const [isHovered, setIsHovered] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onFilesSelected(Array.from(e.target.files));
    }
    // Reset input so the same file can be selected again if needed
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const handleLink = () => {
    onUpdate({ ...item, type: 'link', url: 'https://example.com' });
  };

  return (
    <div 
      className="aspect-square relative group rounded-xl bg-[#F2F2F7] overflow-hidden transition-all active:scale-95 cursor-pointer"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        multiple 
        accept="image/*,video/*"
        onChange={handleFileChange}
      />

      {item.type === 'empty' ? (
        <div className="w-full h-full flex flex-col items-center justify-center gap-2 opacity-30 group-hover:opacity-60 transition-opacity">
           <Plus size={20} className="text-gray-500"/>
           <div className="flex gap-2 absolute inset-0 items-center justify-center opacity-0 group-hover:opacity-100 bg-[#F2F2F7]">
             <button onClick={(e) => { e.stopPropagation(); handleUploadClick(); }} className="p-2 bg-white rounded-full shadow-sm hover:scale-110 transition-transform"><ImageIcon size={14} className="text-gray-600"/></button>
             <button onClick={(e) => { e.stopPropagation(); handleLink(); }} className="p-2 bg-white rounded-full shadow-sm hover:scale-110 transition-transform"><LinkIcon size={14} className="text-gray-600"/></button>
           </div>
        </div>
      ) : (
        <>
          {item.type === 'image' && <img src={item.url} alt="asset" className="w-full h-full object-cover" />}
          {item.type === 'video' && (
            <div className="w-full h-full bg-black flex items-center justify-center relative">
               <video src={item.url} className="w-full h-full object-cover opacity-80" />
               <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-8 h-8 rounded-full bg-white/30 backdrop-blur-md flex items-center justify-center">
                   <Video size={14} className="text-white fill-white" />
                 </div>
               </div>
            </div>
          )}
          {item.type === 'link' && <div className="w-full h-full flex items-center justify-center bg-blue-50 text-[#007AFF]"><LinkIcon size={20}/></div>}

          {isHovered && (
            <button 
              onClick={(e) => { e.stopPropagation(); onRemove(); }}
              className="absolute top-1.5 right-1.5 bg-black/50 backdrop-blur-md p-1 rounded-full text-white hover:bg-black/70"
            >
              <X size={10} />
            </button>
          )}
        </>
      )}
    </div>
  );
};

interface TaskListBlockProps {
  list: TaskList;
  onUpdate: (l: TaskList) => void;
  onDelete: () => void;
}

const TaskListBlock: React.FC<TaskListBlockProps> = ({ list, onUpdate, onDelete }) => {
  const [newItemText, setNewItemText] = useState("");

  const addItem = () => {
    if (!newItemText.trim()) return;
    const newItem: TaskItem = { id: Date.now().toString(), text: newItemText, done: false };
    onUpdate({ ...list, items: [...list.items, newItem] });
    setNewItemText("");
  };

  const toggleItem = (itemId: string) => {
    const updatedItems = list.items.map(i => i.id === itemId ? { ...i, done: !i.done } : i);
    onUpdate({ ...list, items: updatedItems });
  };

  const deleteItem = (itemId: string) => {
    onUpdate({ ...list, items: list.items.filter(i => i.id !== itemId) });
  };

  return (
    <div className="mb-4">
      <div className="flex items-center justify-between mb-2">
        <input 
          value={list.title}
          onChange={(e) => onUpdate({ ...list, title: e.target.value })}
          className="bg-transparent text-[13px] font-semibold text-gray-400 uppercase tracking-wide border-none focus:ring-0 p-0 w-full"
          placeholder="List Name"
        />
        <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className="text-gray-300 hover:text-red-500 transition-colors">
          <Trash2 size={12}/>
        </button>
      </div>

      <div className="space-y-0.5">
        {list.items.map(item => (
          <div key={item.id} className="flex items-start gap-3 group py-1.5 border-b border-gray-50 last:border-0">
            <button 
              onClick={(e) => { e.stopPropagation(); toggleItem(item.id); }}
              className={`mt-0.5 w-5 h-5 rounded-full border flex items-center justify-center transition-all ${item.done ? 'bg-[#007AFF] border-[#007AFF]' : 'bg-transparent border-gray-300'}`}
            >
              {item.done && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
            </button>
            <div className="flex-1 min-w-0">
               <input 
                  value={item.text}
                  onChange={(e) => {
                    const updated = list.items.map(i => i.id === item.id ? { ...i, text: e.target.value } : i);
                    onUpdate({ ...list, items: updated });
                  }}
                  className={`bg-transparent text-[15px] leading-6 w-full border-none focus:ring-0 p-0 text-gray-900 ${item.done ? 'text-gray-400' : ''}`}
                />
            </div>
            <button onClick={(e) => { e.stopPropagation(); deleteItem(item.id); }} className="opacity-0 group-hover:opacity-100 text-gray-300 hover:text-red-500">
               <X size={14} />
            </button>
          </div>
        ))}
        <div className="flex items-center gap-3 mt-1.5 pl-0.5 opacity-60 hover:opacity-100 transition-opacity">
           <Plus size={16} className="text-gray-400"/>
           <input 
             value={newItemText}
             onChange={(e) => setNewItemText(e.target.value)}
             onKeyDown={(e) => { if(e.key === 'Enter') addItem(); }}
             placeholder="Add Item"
             className="bg-transparent text-[15px] border-none focus:ring-0 p-0 placeholder-gray-400"
           />
        </div>
      </div>
    </div>
  );
};

// --- Main Component ---

export const PostCard: React.FC<PostCardProps> = (props) => {
  const { card } = props;
  const [sku] = useState(card.content?.sku || `P-${Math.random().toString(36).substr(2, 4).toUpperCase()}`);
  const [viewMode, setViewMode] = useState<'edit' | 'comments'>('edit');
  const [title, setTitle] = useState(card.content?.title || "Untitled Post");
  const [date, setDate] = useState(card.content?.date || "");
  const [caption, setCaption] = useState(card.content?.caption || "");

  const [references, setReferences] = useState<MediaItem[]>(card.content?.references || [{ id: '1', type: 'empty' }, { id: '2', type: 'empty' }]);
  const [finalAssets, setFinalAssets] = useState<MediaItem[]>(card.content?.finalAssets || [{ id: '1', type: 'empty' }]);

  const [taskLists, setTaskLists] = useState<TaskList[]>(card.content?.taskLists || []);

  const [comments, setComments] = useState<Comment[]>(card.content?.comments || []);
  const [newComment, setNewComment] = useState("");

  const addTaskList = () => {
    const newList: TaskList = { id: Date.now().toString(), title: 'New List', color: 'gray', items: [] };
    setTaskLists([...taskLists, newList]);
  };

  const handlePostComment = () => {
    if (!newComment.trim()) return;
    const c: Comment = { id: Date.now().toString(), user: 'You', avatar: 'ME', text: newComment, timestamp: 'Just now' };
    setComments([...comments, c]);
    setNewComment("");
  };

  const handleMediaUpload = (files: File[], targetId: string, listType: 'references' | 'finalAssets') => {
    const currentList = listType === 'references' ? references : finalAssets;
    const setList = listType === 'references' ? setReferences : setFinalAssets;

    // Create MediaItems from files
    const newItems: MediaItem[] = files.map(file => ({
      id: `media-${Date.now()}-${Math.random()}`,
      type: file.type.startsWith('video') ? 'video' : 'image',
      url: URL.createObjectURL(file) // Create local preview URL
    }));

    if (newItems.length === 0) return;

    // 1. Replace the target empty slot with the first file
    // 2. Append the rest of the files as new items
    const updatedList = currentList.map(item => {
      if (item.id === targetId) {
        return newItems[0];
      }
      return item;
    });

    // Append remaining files if more than 1 was selected
    if (newItems.length > 1) {
      updatedList.push(...newItems.slice(1));
    }

    setList(updatedList);
  };

  return (
    <BaseCard 
      {...props} 
      title={sku} // Minimal SKU title
      icon={<FileImage size={16} className="text-gray-400"/>} 
    >
      <div className="flex flex-col h-full">
        {viewMode === 'edit' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 ease-out">

            {/* Title Block */}
            <div className="space-y-1">
              <input 
                className="w-full font-bold text-[28px] leading-tight text-gray-900 bg-transparent border-none focus:ring-0 p-0 placeholder-gray-300" 
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="Post Title"
                onClick={(e) => e.stopPropagation()} 
              />
              <input 
                type="date" 
                className="text-[13px] font-medium text-gray-500 bg-transparent border-none p-0 focus:ring-0"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                onClick={(e) => e.stopPropagation()}
              />
            </div>

            {/* References */}
            <div>
              <div className="flex items-center justify-between mb-3">
                <span className="text-[13px] font-semibold text-gray-400">References</span>
                <button onClick={(e) => { e.stopPropagation(); setReferences([...references, { id: Date.now().toString(), type: 'empty' }]); }} className="text-[#007AFF] hover:bg-blue-50 p-1 rounded-full"><Plus size={16}/></button>
              </div>
              <div className="grid grid-cols-4 gap-3">
                {references.map((item, i) => (
                  <MediaCube 
                    key={item.id} 
                    item={item} 
                    index={i} 
                    onRemove={() => setReferences(references.filter(r => r.id !== item.id))}
                    onUpdate={(updated) => setReferences(references.map(r => r.id === item.id ? updated : r))}
                    onFilesSelected={(files) => handleMediaUpload(files, item.id, 'references')}
                  />
                ))}
              </div>
            </div>

            {/* Caption */}
            <div>
               <span className="text-[13px] font-semibold text-gray-400 mb-2 block">Caption</span>
               <textarea 
                className="w-full text-[15px] leading-relaxed text-gray-900 bg-transparent border-none p-0 resize-none focus:ring-0 placeholder-gray-300"
                rows={4}
                placeholder="Type caption here..."
                value={caption}
                onChange={(e) => setCaption(e.target.value)}
                onClick={(e) => e.stopPropagation()}
              />
            </div>

            {/* Checklists */}
            <div>
               {taskLists.map(list => (
                  <TaskListBlock 
                    key={list.id} 
                    list={list} 
                    onUpdate={(updated) => setTaskLists(taskLists.map(l => l.id === list.id ? updated : l))}
                    onDelete={() => setTaskLists(taskLists.filter(l => l.id !== list.id))}
                  />
                ))}
               <button 
                 onClick={(e) => { e.stopPropagation(); addTaskList(); }}
                 className="flex items-center gap-2 text-[15px] text-gray-400 hover:text-[#007AFF] transition-colors mt-2"
               >
                 <Plus size={16} /> Add Checklist
               </button>
            </div>

            {/* Final Assets */}
            <div className="pt-4 border-t border-gray-100">
              <span className="text-[13px] font-semibold text-gray-400 mb-3 block">Final Assets</span>
              <div className="grid grid-cols-4 gap-3">
                {finalAssets.map((item, i) => (
                  <MediaCube 
                    key={item.id} 
                    item={item} 
                    index={i} 
                    onRemove={() => setFinalAssets(finalAssets.filter(r => r.id !== item.id))}
                    onUpdate={(updated) => setFinalAssets(finalAssets.map(r => r.id === item.id ? updated : r))}
                    onFilesSelected={(files) => handleMediaUpload(files, item.id, 'finalAssets')}
                  />
                ))}
                {finalAssets.length < 4 && (
                   <button 
                    onClick={(e) => { e.stopPropagation(); setFinalAssets([...finalAssets, { id: Date.now().toString(), type: 'empty' }]); }}
                    className="aspect-square rounded-xl border border-dashed border-gray-300 flex items-center justify-center text-gray-400 hover:border-[#007AFF] hover:text-[#007AFF] transition-colors"
                   >
                     <Plus size={20} />
                   </button>
                )}
              </div>
            </div>
          </div>
        )}

        {viewMode === 'comments' && (
          <div className="flex flex-col h-[400px] animate-in slide-in-from-right-8 duration-300 ease-out">
             <div className="flex-1 overflow-y-auto space-y-4 p-1">
                {comments.length === 0 && (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400">
                    <MessageSquare size={32} className="mb-3 opacity-20"/>
                    <p className="text-[15px] font-medium text-gray-400">No comments</p>
                  </div>
                )}
                {comments.map(c => (
                  <div key={c.id} className="flex gap-3 text-[15px]">
                    <div className="w-8 h-8 rounded-full bg-gray-200 text-gray-500 text-xs flex items-center justify-center font-bold flex-shrink-0">
                      {c.avatar}
                    </div>
                    <div>
                      <div className="flex items-baseline gap-2 mb-0.5">
                        <span className="font-semibold text-gray-900">{c.user}</span>
                        <span className="text-[13px] text-gray-400">{c.timestamp}</span>
                      </div>
                      <p className="text-gray-700 leading-normal">{c.text}</p>
                    </div>
                  </div>
                ))}
             </div>
             <div className="pt-4 mt-auto border-t border-gray-100 flex gap-3 items-center">
                <input 
                  className="flex-1 bg-[#F2F2F7] rounded-full px-4 py-2.5 text-[15px] focus:ring-0 border-none placeholder-gray-400"
                  placeholder="Add a comment..."
                  value={newComment}
                  onChange={(e) => setNewComment(e.target.value)}
                  onKeyDown={(e) => { if(e.key === 'Enter') handlePostComment(); }}
                  onClick={(e) => e.stopPropagation()}
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); handlePostComment(); }}
                  className="w-9 h-9 rounded-full bg-[#007AFF] text-white flex items-center justify-center hover:bg-[#0071E3] active:scale-95 transition-all"
                >
                  <Send size={16} />
                </button>
             </div>
          </div>
        )}

        {/* Action Bar - iOS Tab Bar feel */}
        <div className="mt-8 pt-4 border-t border-gray-100 flex items-center justify-between">
          <div className="flex items-center -space-x-2 pl-2">
             <div className="w-8 h-8 rounded-full bg-gray-200 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">JD</div>
             <div className="w-8 h-8 rounded-full bg-gray-300 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">SS</div>
             <button className="w-8 h-8 rounded-full bg-[#F2F2F7] border-2 border-white flex items-center justify-center text-gray-400 hover:bg-gray-200">
               <UserPlus size={14} />
             </button>
          </div>

          <div>
             {viewMode === 'edit' ? (
               <button 
                onClick={(e) => { e.stopPropagation(); setViewMode('comments'); }}
                className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center relative"
               >
                 <MessageSquare size={18} />
                 {comments.length > 0 && (
                   <span className="absolute top-1.5 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
                 )}
               </button>
             ) : (
               <button 
                onClick={(e) => { e.stopPropagation(); setViewMode('edit'); }}
                className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center"
               >
                 <Pencil size={18} />
               </button>
             )}
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

import React, { useState, useEffect } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Search,
  X,
  ChevronDown,
  Check,
  Globe,
  MessageSquare,
  HardDrive
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'Summer Campaign',
    color: '#007AFF',
    cards: [
      { id: 'card-post-1', type: CardType.POST, x: 400, y: 150, width: 360, height: 400, zIndex: 1, content: { title: 'Launch Teaser', date: '2024-06-01' } },
      { id: 'card-ai-1', type: CardType.STRATEGY_AI, x: 820, y: 150, width: 340, height: 300, zIndex: 2, content: {} }
    ]
  },
  {
    id: 'ws-2',
    name: 'Evergreen Content',
    color: '#34C759',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
