export const PostCard: React.FC<PostCardProps> = (props) => {
  const { card } = props;
  const [sku] = useState(card.content?.sku || `P-${Math.random().toString(36).substr(2, 4).toUpperCase()}`);
  const [viewMode, setViewMode] = useState<'edit' | 'comments'>('edit');
  const [title, setTitle] = useState(card.content?.title || "Untitled Post");
  const [date, setDate] = useState(card.content?.date || "");
  const [caption, setCaption] = useState(card.content?.caption || "");

  const [references, setReferences] = useState<MediaItem[]>(card.content?.references || [{ id: '1', type: 'empty' }, { id: '2', type: 'empty' }]);
  const [finalAssets, setFinalAssets] = useState<MediaItem[]>(card.content?.finalAssets || [{ id: '1', type: 'empty' }]);

  const [taskLists, setTaskLists] = useState<TaskList[]>(card.content?.taskLists || []);
  const [comments, setComments] = useState<Comment[]>(card.content?.comments || []);
  const [newComment, setNewComment] = useState("");

  const [previewMedia, setPreviewMedia] = useState<MediaItem | null>(null);

  const addTaskList = () => {
    const newList: TaskList = { id: Date.now().toString(), title: 'New List', color: 'gray', items: [] };
    setTaskLists([...taskLists, newList]);
  };

  const handlePostComment = () => {
    if (!newComment.trim()) return;
    const c: Comment = { id: Date.now().toString(), user: 'You', avatar: 'ME', text: newComment, timestamp: 'Just now' };
    setComments([...comments, c]);
    setNewComment("");
  };

  const handleMediaUpload = (files: File[], targetId: string, listType: 'references' | 'finalAssets') => {
    const currentList = listType === 'references' ? references : finalAssets;
    const setList = listType === 'references' ? setReferences : setFinalAssets;

    const newItems: MediaItem[] = files.map(file => ({
      id: `media-${Date.now()}-${Math.random()}`,
      type: file.type.startsWith('video') ? 'video' : 'image',
      url: URL.createObjectURL(file)
    }));

    if (newItems.length === 0) return;

    // Replace target or append
    let updatedList = [...currentList];
    const targetIndex = updatedList.findIndex(i => i.id === targetId);

    if (targetIndex !== -1 && updatedList[targetIndex].type === 'empty') {
      updatedList[targetIndex] = newItems[0];
      if (newItems.length > 1) {
        updatedList.push(...newItems.slice(1));
      }
    } else {
      updatedList.push(...newItems);
    }

    setList(updatedList);
  };

  const handleReorder = (dragIndex: number, hoverIndex: number, listType: 'references' | 'finalAssets') => {
    const currentList = listType === 'references' ? references : finalAssets;
    const setList = listType === 'references' ? setReferences : setFinalAssets;

    const newList = [...currentList];
    const [removed] = newList.splice(dragIndex, 1);
    newList.splice(hoverIndex, 0, removed);

    setList(newList);
  };

  return (
    <>
      <BaseCard 
        {...props} 
        title={sku} 
        icon={<FileImage size={16} className="text-gray-400"/>} 
      >
        <div className="flex flex-col h-full">
          {viewMode === 'edit' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 ease-out">

              {/* Title Block */}
              <div className="space-y-1">
                <input 
                  className="w-full font-bold text-[28px] leading-tight text-gray-900 bg-transparent border-none focus:ring-0 p-0 placeholder-gray-300 no-drag cursor-text" 
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Post Title"
                  onClick={(e) => e.stopPropagation()} 
                />
                <input 
                  type="date" 
                  className="text-[13px] font-medium text-gray-500 bg-transparent border-none p-0 focus:ring-0 no-drag cursor-pointer"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  onClick={(e) => e.stopPropagation()}
                />
              </div>

              {/* References */}
              <div>
                <div className="flex items-center justify-between mb-3">
                  <span className="text-[13px] font-semibold text-gray-400">References</span>
                  <button onClick={(e) => { e.stopPropagation(); setReferences([...references, { id: Date.now().toString(), type: 'empty' }]); }} className="text-[#007AFF] hover:bg-blue-50 p-1 rounded-full"><Plus size={16}/></button>
                </div>
                <div className="grid grid-cols-4 gap-3">
                  {references.map((item, i) => (
                    <MediaCube 
                      key={item.id} 
                      item={item} 
                      index={i} 
                      listType="references"
                      onRemove={() => setReferences(references.filter(r => r.id !== item.id))}
                      onUpdate={(updated) => setReferences(references.map(r => r.id === item.id ? updated : r))}
                      onFilesSelected={(files) => handleMediaUpload(files, item.id, 'references')}
                      onPreview={setPreviewMedia}
                      onDropItem={handleReorder}
                    />
                  ))}
                </div>
              </div>

              {/* Caption */}
              <div>
                 <span className="text-[13px] font-semibold text-gray-400 mb-2 block">Caption</span>
                 <textarea 
                  className="w-full text-[15px] leading-relaxed text-gray-900 bg-transparent border-none p-0 resize-none focus:ring-0 placeholder-gray-300 no-drag cursor-text"
                  rows={4}
                  placeholder="Type caption here..."
                  value={caption}
                  onChange={(e) => setCaption(e.target.value)}
                  onClick={(e) => e.stopPropagation()}
                />
              </div>

              {/* Checklists */}
              <div>
                 {taskLists.map(list => (
                    <TaskListBlock 
                      key={list.id} 
                      list={list} 
                      onUpdate={(updated) => setTaskLists(taskLists.map(l => l.id === list.id ? updated : l))}
                      onDelete={() => setTaskLists(taskLists.filter(l => l.id !== list.id))}
                    />
                  ))}
                 <button 
                   onClick={(e) => { e.stopPropagation(); addTaskList(); }}
                   className="flex items-center gap-2 text-[15px] text-gray-400 hover:text-[#007AFF] transition-colors mt-2"
                 >
                   <Plus size={16} /> Add Checklist
                 </button>
              </div>

              {/* Final Assets */}
              <div className="pt-4 border-t border-gray-100">
                <span className="text-[13px] font-semibold text-gray-400 mb-3 block">Final Assets</span>
                <div className="grid grid-cols-4 gap-3">
                  {finalAssets.map((item, i) => (
                    <MediaCube 
                      key={item.id} 
                      item={item} 
                      index={i} 
                      listType="finalAssets"
                      onRemove={() => setFinalAssets(finalAssets.filter(r => r.id !== item.id))}
                      onUpdate={(updated) => setFinalAssets(finalAssets.map(r => r.id === item.id ? updated : r))}
                      onFilesSelected={(files) => handleMediaUpload(files, item.id, 'finalAssets')}
                      onPreview={setPreviewMedia}
                      onDropItem={handleReorder}
                    />
                  ))}
                  {finalAssets.length < 4 && (
                     <button 
                      onClick={(e) => { e.stopPropagation(); setFinalAssets([...finalAssets, { id: Date.now().toString(), type: 'empty' }]); }}
                      className="aspect-square rounded-xl border border-dashed border-gray-300 flex items-center justify-center text-gray-400 hover:border-[#007AFF] hover:text-[#007AFF] transition-colors no-drag"
                     >
                       <Plus size={20} />
                     </button>
                  )}
                </div>
              </div>
            </div>
          )}

          {viewMode === 'comments' && (
            <div className="flex flex-col h-[400px] animate-in slide-in-from-right-8 duration-300 ease-out no-drag cursor-auto">
               <div className="flex-1 overflow-y-auto space-y-4 p-1">
                  {comments.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-gray-400">
                      <MessageSquare size={32} className="mb-3 opacity-20"/>
                      <p className="text-[15px] font-medium text-gray-400">No comments</p>
                    </div>
                  )}
                  {comments.map(c => (
                    <div key={c.id} className="flex gap-3 text-[15px]">
                      <div className="w-8 h-8 rounded-full bg-gray-200 text-gray-500 text-xs flex items-center justify-center font-bold flex-shrink-0">
                        {c.avatar}
                      </div>
                      <div>
                        <div className="flex items-baseline gap-2 mb-0.5">
                          <span className="font-semibold text-gray-900">{c.user}</span>
                          <span className="text-[13px] text-gray-400">{c.timestamp}</span>
                        </div>
                        <p className="text-gray-700 leading-normal">{c.text}</p>
                      </div>
                    </div>
                  ))}
               </div>
               <div className="pt-4 mt-auto border-t border-gray-100 flex gap-3 items-center">
                  <input 
                    className="flex-1 bg-[#F2F2F7] rounded-full px-4 py-2.5 text-[15px] focus:ring-0 border-none placeholder-gray-400"
                    placeholder="Add a comment..."
                    value={newComment}
                    onChange={(e) => setNewComment(e.target.value)}
                    onKeyDown={(e) => { if(e.key === 'Enter') handlePostComment(); }}
                    onClick={(e) => e.stopPropagation()}
                  />
                  <button 
                    onClick={(e) => { e.stopPropagation(); handlePostComment(); }}
                    className="w-9 h-9 rounded-full bg-[#007AFF] text-white flex items-center justify-center hover:bg-[#0071E3] active:scale-95 transition-all"
                  >
                    <Send size={16} />
                  </button>
               </div>
            </div>
          )}

          {/* Action Bar */}
          <div className="mt-8 pt-4 border-t border-gray-100 flex items-center justify-between no-drag">
            <div className="flex items-center -space-x-2 pl-2">
               <div className="w-8 h-8 rounded-full bg-gray-200 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">JD</div>
               <div className="w-8 h-8 rounded-full bg-gray-300 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">SS</div>
               <button className="w-8 h-8 rounded-full bg-[#F2F2F7] border-2 border-white flex items-center justify-center text-gray-400 hover:bg-gray-200">
                 <UserPlus size={14} />
               </button>
            </div>

            <div>
               {viewMode === 'edit' ? (
                 <button 
                  onClick={(e) => { e.stopPropagation(); setViewMode('comments'); }}
                  className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center relative"
                 >
                   <MessageSquare size={18} />
                   {comments.length > 0 && (
                     <span className="absolute top-1.5 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
                   )}
                 </button>
               ) : (
                 <button 
                  onClick={(e) => { e.stopPropagation(); setViewMode('edit'); }}
                  className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center"
                 >
                   <Pencil size={18} />
                 </button>
               )}
            </div>
          </div>
        </div>
      </BaseCard>

      {/* Media Lightbox */}
      {previewMedia && (
        <MediaPreviewOverlay 
          item={previewMedia} 
          onClose={() => setPreviewMedia(null)} 
        />
      )}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Search,
  X,
  ChevronDown,
  Check,
  Globe,
  MessageSquare,
  HardDrive
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'Summer Campaign',
    color: '#007AFF',
    cards: [
      { id: 'card-post-1', type: CardType.POST, x: 400, y: 150, width: 360, height: 400, zIndex: 1, content: { title: 'Launch Teaser', date: '2024-06-01' } },
      { id: 'card-ai-1', type: CardType.STRATEGY_AI, x: 820, y: 150, width: 340, height: 300, zIndex: 2, content: {} }
    ]
  },
  {
    id: 'ws-2',
    name: 'Evergreen Content',
    color: '#34C759',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      // Position: centered horizontally relative to button, above the button
      setColorPickerState({
        id,
        x: rect.left + rect.width / 2,
        y: rect.top
      });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : 360,
      height: 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
    // Optionally close drawer after adding
    // setIsDrawerOpen(false);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  // --- Menu Data Configuration ---

  const frequentTools = [
    { 
      id: 'ai', 
      label: 'Ask AI', 
      desc: 'Prompt an AI language model', 
      icon: <Sparkles size={24} />, 
      iconColor: 'text-pink-600',
      bg: 'bg-pink-50',
      action: () => addCard(CardType.STRATEGY_AI)
    },
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create social content', 
      icon: <FileImage size={24} />, 
      iconColor: 'text-purple-600',
      bg: 'bg-purple-50',
      action: () => addCard(CardType.POST)
    },
  ];

  const integrationTools = [
    { 
      id: 'analytics', 
      label: 'Analytics', 
      desc: 'Visualize live performance data', 
      icon: <BarChart2 size={20} />, 
      color: 'bg-emerald-100 text-emerald-600',
      tag: 'DATA',
      action: () => addCard(CardType.ANALYTICS)
    },
    { 
      id: 'persona', 
      label: 'Persona', 
      desc: 'Target audience profile card', 
      icon: <Users size={20} />, 
      color: 'bg-orange-100 text-orange-600',
      tag: 'STRATEGY',
      action: () => addCard(CardType.PERSONA)
    },
    // Mock Integrations for visual completeness
    { id: 'drive', label: 'Google Drive', desc: 'Manage files in Drive', icon: <HardDrive size={20} />, color: 'bg-blue-100 text-blue-600', tag: 'MCP', action: () => {} },
    { id: 'slack', label: 'Slack', desc: 'Send channel messages', icon: <MessageSquare size={20} />, color: 'bg-purple-100 text-purple-600', tag: 'MCP', action: () => {} },
    { id: 'web', label: 'Browser', desc: 'Embed web content', icon: <Globe size={20} />, color: 'bg-gray-100 text-gray-600', tag: 'MCP', action: () => {} },
  ];

  const filterItem = (item: any) => 
    item.label.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.desc.toLowerCase().includes(searchTerm.toLowerCase());

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Main Canvas Area */}
      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />
      </div>

      {/* Trigger Zone (Top Left) with Auto-Open on Hover */}
      <div 
        className={`fixed top-0 left-0 z-40 w-32 h-32 flex items-start justify-start p-6 transition-all duration-300 ${isDrawerOpen ? '-translate-x-full opacity-0 pointer-events-none' : 'translate-x-0 opacity-100'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
      >
        <button 
          onClick={() => setIsDrawerOpen(true)}
          className="relative w-14 h-14 rounded-full group transition-transform duration-300 hover:scale-105 active:scale-95"
        >
           {/* External Shimmering Perimeter - Rotating Light - Bright & Colorful */}
           {/* Positioned OUTSIDE the button body (negative inset) */}
           <div className="absolute -inset-[3px] rounded-full overflow-hidden z-0">
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[250%] h-[250%] bg-[conic-gradient(from_0deg,transparent_0%,transparent_50%,#FF0080_70%,#7928CA_85%,#FFFFFF_95%,transparent_100%)] animate-[spin_3s_linear_infinite]" />
           </div>

           {/* Button Body - Placed on top of the spinner to create the 'ring' effect */}
           <div className="absolute inset-0 rounded-full bg-gradient-to-br from-white/95 via-pink-100/50 to-indigo-100/50 backdrop-blur-xl border border-white/60 flex items-center justify-center z-10 shadow-sm">
              <Plus size={28} strokeWidth={1} className="text-gray-600 group-hover:text-indigo-600 transition-colors duration-300" />
           </div>
        </button>
      </div>

      {/* Side Drawer Overlay (Left Side) - Auto close on mouse leave */}
      <div 
        className={`fixed inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`}
        onMouseLeave={() => setIsDrawerOpen(false)}
      >

        {/* Drawer Content */}
        <div className="w-[340px] h-full bg-white shadow-2xl flex flex-col border-r border-gray-200">

          {/* Header & Search */}
          <div className="p-5 border-b border-gray-100 bg-white z-10">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                autoFocus={isDrawerOpen}
                type="text" 
                placeholder="Search all nodes" 
                className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2.5 text-[15px] focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none placeholder-gray-400"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          {/* Scrollable List */}
          <div className="flex-1 overflow-y-auto overflow-x-hidden">
            <div className="p-5 space-y-8">

              {/* Frequently Used Section */}
              {(!searchTerm || frequentTools.some(filterItem)) && (
                <div className="space-y-3">
                  <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Frequently Used</h3>
                  <div className="grid grid-cols-2 gap-3">
                    {frequentTools.filter(filterItem).map(tool => (
                      <button 
                        key={tool.id}
                        onClick={tool.action}
                        className="flex flex-col items-start p-4 rounded-2xl bg-white border border-gray-200 hover:border-gray-300 hover:shadow-md transition-all active:scale-[0.98] text-left group"
                      >
                        <div className={`w-10 h-10 rounded-xl ${tool.bg} ${tool.iconColor} flex items-center justify-center mb-3 group-hover:scale-110 transition-transform`}>
                          {tool.icon}
                        </div>
                        <div className="font-semibold text-gray-900 text-[14px] leading-tight mb-1">{tool.label}</div>
                        <div className="text-[12px] text-gray-500 leading-snug line-clamp-2">{tool.desc}</div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Integrations / All Tools Section */}
              {(!searchTerm || integrationTools.some(filterItem)) && (
                <div className="space-y-3">
                   <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Integrations</h3>
                   <div className="space-y-1">
                      {integrationTools.filter(filterItem).map(tool => (
                        <button
                          key={tool.id}
                          onClick={tool.action}
                          className="w-full flex items-center gap-4 p-3 rounded-xl hover:bg-gray-50 transition-colors group text-left"
                        >
                          <div className={`w-10 h-10 rounded-xl ${tool.color} flex items-center justify-center shadow-sm border border-black/5 flex-shrink-0 group-hover:scale-105 transition-transform`}>
                            {tool.icon}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between mb-0.5">
                               <span className="font-semibold text-gray-900 text-[14px]">{tool.label}</span>
                               {tool.tag && (
                                 <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-md ${tool.tag === 'MCP' ? 'bg-blue-100 text-blue-600' : 'bg-green-100 text-green-600'}`}>
                                   {tool.tag}
                                 </span>
                               )}
                            </div>
                            <p className="text-[13px] text-gray-500 truncate">{tool.desc}</p>
                          </div>
                          <div className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity">
                            <Plus size={16} />
                          </div>
                        </button>
                      ))}
                   </div>
                </div>
              )}

              {searchTerm && !frequentTools.some(filterItem) && !integrationTools.some(filterItem) && (
                <div className="text-center py-10 text-gray-400">
                  <p>No tools found</p>
                </div>
              )}

            </div>
          </div>
