      {/* Trigger Zone (Top Left) with Auto-Open on Hover */}
      <div 
        className={`fixed top-0 left-0 z-40 w-32 h-32 flex items-start justify-start p-6 transition-all duration-300 ${isDrawerOpen ? '-translate-x-full opacity-0 pointer-events-none' : 'translate-x-0 opacity-100'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
      >
        <button 
          onClick={() => setIsDrawerOpen(true)}
          className="relative w-14 h-14 rounded-full group transition-transform duration-300 hover:scale-105 active:scale-95"
        >
           {/* External Shimmering Perimeter - Rotating Light - Bright & Colorful */}
           {/* Positioned OUTSIDE the button body (negative inset) to create a border effect */}
           <div className="absolute -inset-[3px] rounded-full overflow-hidden z-0">
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[200%] h-[200%] bg-[conic-gradient(from_0deg,transparent_0_300deg,#FF0080_320deg,#7928CA_340deg,#FFFFFF_360deg)] animate-[spin_2s_linear_infinite]" />
           </div>

           {/* Button Body - Placed on top of the spinner to create the 'ring' effect */}
           <div className="absolute inset-0 rounded-full bg-gradient-to-br from-white/95 via-pink-100/50 to-indigo-100/50 backdrop-blur-xl border border-white/60 flex items-center justify-center z-10 shadow-sm">
              <Plus size={28} strokeWidth={1} className="text-gray-600 group-hover:text-indigo-600 transition-colors duration-300" />
           </div>
        </button>
      </div>

      {/* Side Drawer Overlay (Left Side) - Auto close on mouse leave */}
      <div 
        className={`fixed inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`}
        onMouseLeave={() => setIsDrawerOpen(false)}
      >

        {/* Drawer Content */}
        <div className="w-[340px] h-full bg-white shadow-2xl flex flex-col border-r border-gray-200">

          {/* Header & Search */}
          <div className="p-5 border-b border-gray-100 bg-white z-10">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                autoFocus={isDrawerOpen}
                type="text" 
                placeholder="Search all nodes" 
                className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2.5 text-[15px] focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none placeholder-gray-400"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          {/* Scrollable List */}
          <div className="flex-1 overflow-y-auto overflow-x-hidden">
