          </div>
        </div>
      </BaseCard>

      {/* Media Lightbox */}
      {previewMedia && (
        <MediaPreviewOverlay 
          item={previewMedia} 
          onClose={() => setPreviewMedia(null)} 
        />
      )}
    </>
  );
};

