                  {finalAssets.map((item, i) => (
                    <MediaCube 
                      key={item.id} 
                      item={item} 
                      index={i} 
                      listType="finalAssets"
                      onRemove={() => setFinalAssets(finalAssets.filter(r => r.id !== item.id))}
                      onUpdate={(updated) => setFinalAssets(finalAssets.map(r => r.id === item.id ? updated : r))}
