export const PostCard: React.FC<PostCardProps> = (props) => {
  const { card } = props;
  const [sku] = useState(card.content?.sku || `P-${Math.random().toString(36).substr(2, 4).toUpperCase()}`);
  const [viewMode, setViewMode] = useState<'edit' | 'comments'>('edit');
  const [title, setTitle] = useState(card.content?.title || "Untitled Post");
  const [date, setDate] = useState(card.content?.date || "");
  const [caption, setCaption] = useState(card.content?.caption || "");

  // Initialize without empty items, just content
  const [references, setReferences] = useState<MediaItem[]>((card.content?.references || []).filter((i: MediaItem) => i.type !== 'empty'));
  const [finalAssets, setFinalAssets] = useState<MediaItem[]>((card.content?.finalAssets || []).filter((i: MediaItem) => i.type !== 'empty'));

  const [taskLists, setTaskLists] = useState<TaskList[]>(card.content?.taskLists || []);
  const [comments, setComments] = useState<Comment[]>(card.content?.comments || []);
  const [newComment, setNewComment] = useState("");

  // Drive State
  const [driveInfo, setDriveInfo] = useState({
    synced: !!card.content?.driveFolderId,
    url: card.content?.driveFolderUrl || 'https://drive.google.com'
  });

  const [previewContext, setPreviewContext] = useState<{ item: MediaItem; list: MediaItem[] } | null>(null);

  const addTaskList = () => {
    const newList: TaskList = { id: Date.now().toString(), title: 'New List', color: 'gray', items: [] };
    setTaskLists([...taskLists, newList]);
  };

  const handlePostComment = () => {
    if (!newComment.trim()) return;
    const c: Comment = { id: Date.now().toString(), user: 'You', avatar: 'ME', text: newComment, timestamp: 'Just now' };
    setComments([...comments, c]);
    setNewComment("");
  };

  const handleMediaUpload = (files: File[], listType: 'references' | 'finalAssets') => {
    const currentList = listType === 'references' ? references : finalAssets;
    const setList = listType === 'references' ? setReferences : setFinalAssets;

    const newItems: MediaItem[] = files.map(file => ({
      id: `media-${Date.now()}-${Math.random()}`,
      type: file.type.startsWith('video') ? 'video' : 'image',
      url: URL.createObjectURL(file)
    }));

    if (newItems.length === 0) return;
    setList([...currentList, ...newItems]);
  };

  const handleReorder = (dragIndex: number, hoverIndex: number, listType: 'references' | 'finalAssets') => {
    const currentList = listType === 'references' ? references : finalAssets;
    const setList = listType === 'references' ? setReferences : setFinalAssets;

    const newList = [...currentList];
    const [removed] = newList.splice(dragIndex, 1);
    newList.splice(hoverIndex, 0, removed);

    setList(newList);
  };

  const handleDriveSync = async () => {
    // Mock Async Operation
    return new Promise<void>((resolve, reject) => {
      setTimeout(() => {
        // Randomly succeed
        if (Math.random() > 0.1) {
          setDriveInfo({
            synced: true,
            url: 'https://drive.google.com/drive/folders/mock-folder-id'
          });
          resolve();
        } else {
          reject(new Error("Network Error"));
        }
      }, 1500);
    });
  };

  return (
    <>
      <BaseCard 
        {...props} 
        title={sku} 
        icon={<FileImage size={16} className="text-gray-400"/>} 
      >
        <div className="flex flex-col h-full">
          {viewMode === 'edit' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 ease-out">

              {/* Title Block */}
              <div className="space-y-1">
                <input 
                  className="w-full font-bold text-[28px] leading-tight text-gray-900 bg-transparent border-none focus:ring-0 p-0 placeholder-gray-300 no-drag cursor-text" 
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Post Title"
                  onClick={(e) => e.stopPropagation()} 
                />
                <input 
                  type="date" 
                  className="text-[13px] font-medium text-gray-500 bg-transparent border-none p-0 focus:ring-0 no-drag cursor-pointer"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  onClick={(e) => e.stopPropagation()}
                />
              </div>

              {/* References */}
              <div>
                <div className="flex items-center justify-between mb-3">
                  <span className="text-[13px] font-semibold text-gray-400">References</span>
                </div>
                <div className="grid grid-cols-4 gap-3">
                  {references.map((item, i) => (
                    <MediaCube 
                      key={item.id} 
                      item={item} 
                      index={i} 
                      listType="references"
                      onRemove={() => setReferences(references.filter(r => r.id !== item.id))}
                      onUpdate={(updated) => setReferences(references.map(r => r.id === item.id ? updated : r))}
                      onFilesSelected={(files) => handleMediaUpload(files, 'references')}
                      onPreview={() => setPreviewContext({ item, list: references })}
                      onDropItem={handleReorder}
                    />
                  ))}
                  <AddMediaButton onFilesSelected={(files) => handleMediaUpload(files, 'references')} />
                </div>
              </div>

              {/* Caption */}
              <div>
                 <span className="text-[13px] font-semibold text-gray-400 mb-2 block">Caption</span>
                 <textarea 
                  className="w-full text-[15px] leading-relaxed text-gray-900 bg-transparent border-none p-0 resize-none focus:ring-0 placeholder-gray-300 no-drag cursor-text"
                  rows={4}
                  placeholder="Type caption here..."
                  value={caption}
                  onChange={(e) => setCaption(e.target.value)}
                  onClick={(e) => e.stopPropagation()}
                />
              </div>

              {/* Checklists */}
              <div>
                 {taskLists.map(list => (
                    <TaskListBlock 
                      key={list.id} 
                      list={list} 
                      onUpdate={(updated) => setTaskLists(taskLists.map(l => l.id === list.id ? updated : l))}
                      onDelete={() => setTaskLists(taskLists.filter(l => l.id !== list.id))}
                    />
                  ))}
                 <button 
                   onClick={(e) => { e.stopPropagation(); addTaskList(); }}
                   className="flex items-center gap-2 text-[15px] text-gray-400 hover:text-[#007AFF] transition-colors mt-2"
                 >
                   <Plus size={16} /> Add Checklist
                 </button>
              </div>

              {/* Final Assets */}
              <div className="pt-4 border-t border-gray-100">
                <span className="text-[13px] font-semibold text-gray-400 mb-3 block">Final Assets</span>
                <div className="grid grid-cols-4 gap-3">
                  {finalAssets.map((item, i) => (
                    <MediaCube 
                      key={item.id} 
                      item={item} 
                      index={i} 
                      listType="finalAssets"
                      onRemove={() => setFinalAssets(finalAssets.filter(r => r.id !== item.id))}
                      onUpdate={(updated) => setFinalAssets(finalAssets.map(r => r.id === item.id ? updated : r))}
                      onFilesSelected={(files) => handleMediaUpload(files, 'finalAssets')}
                      onPreview={() => setPreviewContext({ item, list: finalAssets })}
                      onDropItem={handleReorder}
                    />
                  ))}
                  <AddMediaButton onFilesSelected={(files) => handleMediaUpload(files, 'finalAssets')} />
                </div>
              </div>
            </div>
          )}

          {viewMode === 'comments' && (
            <div className="flex flex-col h-[400px] animate-in slide-in-from-right-8 duration-300 ease-out no-drag cursor-auto">
               <div className="flex-1 overflow-y-auto space-y-4 p-1">
                  {comments.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-gray-400">
                      <MessageSquare size={32} className="mb-3 opacity-20"/>
                      <p className="text-[15px] font-medium text-gray-400">No comments</p>
                    </div>
                  )}
                  {comments.map(c => (
                    <div key={c.id} className="flex gap-3 text-[15px]">
                      <div className="w-8 h-8 rounded-full bg-gray-200 text-gray-500 text-xs flex items-center justify-center font-bold flex-shrink-0">
                        {c.avatar}
                      </div>
                      <div>
                        <div className="flex items-baseline gap-2 mb-0.5">
                          <span className="font-semibold text-gray-900">{c.user}</span>
                          <span className="text-[13px] text-gray-400">{c.timestamp}</span>
                        </div>
                        <p className="text-gray-700 leading-normal">{c.text}</p>
                      </div>
                    </div>
                  ))}
               </div>
               <div className="pt-4 mt-auto border-t border-gray-100 flex gap-3 items-center">
                  <input 
                    className="flex-1 bg-[#F2F2F7] rounded-full px-4 py-2.5 text-[15px] focus:ring-0 border-none placeholder-gray-400"
                    placeholder="Add a comment..."
                    value={newComment}
                    onChange={(e) => setNewComment(e.target.value)}
                    onKeyDown={(e) => { if(e.key === 'Enter') handlePostComment(); }}
                    onClick={(e) => e.stopPropagation()}
                  />
                  <button 
                    onClick={(e) => { e.stopPropagation(); handlePostComment(); }}
                    className="w-9 h-9 rounded-full bg-[#007AFF] text-white flex items-center justify-center hover:bg-[#0071E3] active:scale-95 transition-all"
                  >
                    <Send size={16} />
                  </button>
               </div>
            </div>
          )}

          {/* Action Bar */}
          <div className="mt-8 pt-4 border-t border-gray-100 flex items-center justify-between no-drag">
            {/* Left: Assignees */}
            <div className="flex items-center -space-x-2 pl-2">
               <div className="w-8 h-8 rounded-full bg-gray-200 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">JD</div>
               <div className="w-8 h-8 rounded-full bg-gray-300 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">SS</div>
               <button className="w-8 h-8 rounded-full bg-[#F2F2F7] border-2 border-white flex items-center justify-center text-gray-400 hover:bg-gray-200">
                 <UserPlus size={14} />
               </button>
            </div>

            {/* Right: Tools (Drive + Comments) */}
            <div className="flex items-center gap-2">
               {/* Drive Integration */}
               <DriveSyncButton 
                  sku={sku}
                  title={title}
                  hasAssets={finalAssets.length > 0}
                  isSynced={driveInfo.synced}
                  driveUrl={driveInfo.url}
                  onSync={handleDriveSync}
               />

               {viewMode === 'edit' ? (
                 <button 
                  onClick={(e) => { e.stopPropagation(); setViewMode('comments'); }}
                  className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center relative"
                 >
                   <MessageSquare size={18} />
                   {comments.length > 0 && (
                     <span className="absolute top-1.5 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
                   )}
                 </button>
               ) : (
                 <button 
                  onClick={(e) => { e.stopPropagation(); setViewMode('edit'); }}
                  className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center"
                 >
                   <Pencil size={18} />
                 </button>
               )}
            </div>
          </div>
        </div>
      </BaseCard>

      {/* Media Lightbox */}
      {previewContext && (
        <MediaPreviewOverlay 
          initialItem={previewContext.item}
          items={previewContext.list}
          onClose={() => setPreviewContext(null)} 
        />
      )}
    </>
  );
};

