import React, { useState, useEffect, useMemo } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, GridConfig, GridPlannerContent, MediaItem, PostCardContent } from '../../types';
import { Settings, Calendar, RefreshCw, X, LayoutGrid } from 'lucide-react';

interface GridPlannerCardProps {
  card: CardData;
  allCards: CardData[];
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onUnlink: (gridId: string, slotIndex: number, postCardId: string) => void;
  hoveredSlotIndex?: number | null; // From Canvas, when dragging a PostCard over this grid
  zoomScale: number;
}

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June', 
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const GridPlannerCard: React.FC<GridPlannerCardProps> = (props) => {
  const { card, allCards, onUpdateContent, onUnlink, hoveredSlotIndex } = props;
  const content = card.content as GridPlannerContent;

  const [isFlipped, setIsFlipped] = useState(false);

  // Local state for settings form
  const [tempConfig, setTempConfig] = useState<GridConfig>(content.config || {
    month: new Date().getMonth(),
    year: new Date().getFullYear(),
    logicType: 'frequency',
    value: 3
  });

  // Ensure content defaults exist
  useEffect(() => {
    if (!content.config) {
      onUpdateContent(card.id, {
        ...content,
        title: "Social Planner",
        connections: {},
        config: tempConfig
      });
    }
  }, []);

  const handleSaveSettings = () => {
    // Clear connections if month/year changes to prevent data mismatch?
    // For now, we keep connections but they might look weird if dates shift.
    // Ideally, we'd warn the user.
    onUpdateContent(card.id, {
      ...content,
      config: tempConfig
    });
    setIsFlipped(false);
  };

  // --- Logic Engine ---

  const slots = useMemo(() => {
    const { month, year, logicType, value } = content.config || tempConfig;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const generatedSlots: { date: Date; label: string; index: number }[] = [];

    if (logicType === 'frequency') {
      // Every X days, starting from day 1 (or allow offset in future)
      const step = Math.max(1, value);
      for (let d = 1; d <= daysInMonth; d += step) {
        generatedSlots.push({
          date: new Date(year, month, d),
          label: `${MONTHS[month].substring(0, 3)} ${d}`,
          index: generatedSlots.length
        });
      }
    } else {
      // Total X posts spread evenly
      const count = Math.max(1, Math.min(value, daysInMonth));
      const step = daysInMonth / count;
      for (let i = 0; i < count; i++) {
        const day = Math.floor(1 + (i * step));
        generatedSlots.push({
          date: new Date(year, month, day),
          label: `${MONTHS[month].substring(0, 3)} ${day}`,
          index: i
        });
      }
    }
    return generatedSlots;
  }, [content.config, tempConfig]);


  // --- Render Helpers ---

  const renderFront = () => (
    <div className="flex flex-col h-full">
      {/* Grid Container */}
      <div className="grid grid-cols-3 gap-2 flex-1 auto-rows-min pb-12">
        {slots.map((slot, i) => {
          const connectedCardId = content.connections?.[i];
          const connectedCard = connectedCardId ? allCards.find(c => c.id === connectedCardId) : null;

          let previewMedia: MediaItem | undefined;
          if (connectedCard && connectedCard.content.finalAssets?.length > 0) {
            previewMedia = connectedCard.content.finalAssets[0];
          }

          const isHovered = hoveredSlotIndex === i;

          return (
            <div 
              key={i}
              className={`
                aspect-[4/5] rounded-xl relative group transition-all duration-200
                ${connectedCard 
                  ? 'bg-white shadow-sm ring-1 ring-black/5' 
                  : 'bg-white/40 border-2 border-dashed border-gray-200 hover:border-blue-300'
                }
                ${isHovered ? 'ring-4 ring-blue-500 scale-105 z-10 bg-blue-50' : ''}
              `}
            >
              {/* Connected State */}
              {connectedCard && (
                <>
                  {previewMedia?.type === 'image' && (
                    <img src={previewMedia.url} className="w-full h-full object-cover rounded-xl" />
                  )}
                  {previewMedia?.type === 'video' && (
                    <video src={previewMedia.url} className="w-full h-full object-cover rounded-xl" />
                  )}
                  {!previewMedia && (
