import React, { useState, useEffect, useMemo } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, GridConfig, GridPlannerContent, MediaItem, PostCardContent } from '../../types';
import { Settings, Calendar, RefreshCw, X, LayoutGrid } from 'lucide-react';

interface GridPlannerCardProps {
  card: CardData;
  allCards: CardData[];
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onUnlink: (gridId: string, slotIndex: number, postCardId: string) => void;
  hoveredSlotIndex?: number | null; // From Canvas, when dragging a PostCard over this grid
  zoomScale: number;
}

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June', 
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const GridPlannerCard: React.FC<GridPlannerCardProps> = (props) => {
  const { card, allCards, onUpdateContent, onUnlink, hoveredSlotIndex } = props;
  const content = card.content as GridPlannerContent;

  const [isFlipped, setIsFlipped] = useState(false);

  // Local state for settings form
  const [tempConfig, setTempConfig] = useState<GridConfig>(content.config || {
    month: new Date().getMonth(),
    year: new Date().getFullYear(),
    logicType: 'frequency',
    value: 3
  });

  // Ensure content defaults exist
  useEffect(() => {
    if (!content.config) {
      onUpdateContent(card.id, {
        ...content,
        title: "Social Planner",
        connections: {},
        config: tempConfig
      });
    }
  }, []);

  const handleSaveSettings = () => {
    onUpdateContent(card.id, {
      ...content,
      config: tempConfig
    });
    setIsFlipped(false);
  };

  // --- Logic Engine ---

  const slots = useMemo(() => {
    const { month, year, logicType, value } = content.config || tempConfig;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const generatedSlots: { date: Date; label: string; index: number }[] = [];

    if (logicType === 'frequency') {
      // Every X days, starting from day 1 (or allow offset in future)
      const step = Math.max(1, value);
      for (let d = 1; d <= daysInMonth; d += step) {
        generatedSlots.push({
          date: new Date(year, month, d),
          label: `${MONTHS[month].substring(0, 3)} ${d}`,
          index: generatedSlots.length
        });
      }
    } else {
      // Total X posts spread evenly
      const count = Math.max(1, Math.min(value, daysInMonth));
      const step = daysInMonth / count;
      for (let i = 0; i < count; i++) {
        const day = Math.floor(1 + (i * step));
        generatedSlots.push({
          date: new Date(year, month, day),
          label: `${MONTHS[month].substring(0, 3)} ${day}`,
          index: i
        });
      }
    }
    return generatedSlots;
  }, [content.config, tempConfig]);


  // --- Render Helpers ---

  const renderFront = () => (
    <div className="flex flex-col h-full bg-white relative">
      {/* Grid Container */}
      <div className="grid grid-cols-3 gap-2 flex-1 auto-rows-min pb-14 overflow-y-auto no-scrollbar">
        {slots.map((slot, i) => {
          const connectedCardId = content.connections?.[i];
          const connectedCard = connectedCardId ? allCards.find(c => c.id === connectedCardId) : null;

          let previewMedia: MediaItem | undefined;
          if (connectedCard && connectedCard.content.finalAssets?.length > 0) {
            previewMedia = connectedCard.content.finalAssets[0];
          }

          const isHovered = hoveredSlotIndex === i;

          return (
            <div 
              key={i}
              className={`
                aspect-[4/5] rounded-xl relative group transition-all duration-200
                ${connectedCard 
                  ? 'bg-white shadow-sm ring-1 ring-black/5' 
                  : 'bg-white/40 border-2 border-dashed border-gray-200 hover:border-blue-300'
                }
                ${isHovered ? 'ring-4 ring-blue-500 scale-105 z-10 bg-blue-50' : ''}
              `}
            >
              {/* Connected State */}
              {connectedCard && (
                <>
                  {previewMedia?.type === 'image' && (
                    <img src={previewMedia.url} className="w-full h-full object-cover rounded-xl" />
                  )}
                  {previewMedia?.type === 'video' && (
                    <video src={previewMedia.url} className="w-full h-full object-cover rounded-xl" />
                  )}
                  {!previewMedia && (
                    <div className="w-full h-full flex flex-col items-center justify-center p-2 text-center">
                       <span className="text-xs font-bold text-gray-900 line-clamp-2">{connectedCard.content.title}</span>
                       <span className="text-[10px] text-gray-400 mt-1">No Asset</span>
                    </div>
                  )}

                  {/* Unlink Button */}
                  <button 
                    onClick={(e) => {
                      e.stopPropagation();
                      onUnlink(card.id, i, connectedCard.id);
                    }}
                    className="absolute -top-2 -right-2 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity shadow-sm hover:scale-110"
                  >
                    <X size={12} strokeWidth={3} />
                  </button>
                </>
              )}

              {/* Date Label (Always Visible) */}
              <div className={`
                absolute bottom-2 left-1/2 -translate-x-1/2 px-2 py-1 rounded-md text-[10px] font-bold tracking-wide uppercase
                ${connectedCard ? 'bg-black/60 text-white backdrop-blur-md' : 'bg-gray-200/50 text-gray-500'}
              `}>
                {slot.label}
              </div>
            </div>
          );
        })}
      </div>

      {/* Footer */}
      <div className="absolute bottom-0 left-0 right-0 h-14 border-t border-gray-100 bg-white/95 backdrop-blur-xl flex items-center justify-between z-10 -mx-5 px-5">
        <div className="flex -space-x-2">
           {/* Avatars placeholder */}
           <div className="w-6 h-6 rounded-full bg-blue-100 border border-white flex items-center justify-center text-[10px] font-bold text-blue-500">A</div>
           <div className="w-6 h-6 rounded-full bg-green-100 border border-white flex items-center justify-center text-[10px] font-bold text-green-500">M</div>
        </div>

        <button 
          onClick={(e) => { e.stopPropagation(); setIsFlipped(true); }}
          className="w-8 h-8 flex items-center justify-center rounded-full text-gray-400 hover:bg-gray-100 hover:text-gray-900 transition-colors"
        >
          <Settings size={18} />
        </button>
      </div>
    </div>
  );

  const renderBack = () => (
    <div className="flex flex-col h-full bg-[#f8f9fa] rounded-2xl border border-gray-100 overflow-hidden">
      <div className="p-6 space-y-6 flex-1 overflow-y-auto">

        {/* Month Selection */}
        <div className="space-y-3">
          <label className="text-[13px] font-bold text-gray-400 uppercase tracking-wide flex items-center gap-2">
            <Calendar size={14} /> Timeframe
          </label>
          <div className="grid grid-cols-2 gap-3">
            <select 
              className="bg-white border-none rounded-xl py-2.5 px-3 text-sm font-medium shadow-sm focus:ring-2 focus:ring-blue-500 outline-none"
              value={tempConfig.month}
              onChange={e => setTempConfig({...tempConfig, month: parseInt(e.target.value)})}
            >
              {MONTHS.map((m, i) => <option key={i} value={i}>{m}</option>)}
            </select>
            <input 
              type="number"
              className="bg-white border-none rounded-xl py-2.5 px-3 text-sm font-medium shadow-sm focus:ring-2 focus:ring-blue-500 outline-none"
              value={tempConfig.year}
              onChange={e => setTempConfig({...tempConfig, year: parseInt(e.target.value)})}
            />
          </div>
        </div>

        {/* Logic Selection */}
        <div className="space-y-3">
          <label className="text-[13px] font-bold text-gray-400 uppercase tracking-wide flex items-center gap-2">
            <RefreshCw size={14} /> Posting Cadence
          </label>

          <div className="bg-white rounded-xl p-3 shadow-sm space-y-3">
            <label className="flex items-center gap-3 cursor-pointer">
              <input 
                type="radio" 
                name="logic"
                checked={tempConfig.logicType === 'frequency'}
                onChange={() => setTempConfig({...tempConfig, logicType: 'frequency'})}
                className="text-blue-500 focus:ring-blue-500"
              />
              <span className="text-[14px] text-gray-700">Every <span className="font-bold text-gray-900">X</span> days</span>
            </label>

            <label className="flex items-center gap-3 cursor-pointer">
               <input 
                type="radio" 
                name="logic"
                checked={tempConfig.logicType === 'count'}
                onChange={() => setTempConfig({...tempConfig, logicType: 'count'})}
                className="text-blue-500 focus:ring-blue-500"
              />
              <span className="text-[14px] text-gray-700">Total <span className="font-bold text-gray-900">X</span> posts</span>
            </label>

            <div className="pt-2 border-t border-gray-100">
               <div className="flex items-center justify-between">
                 <span className="text-[13px] font-medium text-gray-500">Value (X)</span>
                 <input 
                    type="number" 
                    min="1"
                    max="31"
                    className="w-20 bg-gray-50 border-none rounded-lg py-1 px-2 text-right font-bold text-gray-900 outline-none"
                    value={tempConfig.value}
                    onChange={(e) => setTempConfig({...tempConfig, value: parseInt(e.target.value) || 1})}
                 />
               </div>
            </div>
          </div>
        </div>
      </div>

      {/* Footer Actions */}
      <div className="mt-auto p-5 border-t border-gray-200 bg-white flex gap-3 z-10">
        <button 
          onClick={(e) => { e.stopPropagation(); setIsFlipped(false); setTempConfig(content.config); }}
          className="flex-1 py-2.5 rounded-xl text-[15px] font-medium text-gray-500 hover:bg-gray-100 transition-colors"
        >
          Cancel
        </button>
        <button 
          onClick={(e) => { e.stopPropagation(); handleSaveSettings(); }}
          className="flex-1 py-2.5 rounded-xl text-[15px] font-medium bg-blue-600 text-white hover:bg-blue-700 shadow-md active:scale-95 transition-all"
        >
          Apply Changes
        </button>
      </div>
    </div>
  );

  return (
    <BaseCard 
      {...props} 
      title={content.title || "Grid Planner"} 
      icon={<LayoutGrid size={16} className="text-blue-500"/>}
    >
      <div 
        className="relative w-full h-full"
        style={{ perspective: '1000px' }}
      >
        <div 
          className="w-full h-full transition-transform duration-500 relative"
          style={{ 
            transformStyle: 'preserve-3d',
            transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)' 
          }}
        >
          {/* Front Face */}
          <div 
            className="absolute inset-0"
            style={{ backfaceVisibility: 'hidden' }}
          >
             {renderFront()}
          </div>

          {/* Back Face */}
          <div 
            className="absolute inset-0 h-full"
            style={{ 
              transform: 'rotateY(180deg)',
              backfaceVisibility: 'hidden' 
            }}
          >
             {renderBack()}
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Position, GridPlannerContent } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';
import { GridPlannerCard } from './cards/GridPlannerCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
}

// Layout constants matching GridPlannerCard CSS
const GRID_HEADER_HEIGHT = 60; // Approx header height
const GRID_PADDING = 20;
const GRID_GAP = 8;

export const Canvas: React.FC<CanvasProps> = ({ cards, onCardsChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);

  // Dragging Logic for Snapping
  const [draggingCardId, setDraggingCardId] = useState<string | null>(null);
  const [hoveredGridId, setHoveredGridId] = useState<string | null>(null);
  const [hoveredSlotIndex, setHoveredSlotIndex] = useState<number | null>(null);

  // --- Infinite Background Logic ---
  const gridLayers = useMemo(() => {
    const layers = [];
    const baseSpacing = 40; // The fundamental grid unit in world space

    // Determine the "base power" of the current zoom level.
    // e.g., if zoom is 1, log10(1) = 0. If zoom is 0.1, log10(0.1) = -1.
    // We look at the power below and above to blend layers.
    const logScale = Math.log10(scale);
    const currentPower = Math.floor(logScale);

    // We render a window of scales around the current power to ensure seamless continuity
    // Iterate from currentPower - 1 to currentPower + 1 (covering zooming out and in)
    for (let i = -1; i <= 1; i++) {
      const power = -currentPower + i; 
      // Calculate the visual spacing of this layer on screen
      const worldSpacing = baseSpacing * Math.pow(10, power);
      const visualSpacing = worldSpacing * scale;

      // Opacity Curve Logic:
      // - Fade in between 15px and 25px
      // - Full opacity between 25px and 100px
      // - Fade out between 100px and 250px
      let opacity = 0;

      if (visualSpacing >= 15 && visualSpacing <= 250) {
        if (visualSpacing < 25) {
           // Fade In
           opacity = (visualSpacing - 15) / 10;
        } else if (visualSpacing > 100) {
           // Fade Out
           opacity = 1 - (visualSpacing - 100) / 150;
        } else {
           // Stable
           opacity = 1;
        }
      }

      if (opacity > 0) {
        layers.push({
          spacing: visualSpacing,
          opacity: Math.max(0, Math.min(1, opacity)), // Clamp 0-1
          key: `grid-layer-${power}`
        });
      }
    }
    return layers;
  }, [scale]);

  const handleWheel = (e: WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const s = Math.exp(-e.deltaY * 0.01);
      setScale(prev => Math.min(Math.max(0.05, prev * s), 10)); // Expanded zoom limits for infinite feel
    } else {
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button === 0 || e.button === 1) {
      setIsPanning(true);
      setLastMousePos({ x: e.clientX, y: e.clientY });
      setSelectedCardId(null); 
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    // 1. Pan Canvas
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
      return;
    }

    // 2. Drag Collision Detection (Snapping Logic)
    if (draggingCardId) {
      const draggedCard = cards.find(c => c.id === draggingCardId);
      if (draggedCard && draggedCard.type === CardType.POST) {
        // Find if we are hovering over any GRID_PLANNER
        const mouseXWorld = (e.clientX - pan.x) / scale;
        const mouseYWorld = (e.clientY - pan.y) / scale;

        let foundGridId: string | null = null;
        let foundSlotIndex: number | null = null;

        for (const card of cards) {
          if (card.type === CardType.GRID_PLANNER) {
            // Check bounding box
            if (
              mouseXWorld >= card.x && 
              mouseXWorld <= card.x + card.width &&
              mouseYWorld >= card.y && 
              mouseYWorld <= card.y + card.height
            ) {
              foundGridId = card.id;

              // Calculate specific slot
              // Geometry: 3 cols. Width available = width - 2*padding.
              const contentWidth = card.width - (GRID_PADDING * 2);
              const colWidth = (contentWidth - (2 * GRID_GAP)) / 3;
              const rowHeight = colWidth * 1.25; // 4:5 aspect ratio

              const relativeX = mouseXWorld - (card.x + GRID_PADDING);
              const relativeY = mouseYWorld - (card.y + GRID_HEADER_HEIGHT + GRID_PADDING);

              if (relativeX >= 0 && relativeY >= 0) {
                 const col = Math.floor(relativeX / (colWidth + GRID_GAP));
                 const row = Math.floor(relativeY / (rowHeight + GRID_GAP));

                 if (col >= 0 && col < 3 && row >= 0) {
                   foundSlotIndex = (row * 3) + col;
                 }
              }
              break; // Found the top-most grid
            }
          }
        }

        setHoveredGridId(foundGridId);
        setHoveredSlotIndex(foundSlotIndex);
      }
    }
  };

  const handleMouseUp = () => {
    // Logic for Dropping a Post Card onto a Grid Slot
    if (draggingCardId && hoveredGridId && hoveredSlotIndex !== null) {
      const grid = cards.find(c => c.id === hoveredGridId);
      const post = cards.find(c => c.id === draggingCardId);

      if (grid && post) {
        // 1. Calculate the date for this slot
        const content = grid.content as GridPlannerContent;
        // Re-generate slots logic briefly to get the date (duplication for safety)
        const { month, year, logicType, value } = content.config;
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        let slotDateStr = "";

        // Simplified logic generator (matches GridPlannerCard)
        const generatedDates = [];
        if (logicType === 'frequency') {
            const step = Math.max(1, value);
            for (let d = 1; d <= daysInMonth; d += step) generatedDates.push(new Date(year, month, d));
        } else {
            const count = Math.max(1, Math.min(value, daysInMonth));
            const step = daysInMonth / count;
            for (let i = 0; i < count; i++) generatedDates.push(new Date(year, month, Math.floor(1 + (i * step))));
        }

        if (generatedDates[hoveredSlotIndex]) {
            slotDateStr = generatedDates[hoveredSlotIndex].toISOString().split('T')[0];
        }

        // 2. Update Cards
        const newCards = cards.map(c => {
          if (c.id === hoveredGridId) {
            // Link Post to Grid Slot
            return {
              ...c,
              content: {
                ...c.content,
                connections: {
                  ...c.content.connections,
                  [hoveredSlotIndex]: draggingCardId
                }
              }
            };
          }
          if (c.id === draggingCardId) {
            // Update Post Date
            return {
              ...c,
              content: {
                ...c.content,
                date: slotDateStr
              }
            };
          }
          return c;
        });

        onCardsChange(newCards);
      }
    }

    setIsPanning(false);
    setDraggingCardId(null);
    setHoveredGridId(null);
    setHoveredSlotIndex(null);
  };

  // --- CRUD Handlers ---

  const updateCardPosition = (id: string, x: number, y: number) => {
    // This runs on every frame of drag, so we hook into it to track dragging state
    if (draggingCardId !== id) setDraggingCardId(id);
    onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
  };

  const updateCardContent = (id: string, content: any) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, content } : c));
  };

  const handleDeleteCard = (id: string) => {
    onCardsChange(cards.filter(c => c.id !== id));
    if (selectedCardId === id) setSelectedCardId(null);
  };

  const handleUnlink = (gridId: string, slotIndex: number, postCardId: string) => {
    onCardsChange(cards.map(c => {
      if (c.id === gridId) {
        const newConnections = { ...c.content.connections };
        delete newConnections[slotIndex];
        return { ...c, content: { ...c.content, connections: newConnections }};
      }
      return c;
    }));
  };

  const bringToFront = (id: string) => {
    setSelectedCardId(id);
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!selectedCardId) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) return;
      if (e.key === 'Delete' || e.key === 'Backspace') handleDeleteCard(selectedCardId);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardId, cards]);

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardId === card.id,
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      case CardType.GRID_PLANNER:
        return (
          <GridPlannerCard 
            {...commonProps} 
            allCards={cards}
            onUpdateContent={updateCardContent}
            onUnlink={handleUnlink}
            hoveredSlotIndex={hoveredGridId === card.id ? hoveredSlotIndex : null}
          />
        );
      default:
        return <PostCard {...commonProps} />;
    }
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#f3f4f6] relative overflow-hidden cursor-grab active:cursor-grabbing"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* 
        Multi-Layer Infinite Grid 
        Renders overlapping grid layers based on zoom level.
        Each layer has a fixed dot size (1.5px) but variable spacing.
      */}
      {gridLayers.map((layer) => (
        <div 
          key={layer.key}
          className="absolute inset-0 pointer-events-none transition-opacity duration-300 ease-linear"
          style={{
            // Use visual spacing for background size
            backgroundSize: `${layer.spacing}px ${layer.spacing}px`,
            // Pan directly maps to screen pixels, aligning all layers
            backgroundPosition: `${pan.x}px ${pan.y}px`,
            // Dot is always 1.5px screen size. We use rgba to handle opacity fade.
            backgroundImage: `radial-gradient(circle, rgba(156, 163, 175, ${layer.opacity}) 1.5px, transparent 1.5px)`,
            opacity: 1 // We handle opacity in the color, but could also use CSS opacity
          }}
        />
      ))}

      {/* World Transform Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
        }}
      >
        {cards.map(renderCard)}
      </div>

      {/* Scale Indicator */}
      <div className="absolute bottom-6 right-6 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-mono border border-gray-200 shadow-sm pointer-events-none text-gray-500">
        {Math.round(scale * 100)}%
      </div>
    </div>
  );
};

