import React, { useRef, useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Position, GridPlannerContent } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';
import { GridPlannerCard } from './cards/GridPlannerCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
}

// Layout constants matching GridPlannerCard Visuals
const GRID_HEADER_HEIGHT = 90; // Approx height of the Header section (Month + Year) including padding
const GRID_PADDING = 20;
const GRID_GAP = 8;

export const Canvas: React.FC<CanvasProps> = ({ cards, onCardsChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);

  // Dragging Logic for Snapping
  const [draggingCardId, setDraggingCardId] = useState<string | null>(null);
  const [hoveredGridId, setHoveredGridId] = useState<string | null>(null);
  const [hoveredSlotIndex, setHoveredSlotIndex] = useState<number | null>(null);

  // --- Infinite Background Logic ---
  const gridLayers = useMemo(() => {
    const layers = [];
    const baseSpacing = 40; // The fundamental grid unit in world space

    // Determine the "base power" of the current zoom level.
    const logScale = Math.log10(scale);
    const currentPower = Math.floor(logScale);

    // We render a window of scales around the current power to ensure seamless continuity
    for (let i = -1; i <= 1; i++) {
      const power = -currentPower + i; 
      const worldSpacing = baseSpacing * Math.pow(10, power);
      const visualSpacing = worldSpacing * scale;

      // Revised Opacity Curve for Smoothness
      let rawOpacity = 0;

      if (visualSpacing >= 15 && visualSpacing <= 250) {
        if (visualSpacing < 50) {
           rawOpacity = (visualSpacing - 15) / 35;
        } else if (visualSpacing > 100) {
           rawOpacity = 1 - (visualSpacing - 100) / 150;
        } else {
           rawOpacity = 1;
        }
      }

      // Clamp and Dampen
      const finalOpacity = Math.max(0, Math.min(1, rawOpacity)) * 0.3;

      if (finalOpacity > 0.01) {
        layers.push({
          spacing: visualSpacing,
          opacity: finalOpacity,
          key: `grid-layer-${power}`
        });
      }
    }
    return layers;
  }, [scale]);

  const handleWheel = (e: WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const s = Math.exp(-e.deltaY * 0.005);
      setScale(prev => Math.min(Math.max(0.05, prev * s), 10)); 
    } else {
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button === 0 || e.button === 1) {
      setIsPanning(true);
      setLastMousePos({ x: e.clientX, y: e.clientY });
      setSelectedCardId(null); 
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    // 1. Pan Canvas
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
      return;
    }

    // 2. Drag Collision Detection (Snapping Logic)
    if (draggingCardId) {
      const draggedCard = cards.find(c => c.id === draggingCardId);
      if (draggedCard && draggedCard.type === CardType.POST) {
        // Find if we are hovering over any GRID_PLANNER
        const mouseXWorld = (e.clientX - pan.x) / scale;
        const mouseYWorld = (e.clientY - pan.y) / scale;

        let foundGridId: string | null = null;
        let foundSlotIndex: number | null = null;

        for (const card of cards) {
          if (card.type === CardType.GRID_PLANNER) {
            // Check bounding box
            if (
              mouseXWorld >= card.x && 
              mouseXWorld <= card.x + card.width &&
              mouseYWorld >= card.y && 
              mouseYWorld <= card.y + card.height
            ) {
              foundGridId = card.id;

              // Calculate specific slot based on the GridPlannerCard layout
              // Layout: Padding=20, Header~90px top.
              // Grid: 3 columns.

              const contentWidth = card.width - (GRID_PADDING * 2);
              const colWidth = (contentWidth - (2 * GRID_GAP)) / 3;
              const rowHeight = colWidth * 1.25; // 4:5 aspect ratio

              // Relative position inside the card's "grid area"
              // We assume the scroll is at top for drag detection simplicity in this version
              // or that the card fits the content.
              const relativeX = mouseXWorld - (card.x + GRID_PADDING);
              const relativeY = mouseYWorld - (card.y + GRID_HEADER_HEIGHT);

              if (relativeX >= 0 && relativeY >= 0) {
                 const col = Math.floor(relativeX / (colWidth + GRID_GAP));
                 const row = Math.floor(relativeY / (rowHeight + GRID_GAP));

                 // If within bounds of columns
                 if (col >= 0 && col < 3 && row >= 0) {
                   foundSlotIndex = (row * 3) + col;
                 }
              }
              break; // Found the top-most grid
            }
          }
        }

        setHoveredGridId(foundGridId);
        setHoveredSlotIndex(foundSlotIndex);
      }
    }
  };

  const handleMouseUp = () => {
    // Logic for Dropping a Post Card onto a Grid Slot
    if (draggingCardId && hoveredGridId && hoveredSlotIndex !== null) {
      const grid = cards.find(c => c.id === hoveredGridId);
      const post = cards.find(c => c.id === draggingCardId);

      if (grid && post) {
        // 1. Calculate the date for this slot using the SAME logic as GridPlannerCard
        const content = grid.content as GridPlannerContent;
        const defaultConfig = { month: new Date().getMonth(), year: new Date().getFullYear(), logicType: 'frequency', value: 3 };
        const { month, year, logicType, value } = content.config || defaultConfig;

        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const generatedSlots: Date[] = [];

        // Logic must strictly match GridPlannerCard.tsx
        if (logicType === 'frequency') {
            const step = Math.max(1, value);
            for (let d = 1; d <= daysInMonth; d += step) {
               generatedSlots.push(new Date(year, month, d));
            }
        } else {
            const count = Math.max(1, Math.min(value, daysInMonth));
            const step = daysInMonth / count;
            for (let i = 0; i < count; i++) {
               const day = Math.floor(1 + (i * step));
               generatedSlots.push(new Date(year, month, day));
            }
        }

        let slotDateStr = "";
        // Only assign if the slot index actually exists in the generated logic
        if (hoveredSlotIndex < generatedSlots.length) {
            // YYYY-MM-DD format for input[type="date"]
            const d = generatedSlots[hoveredSlotIndex];
            // Adjust for local timezone to ensure YYYY-MM-DD is correct
            const offset = d.getTimezoneOffset();
            const localDate = new Date(d.getTime() - (offset*60*1000));
            slotDateStr = localDate.toISOString().split('T')[0];
        }

        // 2. Update Cards
        const newCards = cards.map(c => {
          if (c.id === hoveredGridId) {
            // Link Post to Grid Slot
            return {
              ...c,
              content: {
                ...c.content,
                connections: {
                  ...c.content.connections,
                  [hoveredSlotIndex]: draggingCardId
                }
              }
            };
          }
          if (c.id === draggingCardId) {
            // Update Post Date
            return {
              ...c,
              content: {
                ...c.content,
                date: slotDateStr // Apply the calculated date
              }
            };
          }
          return c;
        });

        onCardsChange(newCards);
      }
    }

    setIsPanning(false);
    setDraggingCardId(null);
    setHoveredGridId(null);
    setHoveredSlotIndex(null);
  };

  // --- CRUD Handlers ---

  const updateCardPosition = (id: string, x: number, y: number) => {
    // This runs on every frame of drag, so we hook into it to track dragging state
    if (draggingCardId !== id) setDraggingCardId(id);
    onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
  };

  const updateCardContent = (id: string, content: any) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, content } : c));
  };

  const handleDeleteCard = (id: string) => {
    onCardsChange(cards.filter(c => c.id !== id));
    if (selectedCardId === id) setSelectedCardId(null);
  };

  const handleUnlink = (gridId: string, slotIndex: number, postCardId: string) => {
    onCardsChange(cards.map(c => {
      if (c.id === gridId) {
        const newConnections = { ...c.content.connections };
        delete newConnections[slotIndex];
        return { ...c, content: { ...c.content, connections: newConnections }};
      }
      return c;
    }));
  };

  const bringToFront = (id: string) => {
    setSelectedCardId(id);
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!selectedCardId) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) return;
      if (e.key === 'Delete' || e.key === 'Backspace') handleDeleteCard(selectedCardId);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardId, cards]);

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardId === card.id,
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      case CardType.GRID_PLANNER:
        return (
          <GridPlannerCard 
            {...commonProps} 
            allCards={cards}
            onUpdateContent={updateCardContent}
            onUnlink={handleUnlink}
            hoveredSlotIndex={hoveredGridId === card.id ? hoveredSlotIndex : null}
          />
        );
      default:
        return <PostCard {...commonProps} />;
    }
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#f3f4f6] relative overflow-hidden cursor-grab active:cursor-grabbing"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* 
        Multi-Layer Infinite Grid 
        Renders overlapping grid layers based on zoom level.
      */}
      {gridLayers.map((layer) => (
        <div 
          key={layer.key}
          className="absolute inset-0 pointer-events-none"
          style={{
            // Use visual spacing for background size
            backgroundSize: `${layer.spacing}px ${layer.spacing}px`,
            // Pan directly maps to screen pixels, aligning all layers
            backgroundPosition: `${pan.x}px ${pan.y}px`,
            // Dot is always 1.5px screen size. Use subtle gray with calculated opacity.
            backgroundImage: `radial-gradient(circle, rgba(156, 163, 175, ${layer.opacity}) 1.5px, transparent 1.5px)`,
            opacity: 1 
          }}
        />
      ))}

      {/* World Transform Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
        }}
      >
        {cards.map(renderCard)}
      </div>

      {/* Scale Indicator */}
      <div className="absolute bottom-6 right-6 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-mono border border-gray-200 shadow-sm pointer-events-none text-gray-500">
        {Math.round(scale * 100)}%
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { CardData, CardType } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title: string;
  accentColor?: string;
  icon?: React.ReactNode;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, 
  zoomScale,
  children,
  title,
  icon
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Identify cards that function as "mini-apps" and need a fixed viewport
  const isFixedLayout = [CardType.GRID_PLANNER, CardType.ANALYTICS, CardType.PERSONA].includes(card.type);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isFullscreen) return;

    // IMPORTANT: Stop propagation to ensure the Canvas doesn't receive this event.
    e.stopPropagation();

    // Select the card immediately on click
    onSelect(card.id);

    const target = e.target as HTMLElement;

    // Check if the user is interacting with inputs, buttons, or scrollbars
    const isInteractive = 
      target.tagName === 'INPUT' || 
      target.tagName === 'TEXTAREA' || 
      target.tagName === 'BUTTON' || 
      target.closest('button') ||
      target.closest('.no-drag'); // Class to manually opt-out of dragging

    if (!isInteractive) {
      setIsDragging(true);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    }
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale]);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFullscreen(!isFullscreen);
  };

  const getSelectionStyles = () => {
    if (isFullscreen) return 'fixed inset-0 z-[9999] w-full h-full rounded-none bg-white overflow-auto';

    const colors = {
      [CardType.POST]: { ring: 'ring-purple-500', hover: 'hover:ring-purple-300' },
      [CardType.STRATEGY_AI]: { ring: 'ring-indigo-500', hover: 'hover:ring-indigo-300' },
      [CardType.ANALYTICS]: { ring: 'ring-emerald-500', hover: 'hover:ring-emerald-300' },
      [CardType.PERSONA]: { ring: 'ring-orange-500', hover: 'hover:ring-orange-300' },
      [CardType.GRID_PLANNER]: { ring: 'ring-blue-400', hover: 'hover:ring-blue-300' },
    }[card.type] || { ring: 'ring-gray-400', hover: 'hover:ring-gray-300' };

    const base = "flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] cursor-grab active:cursor-grabbing";
    const positionClass = isFullscreen ? '' : 'absolute';

    if (isSelected) {
      return `${base} ${positionClass} shadow-[0_20px_40px_-12px_rgba(0,0,0,0.12)] z-50 scale-[1.005] ring-2 ring-offset-0 ${colors.ring}`;
    } else {
      return `${base} ${positionClass} shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)] hover:ring-2 hover:ring-offset-0 ${colors.hover}`;
    }
  };

  const cardContent = (
    <div
      ref={containerRef}
      className={getSelectionStyles()}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        // Critical Fix: Fixed layout cards (Grid/Analytics) must enforce exact height to allow internal scrolling.
        height: isFixedLayout ? card.height : 'auto', 
        minHeight: isFixedLayout ? undefined : card.height,
        borderRadius: '24px',
      } : {}}
      onMouseDown={handleMouseDown} 
      onClick={(e) => e.stopPropagation()}
    >
      {/* Header - Native iOS feel */}
      <div 
        className={`flex items-center justify-between px-5 pt-5 pb-2 rounded-t-[24px] select-none shrink-0`}
      >
        <div className="flex items-center gap-2.5 text-gray-900">
          <span className="text-gray-400">{icon}</span>
          <span className="text-[13px] font-semibold tracking-tight text-gray-500">{title}</span>
        </div>

        <button 
          onClick={toggleFullscreen} 
          className="w-6 h-6 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:bg-gray-200 hover:text-gray-600 transition-colors"
        >
          {isFullscreen ? <Minimize2 size={14} /> : <Maximize2 size={14} />}
        </button>
      </div>

      {/* Content Area */}
      {/* Critical Fix: Removed padding for Fixed Layouts to allow full-bleed scroll containers */}
      <div className={`flex-1 flex flex-col min-h-0 ${isFixedLayout ? 'overflow-hidden rounded-b-[24px]' : 'px-5 pb-5 overflow-visible'}`}>
        {children}
      </div>
    </div>
  );

  if (isFullscreen) {
    return createPortal(cardContent, document.body);
  }

  return cardContent;
};

import React, { useState, useEffect, useMemo } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, GridConfig, GridPlannerContent, MediaItem } from '../../types';
import { Settings, X, LayoutGrid, ChevronRight } from 'lucide-react';

interface GridPlannerCardProps {
  card: CardData;
  allCards: CardData[];
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onUnlink: (gridId: string, slotIndex: number, postCardId: string) => void;
  hoveredSlotIndex?: number | null;
  zoomScale: number;
}

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June', 
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const GridPlannerCard: React.FC<GridPlannerCardProps> = (props) => {
  const { card, allCards, onUpdateContent, onUnlink, hoveredSlotIndex } = props;
  const content = card.content as GridPlannerContent;

  const [isFlipped, setIsFlipped] = useState(false);

  const defaultConfig: GridConfig = {
    month: new Date().getMonth(),
    year: new Date().getFullYear(),
    logicType: 'frequency',
    value: 3
  };

  const [tempConfig, setTempConfig] = useState<GridConfig>(content.config || defaultConfig);

  useEffect(() => {
    if (!content.config) {
      onUpdateContent(card.id, {
        ...content,
        title: "Social Planner",
        connections: {},
        config: defaultConfig
      });
    }
  }, []);

  const handleSaveSettings = () => {
    onUpdateContent(card.id, { ...content, config: tempConfig });
    setIsFlipped(false);
  };

  const slots = useMemo(() => {
    const { month, year, logicType, value } = content.config || tempConfig;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const generatedSlots: { date: Date; label: string; index: number }[] = [];

    if (logicType === 'frequency') {
      const step = Math.max(1, value);
      for (let d = 1; d <= daysInMonth; d += step) {
        generatedSlots.push({
          date: new Date(year, month, d),
          label: `${d}`, 
          index: generatedSlots.length
        });
      }
    } else {
      const count = Math.max(1, Math.min(value, daysInMonth));
      const step = daysInMonth / count;
      for (let i = 0; i < count; i++) {
        const day = Math.floor(1 + (i * step));
        generatedSlots.push({
          date: new Date(year, month, day),
          label: `${day}`,
          index: i
        });
      }
    }
    return generatedSlots;
  }, [content.config, tempConfig]);

  const renderFront = () => (
    <div className="flex flex-col h-full bg-white relative">
        {/* Header Area */}
        <div className="px-5 pt-2 pb-3 bg-white z-10 shrink-0">
            <div className="text-[13px] font-semibold text-gray-400 uppercase tracking-wide">
                {MONTHS[content.config?.month || 0]}
            </div>
            <div className="text-[32px] font-bold text-gray-900 leading-none tracking-tight">
                {content.config?.year}
            </div>
        </div>

        {/* Grid Scroll Area */}
        <div className="flex-1 overflow-y-auto px-5 pb-2 no-scrollbar min-h-0">
            <div className="grid grid-cols-3 gap-2 auto-rows-min pb-4">
                {slots.map((slot, i) => {
                const connectedCardId = content.connections?.[i];
                const connectedCard = connectedCardId ? allCards.find(c => c.id === connectedCardId) : null;

                let previewMedia: MediaItem | undefined;
                if (connectedCard && connectedCard.content.finalAssets?.length > 0) {
                    previewMedia = connectedCard.content.finalAssets[0];
                }

                const isHovered = hoveredSlotIndex === i;

                return (
                    <div 
                    key={i}
                    className={`
                        aspect-[4/5] rounded-xl relative group transition-all duration-300 ease-out
                        ${connectedCard 
                            ? 'bg-white shadow-sm ring-1 ring-black/5' 
                            : 'bg-gray-50 border border-dashed border-gray-200 hover:border-blue-300 hover:bg-blue-50/10'
                        }
                        ${isHovered ? 'ring-2 ring-blue-500 bg-blue-50/50 border-blue-400 scale-105 z-20 shadow-lg' : ''}
                    `}
                    >
                        {connectedCard ? (
                            <>
                                {previewMedia?.type === 'image' && (
                                    <img src={previewMedia.url} className="w-full h-full object-cover rounded-xl select-none pointer-events-none" />
                                )}
                                {previewMedia?.type === 'video' && (
                                    <video src={previewMedia.url} className="w-full h-full object-cover rounded-xl select-none pointer-events-none" />
                                )}
                                {!previewMedia && (
                                    <div className="w-full h-full flex flex-col items-center justify-center p-2 text-center bg-gray-100 rounded-xl">
                                        <LayoutGrid size={20} className="text-gray-300 mb-1" />
                                        <span className="text-[9px] font-semibold text-gray-500 line-clamp-2 leading-tight">
                                            {connectedCard.content.title || "Untitled"}
                                        </span>
                                    </div>
                                )}

                                <div className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onUnlink(card.id, i, connectedCard.id); }}
                                        className="w-5 h-5 bg-white/90 backdrop-blur rounded-full text-red-500 shadow-sm flex items-center justify-center hover:scale-110 active:scale-95 transition-transform"
                                    >
                                        <X size={10} strokeWidth={3} />
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="w-full h-full flex flex-col items-center justify-center text-gray-300 pointer-events-none">
                                {isHovered && <div className="text-blue-500 font-bold text-[10px] animate-pulse">DROP</div>}
                            </div>
                        )}

                        <div className={`
                            absolute top-1 left-1 px-1.5 py-0.5 rounded-md text-[9px] font-bold tracking-tight shadow-sm pointer-events-none
                            ${connectedCard ? 'bg-black/60 text-white backdrop-blur-md' : 'bg-white text-gray-400 ring-1 ring-black/5'}
                        `}>
                            {slot.label}
                        </div>
                    </div>
                );
                })}
            </div>
        </div>

        {/* Footer / Action Bar */}
        <div className="mt-auto px-5 py-3 border-t border-gray-100 flex items-center justify-between bg-white shrink-0">
            <div className="flex items-center gap-2">
                <div className="flex -space-x-2">
                    <div className="w-7 h-7 rounded-full bg-blue-100 flex items-center justify-center text-[10px] font-bold text-blue-600 ring-2 ring-white shadow-sm">
                        {slots.length}
                    </div>
                </div>
                <span className="text-[13px] font-medium text-gray-400">Total Posts</span>
            </div>

            <button 
                onClick={(e) => { e.stopPropagation(); setIsFlipped(true); setTempConfig(content.config || defaultConfig); }}
                className="w-9 h-9 rounded-full bg-gray-50 text-gray-500 hover:bg-gray-100 hover:text-gray-900 transition-all flex items-center justify-center active:scale-95"
            >
                <Settings size={18} />
            </button>
        </div>
    </div>
  );

  const renderBack = () => (
    <div className="flex flex-col h-full bg-[#F2F2F7] relative">
        {/* Settings Header */}
        <div className="px-4 py-3 bg-white border-b border-gray-200 flex items-center justify-between shrink-0">
            <span className="text-[15px] font-semibold text-gray-900">Settings</span>
            <button 
                onClick={(e) => { e.stopPropagation(); handleSaveSettings(); }}
                className="text-[15px] font-semibold text-[#007AFF] hover:opacity-80 transition-opacity"
            >
                Done
            </button>
        </div>

        {/* Settings Form */}
        <div className="p-4 space-y-6 overflow-y-auto flex-1">
            <div className="space-y-1.5">
                <div className="text-[12px] font-medium text-gray-500 uppercase ml-3">Timeframe</div>
                <div className="bg-white rounded-xl overflow-hidden shadow-sm border border-gray-200">
                    <div className="flex items-center justify-between px-4 py-2.5 border-b border-gray-100">
                        <span className="text-[15px] text-gray-900">Month</span>
                        <div className="relative">
                            <select 
                                className="appearance-none bg-transparent text-[15px] text-gray-500 focus:ring-0 border-none pr-6 cursor-pointer text-right"
                                value={tempConfig.month}
                                onChange={e => setTempConfig({...tempConfig, month: parseInt(e.target.value)})}
                            >
                                {MONTHS.map((m, i) => <option key={i} value={i}>{m}</option>)}
                            </select>
                            <ChevronRight size={14} className="absolute right-0 top-1/2 -translate-y-1/2 text-gray-300 pointer-events-none" />
                        </div>
                    </div>
                    <div className="flex items-center justify-between px-4 py-2.5">
                        <span className="text-[15px] text-gray-900">Year</span>
                        <input 
                            type="number"
                            className="text-[15px] text-gray-500 bg-transparent border-none focus:ring-0 text-right w-20 p-0"
                            value={tempConfig.year}
                            onChange={e => setTempConfig({...tempConfig, year: parseInt(e.target.value)})}
                        />
                    </div>
                </div>
            </div>

            <div className="space-y-1.5">
                <div className="text-[12px] font-medium text-gray-500 uppercase ml-3">Cadence</div>
                <div className="bg-gray-200/50 p-1 rounded-xl flex mb-3">
                    <button 
                        className={`flex-1 py-1.5 text-[13px] font-medium rounded-lg transition-all shadow-sm ${tempConfig.logicType === 'frequency' ? 'bg-white text-gray-900' : 'bg-transparent text-gray-500 hover:text-gray-700 shadow-none'}`}
                        onClick={() => setTempConfig({...tempConfig, logicType: 'frequency'})}
                    >
                        Frequency
                    </button>
                    <button 
                        className={`flex-1 py-1.5 text-[13px] font-medium rounded-lg transition-all shadow-sm ${tempConfig.logicType === 'count' ? 'bg-white text-gray-900' : 'bg-transparent text-gray-500 hover:text-gray-700 shadow-none'}`}
                        onClick={() => setTempConfig({...tempConfig, logicType: 'count'})}
                    >
                        Total Count
                    </button>
                </div>

                <div className="bg-white rounded-xl overflow-hidden shadow-sm border border-gray-200 px-4 py-3 flex items-center justify-between">
                    <span className="text-[15px] text-gray-900">
                        {tempConfig.logicType === 'frequency' ? 'Every X Days' : 'Total Posts'}
                    </span>
                    <div className="flex items-center gap-3 bg-gray-50 rounded-lg p-1">
                        <button 
                            className="w-7 h-7 rounded-md bg-white shadow-sm border border-gray-100 flex items-center justify-center text-gray-600 hover:bg-gray-50 active:scale-95 transition-all"
                            onClick={() => setTempConfig({...tempConfig, value: Math.max(1, tempConfig.value - 1)})}
                        >
                            -
                        </button>
                        <span className="text-[15px] font-semibold w-6 text-center tabular-nums">{tempConfig.value}</span>
                        <button 
                            className="w-7 h-7 rounded-md bg-white shadow-sm border border-gray-100 flex items-center justify-center text-gray-600 hover:bg-gray-50 active:scale-95 transition-all"
                            onClick={() => setTempConfig({...tempConfig, value: tempConfig.value + 1})}
                        >
                            +
                        </button>
                    </div>
                </div>
                <p className="text-[11px] text-gray-400 ml-3 leading-snug pr-2">
                    {tempConfig.logicType === 'frequency' 
                        ? `Auto-generate a post slot every ${tempConfig.value} days.` 
                        : `Distribute ${tempConfig.value} posts evenly across the month.`}
                </p>
            </div>
        </div>
    </div>
  );

  return (
    <BaseCard 
      {...props} 
      title={content.title || "Grid Planner"} 
      icon={<LayoutGrid size={16} className="text-[#007AFF]"/>}
    >
      <div 
        className="relative w-full h-full group/card"
        style={{ perspective: '1000px' }}
      >
        <div 
          className="w-full h-full transition-transform duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] relative"
          style={{ 
            transformStyle: 'preserve-3d',
            transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)' 
          }}
        >
          {/* Front Face */}
          <div 
            className="absolute inset-0 w-full h-full"
            style={{ backfaceVisibility: 'hidden' }}
          >
             {renderFront()}
          </div>

          {/* Back Face */}
          <div 
            className="absolute inset-0 w-full h-full"
            style={{ 
              transform: 'rotateY(180deg)',
              backfaceVisibility: 'hidden' 
            }}
          >
             {renderBack()}
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Position, GridPlannerContent } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';
import { GridPlannerCard } from './cards/GridPlannerCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
}

// Layout constants matching GridPlannerCard Visuals
// Offset = BaseCard Header (~50px) + GridPlanner Internal Header (~82px)
const GRID_HEADER_HEIGHT = 132; 
const GRID_PADDING = 20;
const GRID_GAP = 8;

export const Canvas: React.FC<CanvasProps> = ({ cards, onCardsChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);

  // Dragging Logic for Snapping
  const [draggingCardId, setDraggingCardId] = useState<string | null>(null);
  const [hoveredGridId, setHoveredGridId] = useState<string | null>(null);
  const [hoveredSlotIndex, setHoveredSlotIndex] = useState<number | null>(null);

  // --- Infinite Background Logic ---
  const gridLayers = useMemo(() => {
    const layers = [];
    const baseSpacing = 40; // The fundamental grid unit in world space

    // Determine the "base power" of the current zoom level.
    const logScale = Math.log10(scale);
    const currentPower = Math.floor(logScale);

    // We render a window of scales around the current power to ensure seamless continuity
    for (let i = -1; i <= 1; i++) {
      const power = -currentPower + i; 
      const worldSpacing = baseSpacing * Math.pow(10, power);
      const visualSpacing = worldSpacing * scale;

      // Revised Opacity Curve for Smoothness
      let rawOpacity = 0;

      if (visualSpacing >= 15 && visualSpacing <= 250) {
        if (visualSpacing < 50) {
           rawOpacity = (visualSpacing - 15) / 35;
        } else if (visualSpacing > 100) {
           rawOpacity = 1 - (visualSpacing - 100) / 150;
        } else {
           rawOpacity = 1;
        }
      }

      // Clamp and Dampen
      const finalOpacity = Math.max(0, Math.min(1, rawOpacity)) * 0.3;

      if (finalOpacity > 0.01) {
        layers.push({
          spacing: visualSpacing,
          opacity: finalOpacity,
          key: `grid-layer-${power}`
        });
      }
    }
    return layers;
  }, [scale]);

  const handleWheel = (e: WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const s = Math.exp(-e.deltaY * 0.005);
      setScale(prev => Math.min(Math.max(0.05, prev * s), 10)); 
    } else {
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button === 0 || e.button === 1) {
      setIsPanning(true);
      setLastMousePos({ x: e.clientX, y: e.clientY });
      setSelectedCardId(null); 
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    // 1. Pan Canvas
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
      return;
    }

    // 2. Drag Collision Detection (Snapping Logic)
    if (draggingCardId) {
      const draggedCard = cards.find(c => c.id === draggingCardId);
      if (draggedCard && draggedCard.type === CardType.POST) {
        // Find if we are hovering over any GRID_PLANNER
        const mouseXWorld = (e.clientX - pan.x) / scale;
        const mouseYWorld = (e.clientY - pan.y) / scale;

        let foundGridId: string | null = null;
        let foundSlotIndex: number | null = null;

        for (const card of cards) {
          if (card.type === CardType.GRID_PLANNER) {
            // Check bounding box
            if (
              mouseXWorld >= card.x && 
              mouseXWorld <= card.x + card.width &&
              mouseYWorld >= card.y && 
              mouseYWorld <= card.y + card.height
            ) {
              foundGridId = card.id;

              const contentWidth = card.width - (GRID_PADDING * 2);
              const colWidth = (contentWidth - (2 * GRID_GAP)) / 3;
              const rowHeight = colWidth * 1.25; // 4:5 aspect ratio

              // Relative position inside the card's "grid area"
              // Adjust relative Y for combined headers (BaseCard + GridPlanner headers)
              const relativeX = mouseXWorld - (card.x + GRID_PADDING);
              const relativeY = mouseYWorld - (card.y + GRID_HEADER_HEIGHT);

              if (relativeX >= 0 && relativeY >= 0) {
                 const col = Math.floor(relativeX / (colWidth + GRID_GAP));
                 const row = Math.floor(relativeY / (rowHeight + GRID_GAP));

                 // If within bounds of columns
                 if (col >= 0 && col < 3 && row >= 0) {
                   foundSlotIndex = (row * 3) + col;
                 }
              }
              break; // Found the top-most grid
            }
          }
        }

        setHoveredGridId(foundGridId);
        setHoveredSlotIndex(foundSlotIndex);
      }
    }
  };

  const handleMouseUp = () => {
    // Logic for Dropping a Post Card onto a Grid Slot
    if (draggingCardId && hoveredGridId && hoveredSlotIndex !== null) {
      const grid = cards.find(c => c.id === hoveredGridId);
      const post = cards.find(c => c.id === draggingCardId);

      if (grid && post) {
        // 1. Calculate the date for this slot using the SAME logic as GridPlannerCard
        const content = grid.content as GridPlannerContent;
        const defaultConfig = { month: new Date().getMonth(), year: new Date().getFullYear(), logicType: 'frequency', value: 3 };
        const { month, year, logicType, value } = content.config || defaultConfig;

        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const generatedSlots: Date[] = [];

        // Logic must strictly match GridPlannerCard.tsx
        if (logicType === 'frequency') {
            const step = Math.max(1, value);
            for (let d = 1; d <= daysInMonth; d += step) {
               generatedSlots.push(new Date(year, month, d));
            }
        } else {
            const count = Math.max(1, Math.min(value, daysInMonth));
            const step = daysInMonth / count;
            for (let i = 0; i < count; i++) {
               const day = Math.floor(1 + (i * step));
               generatedSlots.push(new Date(year, month, day));
            }
        }

        let slotDateStr = "";
        // Only assign if the slot index actually exists in the generated logic
        if (hoveredSlotIndex < generatedSlots.length) {
            // YYYY-MM-DD format for input[type="date"]
            const d = generatedSlots[hoveredSlotIndex];
            // Adjust for local timezone to ensure YYYY-MM-DD is correct
            const offset = d.getTimezoneOffset();
            const localDate = new Date(d.getTime() - (offset*60*1000));
            slotDateStr = localDate.toISOString().split('T')[0];
        }

        // 2. Update Cards
        const newCards = cards.map(c => {
          if (c.id === hoveredGridId) {
            // Link Post to Grid Slot
            return {
              ...c,
              content: {
                ...c.content,
                connections: {
                  ...c.content.connections,
                  [hoveredSlotIndex]: draggingCardId
                }
              }
            };
          }
          if (c.id === draggingCardId) {
            // Update Post Date
            return {
              ...c,
              content: {
                ...c.content,
                date: slotDateStr // Apply the calculated date
              }
            };
          }
          return c;
        });

        onCardsChange(newCards);
      }
    }

    setIsPanning(false);
    setDraggingCardId(null);
    setHoveredGridId(null);
    setHoveredSlotIndex(null);
  };

  // --- CRUD Handlers ---

  const updateCardPosition = (id: string, x: number, y: number) => {
    // This runs on every frame of drag, so we hook into it to track dragging state
    if (draggingCardId !== id) setDraggingCardId(id);
    onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
  };

  const updateCardContent = (id: string, content: any) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, content } : c));
  };

  const handleDeleteCard = (id: string) => {
    onCardsChange(cards.filter(c => c.id !== id));
    if (selectedCardId === id) setSelectedCardId(null);
  };

  const handleUnlink = (gridId: string, slotIndex: number, postCardId: string) => {
    onCardsChange(cards.map(c => {
      if (c.id === gridId) {
        const newConnections = { ...c.content.connections };
        delete newConnections[slotIndex];
        return { ...c, content: { ...c.content, connections: newConnections }};
      }
      return c;
    }));
  };

  const bringToFront = (id: string) => {
    setSelectedCardId(id);
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!selectedCardId) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) return;
      if (e.key === 'Delete' || e.key === 'Backspace') handleDeleteCard(selectedCardId);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardId, cards]);

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardId === card.id,
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      case CardType.GRID_PLANNER:
        return (
          <GridPlannerCard 
            {...commonProps} 
            allCards={cards}
            onUpdateContent={updateCardContent}
            onUnlink={handleUnlink}
            hoveredSlotIndex={hoveredGridId === card.id ? hoveredSlotIndex : null}
          />
        );
      default:
        return <PostCard {...commonProps} />;
    }
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#f3f4f6] relative overflow-hidden cursor-grab active:cursor-grabbing"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* 
        Multi-Layer Infinite Grid 
        Renders overlapping grid layers based on zoom level.
      */}
      {gridLayers.map((layer) => (
        <div 
          key={layer.key}
          className="absolute inset-0 pointer-events-none"
          style={{
            // Use visual spacing for background size
            backgroundSize: `${layer.spacing}px ${layer.spacing}px`,
            // Pan directly maps to screen pixels, aligning all layers
            backgroundPosition: `${pan.x}px ${pan.y}px`,
            // Dot is always 1.5px screen size. Use subtle gray with calculated opacity.
            backgroundImage: `radial-gradient(circle, rgba(156, 163, 175, ${layer.opacity}) 1.5px, transparent 1.5px)`,
            opacity: 1 
          }}
        />
      ))}

      {/* World Transform Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
        }}
      >
        {cards.map(renderCard)}
      </div>

      {/* Scale Indicator */}
      <div className="absolute bottom-6 right-6 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-mono border border-gray-200 shadow-sm pointer-events-none text-gray-500">
        {Math.round(scale * 100)}%
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, GridConfig, GridPlannerContent, MediaItem } from '../../types';
import { Settings, X, LayoutGrid, ChevronRight, Calendar } from 'lucide-react';

interface GridPlannerCardProps {
  card: CardData;
  allCards: CardData[];
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onUnlink: (gridId: string, slotIndex: number, postCardId: string) => void;
  hoveredSlotIndex?: number | null;
  zoomScale: number;
}

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June', 
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const GridPlannerCard: React.FC<GridPlannerCardProps> = (props) => {
  const { card, allCards, onUpdateContent, onUnlink, hoveredSlotIndex } = props;
  const content = card.content as GridPlannerContent;

  const [isFlipped, setIsFlipped] = useState(false);

  const defaultConfig: GridConfig = {
    month: new Date().getMonth(),
    year: new Date().getFullYear(),
    logicType: 'frequency',
    value: 3
  };

  const [tempConfig, setTempConfig] = useState<GridConfig>(content.config || defaultConfig);

  useEffect(() => {
    if (!content.config) {
      onUpdateContent(card.id, {
        ...content,
        title: "Social Planner",
        connections: {},
        config: defaultConfig
      });
    }
  }, []);

  const handleSaveSettings = () => {
    onUpdateContent(card.id, { ...content, config: tempConfig });
    setIsFlipped(false);
  };

  const slots = useMemo(() => {
    const { month, year, logicType, value } = content.config || tempConfig;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const generatedSlots: { date: Date; label: string; index: number }[] = [];

    if (logicType === 'frequency') {
      const step = Math.max(1, value);
      for (let d = 1; d <= daysInMonth; d += step) {
        generatedSlots.push({
          date: new Date(year, month, d),
          label: `${d}`, 
          index: generatedSlots.length
        });
      }
    } else {
      const count = Math.max(1, Math.min(value, daysInMonth));
      const step = daysInMonth / count;
      for (let i = 0; i < count; i++) {
        const day = Math.floor(1 + (i * step));
        generatedSlots.push({
          date: new Date(year, month, day),
          label: `${day}`,
          index: i
        });
      }
    }
    return generatedSlots;
  }, [content.config, tempConfig]);

  const renderFront = () => (
    <div className="flex flex-col h-full bg-white relative">
        {/* Header Area - Matches PostCard Title Block typography */}
        <div className="px-5 pt-1 pb-4 bg-white z-10 shrink-0 space-y-1">
            <div className="w-full font-bold text-[28px] leading-tight text-gray-900 tracking-tight">
                {content.config?.year}
            </div>
            <div className="flex items-center gap-2 text-[13px] font-medium text-gray-500">
                <Calendar size={13} className="text-gray-400"/>
                <span className="uppercase tracking-wide">{MONTHS[content.config?.month || 0]}</span>
            </div>
        </div>

        {/* Grid Scroll Area */}
        <div className="flex-1 overflow-y-auto px-5 pb-2 no-scrollbar min-h-0">
            <div className="grid grid-cols-3 gap-3 auto-rows-min pb-4">
                {slots.map((slot, i) => {
                const connectedCardId = content.connections?.[i];
                const connectedCard = connectedCardId ? allCards.find(c => c.id === connectedCardId) : null;

                let previewMedia: MediaItem | undefined;
                if (connectedCard && connectedCard.content.finalAssets?.length > 0) {
                    previewMedia = connectedCard.content.finalAssets[0];
                }

                const isHovered = hoveredSlotIndex === i;

                return (
                    <div 
                    key={i}
                    className={`
                        aspect-[4/5] rounded-xl relative group transition-all duration-200 ease-out
                        ${connectedCard 
                            ? 'bg-white shadow-sm ring-1 ring-black/5' 
                            : 'bg-white border border-dashed border-gray-300 hover:border-[#007AFF] hover:bg-gray-50'
                        }
                        ${isHovered ? 'ring-2 ring-[#007AFF] border-transparent scale-[1.02] z-20 shadow-lg' : ''}
                    `}
                    >
                        {connectedCard ? (
                            <>
                                {previewMedia?.type === 'image' && (
                                    <img src={previewMedia.url} className="w-full h-full object-cover rounded-xl select-none pointer-events-none" />
                                )}
                                {previewMedia?.type === 'video' && (
                                    <video src={previewMedia.url} className="w-full h-full object-cover rounded-xl select-none pointer-events-none" />
                                )}
                                {!previewMedia && (
                                    <div className="w-full h-full flex flex-col items-center justify-center p-2 text-center bg-gray-50 rounded-xl">
                                        <LayoutGrid size={20} className="text-gray-300 mb-1" />
                                        <span className="text-[9px] font-semibold text-gray-500 line-clamp-2 leading-tight">
                                            {connectedCard.content.title || "Untitled"}
                                        </span>
                                    </div>
                                )}

                                <div className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onUnlink(card.id, i, connectedCard.id); }}
                                        className="w-5 h-5 bg-white/90 backdrop-blur rounded-full text-red-500 shadow-sm flex items-center justify-center hover:scale-110 active:scale-95 transition-transform"
                                    >
                                        <X size={10} strokeWidth={3} />
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="w-full h-full flex flex-col items-center justify-center text-gray-300 pointer-events-none">
                                {isHovered && <div className="text-[#007AFF] font-bold text-[10px] animate-pulse">DROP</div>}
                            </div>
                        )}

                        <div className={`
                            absolute top-1 left-1 px-1.5 py-0.5 rounded-md text-[9px] font-bold tracking-tight shadow-sm pointer-events-none
                            ${connectedCard ? 'bg-black/60 text-white backdrop-blur-md' : 'bg-white text-gray-400 ring-1 ring-black/5'}
                        `}>
                            {slot.label}
                        </div>
                    </div>
                );
                })}
            </div>
        </div>

        {/* Footer / Action Bar - Matches PostCard Footer structure & colors */}
        <div className="mt-auto px-5 py-4 border-t border-gray-100 flex items-center justify-between bg-white shrink-0">
            <div className="flex items-center gap-2">
                 <div className="h-8 px-3 rounded-full bg-gray-100 border border-white flex items-center justify-center text-[13px] font-semibold text-gray-600 shadow-sm">
                    {slots.length} Posts
                 </div>
            </div>

            <div className="flex items-center gap-2">
                <button 
                    onClick={(e) => { e.stopPropagation(); setIsFlipped(true); setTempConfig(content.config || defaultConfig); }}
                    className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center active:scale-95"
                >
                    <Settings size={18} />
                </button>
            </div>
        </div>
    </div>
  );

  const renderBack = () => (
    <div className="flex flex-col h-full bg-[#F2F2F7] relative">
        {/* Settings Header - Matches iOS Modal Header style */}
        <div className="px-4 py-3 bg-white border-b border-gray-200 flex items-center justify-between shrink-0">
            <span className="text-[15px] font-semibold text-gray-900">Settings</span>
            <button 
                onClick={(e) => { e.stopPropagation(); handleSaveSettings(); }}
                className="text-[15px] font-semibold text-[#007AFF] hover:opacity-80 transition-opacity"
            >
                Done
            </button>
        </div>

        {/* Settings Form */}
        <div className="p-4 space-y-6 overflow-y-auto flex-1">
            <div className="space-y-1.5">
                <div className="text-[12px] font-medium text-gray-500 uppercase ml-3">Timeframe</div>
                <div className="bg-white rounded-xl overflow-hidden shadow-sm border border-gray-200">
                    <div className="flex items-center justify-between px-4 py-2.5 border-b border-gray-100">
                        <span className="text-[15px] text-gray-900">Month</span>
                        <div className="relative">
                            <select 
                                className="appearance-none bg-transparent text-[15px] text-gray-500 focus:ring-0 border-none pr-6 cursor-pointer text-right"
                                value={tempConfig.month}
                                onChange={e => setTempConfig({...tempConfig, month: parseInt(e.target.value)})}
                            >
                                {MONTHS.map((m, i) => <option key={i} value={i}>{m}</option>)}
                            </select>
                            <ChevronRight size={14} className="absolute right-0 top-1/2 -translate-y-1/2 text-gray-300 pointer-events-none" />
                        </div>
                    </div>
                    <div className="flex items-center justify-between px-4 py-2.5">
                        <span className="text-[15px] text-gray-900">Year</span>
                        <input 
                            type="number"
                            className="text-[15px] text-gray-500 bg-transparent border-none focus:ring-0 text-right w-20 p-0"
