                    <button 
                        className={`flex-1 py-1.5 text-[13px] font-semibold rounded-lg transition-all ${tempConfig.logicType === 'count' ? 'bg-white text-gray-900 shadow-sm' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
