import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { BaseCard } from './BaseCard';
import { CardData, TaskList, TaskItem, MediaItem, Comment } from '../../types';
import { 
  FileImage, Paperclip, MessageSquare, Plus, Trash2, 
  Link as LinkIcon, Image as ImageIcon, X, Send, UserPlus, Pencil, Video, Maximize2, Download,
  HardDrive, Loader2, Check, ExternalLink, AlertCircle, ChevronLeft, ChevronRight
} from 'lucide-react';

interface PostCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  isLinked: boolean;
  viewMode: 'edit' | 'comments';
  onChangeViewMode: (mode: 'edit' | 'comments') => void;
  onEdit: (card: CardData) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  card, 
  isSelected, 
  onSelect, 
  onMove, 
  onDelete,
  isLinked,
  viewMode,
  onChangeViewMode,
  onEdit
}) => {
  const [position, setPosition] = useState({ x: card.x, y: card.y });
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const cardRef = useRef<HTMLDivElement>(null);
  const [isCollapsed, setIsCollapsed] = useState(isLinked && !isSelected);

  useEffect(() => {
    setIsCollapsed(isLinked && !isSelected);
  }, [isLinked, isSelected]);

