import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { BaseCard } from './BaseCard';
import { CardData, TaskList, TaskItem, MediaItem, Comment } from '../../types';
import { 
  FileImage, Paperclip, MessageSquare, Plus, Trash2, 
  Link as LinkIcon, Image as ImageIcon, X, Send, UserPlus, Pencil, Video, Maximize2, Download,
  HardDrive, Loader2, Check, ExternalLink, AlertCircle, ChevronLeft, ChevronRight
} from 'lucide-react';

interface PostCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  isLinked?: boolean;
}

// --- Helper Components ---

interface MediaPreviewOverlayProps {
  initialItem: MediaItem;
  items: MediaItem[];
  onClose: () => void;
}

const MediaPreviewOverlay: React.FC<MediaPreviewOverlayProps> = ({ initialItem, items, onClose }) => {
  const [currentItem, setCurrentItem] = useState(initialItem);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'ArrowLeft') navigate(-1);
      if (e.key === 'ArrowRight') navigate(1);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentItem, items, onClose]);

  // Scroll active thumbnail into view
  useEffect(() => {
    if (scrollRef.current) {
        const index = items.findIndex(i => i.id === currentItem.id);
        if (index !== -1) {
            const thumbnail = scrollRef.current.children[index] as HTMLElement;
            if (thumbnail) {
                thumbnail.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
            }
        }
    }
  }, [currentItem]);

  const navigate = (direction: number) => {
    const currentIndex = items.findIndex(i => i.id === currentItem.id);
    if (currentIndex === -1) return;

    const newIndex = currentIndex + direction;
    if (newIndex >= 0 && newIndex < items.length) {
      setCurrentItem(items[newIndex]);
    }
  };

  if (!currentItem || currentItem.type === 'empty') return null;

  return createPortal(
    <div 
      className="fixed inset-0 z-[9999] flex items-center justify-center bg-white/95 backdrop-blur-xl animate-in fade-in duration-200"
      onClick={onClose}
    >
        {/* Navigation Arrows */}
        <button 
            onClick={(e) => { e.stopPropagation(); navigate(-1); }}
            className="absolute left-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/10 hover:bg-black/5 text-gray-500 hover:text-black transition-all disabled:opacity-30 z-20"
            disabled={items.indexOf(currentItem) === 0}
        >
            <ChevronLeft size={32} />
        </button>
        <button 
            onClick={(e) => { e.stopPropagation(); navigate(1); }}
            className="absolute right-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/10 hover:bg-black/5 text-gray-500 hover:text-black transition-all disabled:opacity-30 z-20"
            disabled={items.indexOf(currentItem) === items.length - 1}
        >
            <ChevronRight size={32} />
        </button>

      <div 
        className="relative w-full h-full flex flex-col items-center justify-center pb-20"
        onClick={e => e.stopPropagation()}
      >
        <div className="relative rounded-2xl overflow-hidden shadow-2xl ring-1 ring-black/10 bg-white max-h-[70vh] max-w-[85vw] flex items-center justify-center">
          {currentItem.type === 'image' && (
            <img src={currentItem.url} alt="Preview" className="max-w-full max-h-[70vh] object-contain" />
          )}
          {currentItem.type === 'video' && (
            <video src={currentItem.url} controls autoPlay className="max-w-full max-h-[70vh] object-contain" />
          )}
          {currentItem.type === 'link' && (
            <div className="w-[600px] h-[400px] flex flex-col items-center justify-center bg-gray-50 text-gray-500">
              <LinkIcon size={64} className="mb-4 opacity-20" />
              <p className="text-lg font-medium">{currentItem.url}</p>
            </div>
          )}
        </div>

        {/* Bottom Bar: Thumbnails + Actions */}
        <div className="absolute bottom-8 flex items-center gap-3 animate-in slide-in-from-bottom-4 duration-300 max-w-[90vw]">

            {/* 1. Thumbnail Strip */}
            <div 
                className="bg-white/80 backdrop-blur-md p-1.5 rounded-2xl border border-gray-200 shadow-lg overflow-x-auto no-scrollbar flex gap-2 max-w-[60vw]"
                ref={scrollRef}
                onClick={(e) => e.stopPropagation()}
            >
                {items.map((item) => (
                    <button
                        key={item.id}
                        onClick={() => setCurrentItem(item)}
                        className={`
                            relative w-10 h-10 rounded-lg overflow-hidden flex-shrink-0 transition-all
                            ${item.id === currentItem.id ? 'ring-2 ring-black ring-offset-1 opacity-100 scale-100' : 'opacity-50 hover:opacity-100 hover:scale-105'}
                        `}
                    >
                        {item.type === 'image' && <img src={item.url} className="w-full h-full object-cover" />}
                        {item.type === 'video' && (
                            <div className="w-full h-full bg-black flex items-center justify-center">
                                <Video size={14} className="text-white" />
                            </div>
                        )}
                        {item.type === 'link' && (
                            <div className="w-full h-full bg-blue-50 flex items-center justify-center text-blue-500">
                                <LinkIcon size={14} />
                            </div>
                        )}
                    </button>
                ))}
            </div>

            {/* 2. Download Pill */}
            {currentItem.url && (
             <a 
               href={currentItem.url} 
               download 
               onClick={(e) => e.stopPropagation()}
               className="h-12 px-6 rounded-full bg-black text-white shadow-lg border border-gray-800 font-medium hover:scale-105 active:scale-95 transition-all flex items-center gap-2 whitespace-nowrap"
             >
               <Download size={16} />
               <span className="text-[14px]">Download</span>
             </a>
           )}

            {/* 3. Close Circle */}
           <button 
             onClick={onClose}
             className="w-12 h-12 rounded-full bg-white text-gray-900 shadow-lg border border-gray-200 flex items-center justify-center hover:bg-gray-50 hover:scale-105 active:scale-95 transition-all flex-shrink-0"
           >
             <X size={20} />
           </button>

        </div>
      </div>
    </div>,
    document.body
  );
};

interface AddMediaButtonProps {
  onFilesSelected: (files: File[]) => void;
}

const AddMediaButton: React.FC<AddMediaButtonProps> = ({ onFilesSelected }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
    if (e.dataTransfer.files.length > 0) {
      onFilesSelected(Array.from(e.dataTransfer.files));
    }
  };

  return (
    <button
      onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
      onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); setIsDragOver(true); }}
      onDragLeave={(e) => { e.preventDefault(); e.stopPropagation(); setIsDragOver(false); }}
      onDrop={handleDrop}
      className={`
        aspect-square rounded-xl border border-dashed flex items-center justify-center transition-all duration-200 no-drag relative group
        ${isDragOver ? 'border-[#007AFF] bg-blue-50' : 'bg-white border-gray-300 hover:border-[#007AFF] hover:bg-gray-50'}
      `}
    >
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        multiple 
        accept="image/*,video/*"
        onChange={(e) => {
          if (e.target.files && e.target.files.length > 0) {
            onFilesSelected(Array.from(e.target.files));
          }
          e.target.value = '';
        }}
      />
      <Plus size={24} className={`transition-colors ${isDragOver ? 'text-[#007AFF]' : 'text-gray-400 group-hover:text-[#007AFF]'}`} />
    </button>
  );
};

interface MediaCubeProps {
  item: MediaItem;
  index: number;
  listType: 'references' | 'finalAssets';
  onRemove: () => void;
  onUpdate: (i: MediaItem) => void;
  onFilesSelected: (files: File[]) => void;
  onPreview: () => void;
  onDropItem: (dragIndex: number, hoverIndex: number, listType: 'references' | 'finalAssets') => void;
}

const MediaCube: React.FC<MediaCubeProps> = ({ 
  item, 
  index, 
  listType,
  onRemove, 
  onUpdate, 
  onFilesSelected, 
  onPreview,
  onDropItem
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDragStart = (e: React.DragEvent) => {
    e.stopPropagation();
    e.dataTransfer.setData('application/json', JSON.stringify({ index, listType }));
    e.dataTransfer.effectAllowed = 'move';

    // Create a drag image
    const dragGhost = document.createElement('div');
    dragGhost.style.width = '40px';
    dragGhost.style.height = '40px';
    dragGhost.style.backgroundColor = '#007AFF';
    dragGhost.style.borderRadius = '8px';
    document.body.appendChild(dragGhost);
    e.dataTransfer.setDragImage(dragGhost, 20, 20);
    setTimeout(() => document.body.removeChild(dragGhost), 0);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);

    const dataStr = e.dataTransfer.getData('application/json');
    if (dataStr) {
      const data = JSON.parse(dataStr);
      if (data.listType === listType) {
        onDropItem(data.index, index, listType);
      }
    } else if (e.dataTransfer.files.length > 0) {
      onFilesSelected(Array.from(e.dataTransfer.files));
    }
  };

  return (
    <div 
      className={`
        aspect-square relative group rounded-xl overflow-hidden transition-all duration-300
        bg-white shadow-sm ring-1 ring-black/5
        ${isDragOver ? 'scale-105 ring-2 ring-blue-500 z-10' : ''}
        no-drag cursor-pointer
      `}
      draggable
      onDragStart={handleDragStart}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={(e) => {
        e.stopPropagation();
        onPreview();
      }}
    >
      {item.type === 'image' && <img src={item.url} alt="asset" className="w-full h-full object-cover select-none pointer-events-none" />}
      {item.type === 'video' && (
        <div className="w-full h-full bg-black flex items-center justify-center relative select-none pointer-events-none">
            <video src={item.url} className="w-full h-full object-cover opacity-80" />
            <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-8 h-8 rounded-full bg-white/30 backdrop-blur-md flex items-center justify-center">
                <Video size={14} className="text-white fill-white" />
                </div>
            </div>
        </div>
      )}
      {item.type === 'link' && <div className="w-full h-full flex items-center justify-center bg-blue-50 text-[#007AFF]"><LinkIcon size={20}/></div>}

      {/* Hover Actions */}
      <div className={`absolute inset-0 bg-black/0 transition-colors duration-200 ${isHovered ? 'bg-black/10' : ''}`}>
          {isHovered && (
            <div className="absolute top-1.5 right-1.5 flex gap-1 animate-in fade-in duration-200">
                <button 
                onClick={(e) => { e.stopPropagation(); onRemove(); }}
                className="w-6 h-6 flex items-center justify-center bg-white/90 backdrop-blur-md rounded-full text-red-500 hover:scale-110 transition-transform shadow-sm"
                >
                <Trash2 size={10} />
                </button>
            </div>
          )}
          {isHovered && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="w-8 h-8 rounded-full bg-white/30 backdrop-blur-md flex items-center justify-center text-white drop-shadow-md">
                <Maximize2 size={14} />
                </div>
            </div>
          )}
      </div>
    </div>
  );
};

interface TaskListBlockProps {
  list: TaskList;
  onUpdate: (l: TaskList) => void;
  onDelete: () => void;
}

const TaskListBlock: React.FC<TaskListBlockProps> = ({ list, onUpdate, onDelete }) => {
  const [newItemText, setNewItemText] = useState("");

  const addItem = () => {
    if (!newItemText.trim()) return;
    const newItem: TaskItem = { id: Date.now().toString(), text: newItemText, done: false };
    onUpdate({ ...list, items: [...list.items, newItem] });
    setNewItemText("");
  };

  const toggleItem = (itemId: string) => {
    const updatedItems = list.items.map(i => i.id === itemId ? { ...i, done: !i.done } : i);
    onUpdate({ ...list, items: updatedItems });
  };

  const deleteItem = (itemId: string) => {
    onUpdate({ ...list, items: list.items.filter(i => i.id !== itemId) });
  };

  return (
    <div className="mb-4 no-drag cursor-auto">
      <div className="flex items-center justify-between mb-2">
        <input 
          value={list.title}
          onChange={(e) => onUpdate({ ...list, title: e.target.value })}
          className="bg-transparent text-[13px] font-semibold text-gray-400 uppercase tracking-wide border-none focus:ring-0 p-0 w-full"
          placeholder="List Name"
        />
        <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className="text-gray-300 hover:text-red-500 transition-colors">
          <Trash2 size={12}/>
        </button>
      </div>

      <div className="space-y-0.5">
        {list.items.map(item => (
          <div key={item.id} className="flex items-start gap-3 group py-1.5 border-b border-gray-50 last:border-0">
            <button 
              onClick={(e) => { e.stopPropagation(); toggleItem(item.id); }}
              className={`mt-0.5 w-5 h-5 rounded-full border flex items-center justify-center transition-all ${item.done ? 'bg-[#007AFF] border-[#007AFF]' : 'bg-transparent border-gray-300'}`}
            >
              {item.done && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
            </button>
            <div className="flex-1 min-w-0">
               <input 
                  value={item.text}
                  onChange={(e) => {
                    const updated = list.items.map(i => i.id === item.id ? { ...i, text: e.target.value } : i);
                    onUpdate({ ...list, items: updated });
                  }}
                  className={`bg-transparent text-[15px] leading-6 w-full border-none focus:ring-0 p-0 text-gray-900 ${item.done ? 'text-gray-400' : ''}`}
                />
            </div>
            <button onClick={(e) => { e.stopPropagation(); deleteItem(item.id); }} className="opacity-0 group-hover:opacity-100 text-gray-300 hover:text-red-500">
               <X size={14} />
            </button>
          </div>
        ))}
        <div className="flex items-center gap-3 mt-1.5 pl-0.5 opacity-60 hover:opacity-100 transition-opacity">
           <Plus size={16} className="text-gray-400"/>
           <input 
             value={newItemText}
             onChange={(e) => setNewItemText(e.target.value)}
             onKeyDown={(e) => { if(e.key === 'Enter') addItem(); }}
             placeholder="Add Item"
             className="bg-transparent text-[15px] border-none focus:ring-0 p-0 placeholder-gray-400"
           />
        </div>
      </div>
    </div>
  );
};

// --- Drive Sync Button Component ---

interface DriveSyncButtonProps {
  sku: string;
  title: string;
  hasAssets: boolean;
  isSynced: boolean;
  driveUrl?: string;
  onSync: () => Promise<void>;
}

const DriveSyncButton: React.FC<DriveSyncButtonProps> = ({ sku, title, hasAssets, isSynced, driveUrl, onSync }) => {
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [showToast, setShowToast] = useState(false);

  const handleClick = async (e: React.MouseEvent) => {
    e.stopPropagation();

    // Safety check
    if (!hasAssets) {
      setStatus('error');
      setTimeout(() => setStatus('idle'), 2000);
      return;
    }

    if (e.shiftKey && driveUrl) {
      window.open(driveUrl, '_blank');
      return;
    }

    setStatus('loading');
    try {
      await onSync();
      setStatus('success');
      setShowToast(true);
      setTimeout(() => {
        setStatus('idle');
        setShowToast(false);
      }, 2500);
    } catch (err) {
      setStatus('error');
      setTimeout(() => setStatus('idle'), 3000);
    }
  };

  const getIcon = () => {
    switch (status) {
      case 'loading': return <Loader2 size={18} className="animate-spin text-blue-600" />;
      case 'success': return <Check size={18} className="text-green-500" />;
      case 'error': return <AlertCircle size={18} className="text-red-500" />;
      default: return <HardDrive size={18} className={isSynced ? "text-[#007AFF]" : "text-gray-400 group-hover:text-gray-600"} />;
    }
  };

  return (
    <div className="relative flex items-center">
      {/* Toast Notification */}
      {showToast && (
        <div className="absolute bottom-full mb-3 left-1/2 -translate-x-1/2 whitespace-nowrap bg-gray-900 text-white text-[13px] font-medium px-3 py-1.5 rounded-lg shadow-xl animate-in fade-in slide-in-from-bottom-2">
          Assets Synced to Drive
        </div>
      )}

      {/* Main Button */}
      <button 
        onClick={handleClick}
        disabled={status === 'loading'}
        className={`
          group w-9 h-9 rounded-full flex items-center justify-center transition-all duration-200
          ${isSynced ? 'bg-blue-50 hover:bg-blue-100' : 'bg-[#F2F2F7] hover:bg-gray-200'}
          ${status === 'error' ? 'bg-red-50 ring-2 ring-red-100' : ''}
        `}
        title={hasAssets ? (isSynced ? "Sync updates to Drive (Shift+Click to open)" : "Sync Final Assets to Drive") : "No assets to sync"}
      >
        {getIcon()}
      </button>

      {/* External Link Shortcut (Visible on hover if synced) */}
      {isSynced && status === 'idle' && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            if (driveUrl) window.open(driveUrl, '_blank');
          }}
          className="absolute -right-3 -top-2 w-5 h-5 bg-white rounded-full shadow-md border border-gray-100 flex items-center justify-center text-gray-400 hover:text-[#007AFF] opacity-0 group-hover:opacity-100 transition-opacity"
        >
          <ExternalLink size={10} />
        </button>
      )}
    </div>
  );
};

