import React, { useRef, useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Position, GridPlannerContent } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';
import { GridPlannerCard } from './cards/GridPlannerCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
}

// Layout constants matching GridPlannerCard Visuals
// Offset = BaseCard Header (~50px) + GridPlanner Internal Header (~82px)
const GRID_HEADER_HEIGHT = 132; 
const GRID_PADDING = 20;
const GRID_GAP = 8;

export const Canvas: React.FC<CanvasProps> = ({ cards, onCardsChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);

  // Dragging Logic for Snapping
  const [draggingCardId, setDraggingCardId] = useState<string | null>(null);
  const [hoveredGridId, setHoveredGridId] = useState<string | null>(null);
  const [hoveredSlotIndex, setHoveredSlotIndex] = useState<number | null>(null);

  // --- Infinite Background Logic ---
  const gridLayers = useMemo(() => {
    const layers = [];
    const baseSpacing = 40; // The fundamental grid unit in world space

    // Determine the "base power" of the current zoom level.
    const logScale = Math.log10(scale);
    const currentPower = Math.floor(logScale);

    // We render a window of scales around the current power to ensure seamless continuity
    for (let i = -1; i <= 1; i++) {
      const power = -currentPower + i; 
      const worldSpacing = baseSpacing * Math.pow(10, power);
      const visualSpacing = worldSpacing * scale;

      // Revised Opacity Curve for Smoothness
      let rawOpacity = 0;

      if (visualSpacing >= 15 && visualSpacing <= 250) {
        if (visualSpacing < 50) {
           rawOpacity = (visualSpacing - 15) / 35;
        } else if (visualSpacing > 100) {
           rawOpacity = 1 - (visualSpacing - 100) / 150;
        } else {
           rawOpacity = 1;
        }
      }

      // Clamp and Dampen
      const finalOpacity = Math.max(0, Math.min(1, rawOpacity)) * 0.3;

      if (finalOpacity > 0.01) {
        layers.push({
          spacing: visualSpacing,
          opacity: finalOpacity,
          key: `grid-layer-${power}`
        });
      }
    }
    return layers;
  }, [scale]);

  const handleWheel = (e: WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const s = Math.exp(-e.deltaY * 0.005);
      setScale(prev => Math.min(Math.max(0.05, prev * s), 10)); 
    } else {
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button === 0 || e.button === 1) {
      setIsPanning(true);
      setLastMousePos({ x: e.clientX, y: e.clientY });
      setSelectedCardId(null); 
    }
  };

  // Helper to generate slots based on grid config
  const generateGridSlots = (gridCard: CardData): Date[] => {
      const content = gridCard.content as GridPlannerContent;
      const defaultConfig = { month: new Date().getMonth(), year: new Date().getFullYear(), logicType: 'frequency', value: 3 };
      const { month, year, logicType, value } = content.config || defaultConfig;

      const daysInMonth = new Date(year, month + 1, 0).getDate();
      const generatedSlots: Date[] = [];

      if (logicType === 'frequency') {
          const step = Math.max(1, value);
          for (let d = 1; d <= daysInMonth; d += step) {
              generatedSlots.push(new Date(year, month, d));
          }
      } else {
          const count = Math.max(1, Math.min(value, daysInMonth));
          const step = daysInMonth / count;
          for (let i = 0; i < count; i++) {
              const day = Math.floor(1 + (i * step));
              generatedSlots.push(new Date(year, month, day));
          }
      }
      return generatedSlots;
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    // 1. Pan Canvas
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
      return;
    }

    // 2. Drag Collision Detection (Snapping Logic)
    if (draggingCardId) {
      const draggedCard = cards.find(c => c.id === draggingCardId);
      if (draggedCard && draggedCard.type === CardType.POST) {
        // Find if we are hovering over any GRID_PLANNER
        const mouseXWorld = (e.clientX - pan.x) / scale;
        const mouseYWorld = (e.clientY - pan.y) / scale;

        let foundGridId: string | null = null;
        let foundSlotIndex: number | null = null;

        for (const card of cards) {
          if (card.type === CardType.GRID_PLANNER) {
            // Check bounding box
            if (
              mouseXWorld >= card.x && 
              mouseXWorld <= card.x + card.width &&
              mouseYWorld >= card.y && 
              mouseYWorld <= card.y + card.height
            ) {
              foundGridId = card.id;

              const contentWidth = card.width - (GRID_PADDING * 2);
              const colWidth = (contentWidth - (2 * GRID_GAP)) / 3;
              const rowHeight = colWidth * 1.25; // 4:5 aspect ratio

              // Relative position inside the card's "grid area"
              // Adjust relative Y for combined headers (BaseCard + GridPlanner headers)
              const relativeX = mouseXWorld - (card.x + GRID_PADDING);
              const relativeY = mouseYWorld - (card.y + GRID_HEADER_HEIGHT);

              if (relativeX >= 0 && relativeY >= 0) {
                 const col = Math.floor(relativeX / (colWidth + GRID_GAP));
                 const row = Math.floor(relativeY / (rowHeight + GRID_GAP));

                 const slots = generateGridSlots(card);
                 const totalSlots = slots.length;
                 const visualIndex = (row * 3) + col;

                 // Inverted Feed Logic: Visual index 0 (top-left) maps to the last logical index (latest date).
                 // logicalIndex = (totalSlots - 1) - visualIndex
                 if (col >= 0 && col < 3 && row >= 0 && visualIndex < totalSlots) {
                   foundSlotIndex = (totalSlots - 1) - visualIndex;
                 }
              }
              break; // Found the top-most grid
            }
          }
        }

        setHoveredGridId(foundGridId);
        setHoveredSlotIndex(foundSlotIndex);
      }
    }
  };

  const handleMouseUp = () => {
    // Logic for Dropping a Post Card onto a Grid Slot
    if (draggingCardId && hoveredGridId && hoveredSlotIndex !== null) {
      const grid = cards.find(c => c.id === hoveredGridId);
      const post = cards.find(c => c.id === draggingCardId);

      if (grid && post) {
        const slots = generateGridSlots(grid);
        let slotDateStr = "";

        // Only assign if the slot index actually exists in the generated logic
        if (hoveredSlotIndex < slots.length) {
            // YYYY-MM-DD format for input[type="date"]
            const d = slots[hoveredSlotIndex];
            // Adjust for local timezone to ensure YYYY-MM-DD is correct
            const offset = d.getTimezoneOffset();
            const localDate = new Date(d.getTime() - (offset*60*1000));
            slotDateStr = localDate.toISOString().split('T')[0];
        }

        // 2. Update Cards
        const newCards = cards.map(c => {
          if (c.id === hoveredGridId) {
            // Link Post to Grid Slot
            return {
              ...c,
              content: {
                ...c.content,
                connections: {
                  ...c.content.connections,
                  [hoveredSlotIndex]: draggingCardId
                }
              }
            };
          }
          if (c.id === draggingCardId) {
            // Update Post Date
            return {
              ...c,
              content: {
                ...c.content,
                date: slotDateStr // Apply the calculated date
              }
            };
          }
          return c;
        });

        onCardsChange(newCards);
      }
    }

    setIsPanning(false);
    setDraggingCardId(null);
    setHoveredGridId(null);
    setHoveredSlotIndex(null);
  };

  const handleLinkPost = (gridId: string, slotIndex: number, postId: string) => {
    const grid = cards.find(c => c.id === gridId);
    if (!grid) return;

    const slots = generateGridSlots(grid);
    let slotDateStr = "";
    if (slotIndex < slots.length) {
        const d = slots[slotIndex];
        const offset = d.getTimezoneOffset();
        const localDate = new Date(d.getTime() - (offset*60*1000));
        slotDateStr = localDate.toISOString().split('T')[0];
    }

    const newCards = cards.map(c => {
        if (c.id === gridId) {
            return {
                ...c,
                content: {
                    ...c.content,
                    connections: {
                        ...c.content.connections,
                        [slotIndex]: postId
                    }
                }
            };
        }
        if (c.id === postId) {
            return {
                ...c,
                content: {
                    ...c.content,
                    date: slotDateStr
                }
            };
        }
        return c;
    });
    onCardsChange(newCards);
  };

  // --- CRUD Handlers ---

  const updateCardPosition = (id: string, x: number, y: number) => {
    // This runs on every frame of drag, so we hook into it to track dragging state
    if (draggingCardId !== id) setDraggingCardId(id);
    onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
  };

  const updateCardSize = (id: string, width: number, height: number) => {
     // Prevent redundant updates
     const c = cards.find(x => x.id === id);
     if (c && (Math.abs(c.width - width) > 1 || Math.abs(c.height - height) > 1)) {
        onCardsChange(cards.map(card => card.id === id ? { ...card, width, height } : card));
     }
  };

  const updateCardContent = (id: string, content: any) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, content } : c));
  };

  const handleDeleteCard = (id: string) => {
    onCardsChange(cards.filter(c => c.id !== id));
    if (selectedCardId === id) setSelectedCardId(null);
  };

  const handleUnlink = (gridId: string, slotIndex: number, postCardId: string) => {
    onCardsChange(cards.map(c => {
      if (c.id === gridId) {
        const newConnections = { ...c.content.connections };
        delete newConnections[slotIndex];
        return { ...c, content: { ...c.content, connections: newConnections }};
      }
      return c;
    }));
  };

  const bringToFront = (id: string) => {
    setSelectedCardId(id);
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!selectedCardId) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) return;
      if (e.key === 'Delete' || e.key === 'Backspace') handleDeleteCard(selectedCardId);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardId, cards]);

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardId === card.id,
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        // Check if this post is linked to ANY Grid Planner
        const isLinked = cards.some(c => 
          c.type === CardType.GRID_PLANNER && 
          Object.values((c.content as GridPlannerContent).connections || {}).includes(card.id)
        );
        return <PostCard {...commonProps} isLinked={isLinked} />;

      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      case CardType.GRID_PLANNER:
        return (
          <GridPlannerCard 
            {...commonProps} 
            allCards={cards}
            onUpdateContent={updateCardContent}
            onUnlink={handleUnlink}
            onLinkPost={handleLinkPost}
            onResize={updateCardSize}
            hoveredSlotIndex={hoveredGridId === card.id ? hoveredSlotIndex : null}
          />
        );
      default:
        return <PostCard {...commonProps} />;
    }
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#f3f4f6] relative overflow-hidden cursor-grab active:cursor-grabbing"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* 
        Multi-Layer Infinite Grid 
        Renders overlapping grid layers based on zoom level.
      */}
      {gridLayers.map((layer) => (
        <div 
          key={layer.key}
          className="absolute inset-0 pointer-events-none"
          style={{
            // Use visual spacing for background size
            backgroundSize: `${layer.spacing}px ${layer.spacing}px`,
            // Pan directly maps to screen pixels, aligning all layers
            backgroundPosition: `${pan.x}px ${pan.y}px`,
            // Dot is always 1.5px screen size. Use subtle gray with calculated opacity.
            backgroundImage: `radial-gradient(circle, rgba(156, 163, 175, ${layer.opacity}) 1.5px, transparent 1.5px)`,
            opacity: 1 
          }}
        />
      ))}

      {/* World Transform Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
        }}
      >
        {cards.map(renderCard)}
      </div>

      {/* Scale Indicator */}
      <div className="absolute bottom-6 right-6 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-mono border border-gray-200 shadow-sm pointer-events-none text-gray-500">
        {Math.round(scale * 100)}%
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, CardType, GridConfig, GridPlannerContent, MediaItem } from '../../types';
import { Settings, X, LayoutGrid, ChevronRight, Calendar, Check, Minus, Plus, Link, FileImage } from 'lucide-react';

interface GridPlannerCardProps {
  card: CardData;
  allCards: CardData[];
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onUnlink: (gridId: string, slotIndex: number, postCardId: string) => void;
  onLinkPost: (gridId: string, slotIndex: number, postId: string) => void;
  onResize?: (id: string, width: number, height: number) => void;
  hoveredSlotIndex?: number | null;
  zoomScale: number;
}

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June', 
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const GridPlannerCard: React.FC<GridPlannerCardProps> = (props) => {
  const { card, allCards, onUpdateContent, onUnlink, onLinkPost, hoveredSlotIndex, onResize } = props;
  const content = card.content as GridPlannerContent;

  const [isFlipped, setIsFlipped] = useState(false);
  const [linkingSlotIndex, setLinkingSlotIndex] = useState<number | null>(null);

  const defaultConfig: GridConfig = {
    month: new Date().getMonth(),
    year: new Date().getFullYear(),
    logicType: 'frequency',
    value: 3
  };

  const [tempConfig, setTempConfig] = useState<GridConfig>(content.config || defaultConfig);

  useEffect(() => {
    if (!content.config) {
      onUpdateContent(card.id, {
        ...content,
        title: "Feed Planner",
        connections: {},
        config: defaultConfig
      });
    }
  }, []);

  const handleSaveSettings = () => {
    onUpdateContent(card.id, { ...content, config: tempConfig });
    setIsFlipped(false);
  };

  const availablePosts = useMemo(() => {
    const connectedPostIds = Object.values(content.connections || {});
    return allCards.filter(c => 
        c.type === CardType.POST && 
        !connectedPostIds.includes(c.id)
    );
  }, [allCards, content.connections]);

  const slots = useMemo(() => {
    const { month, year, logicType, value } = content.config || tempConfig;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const generatedSlots: { date: Date; label: string; index: number }[] = [];

    if (logicType === 'frequency') {
      const step = Math.max(1, value);
      for (let d = 1; d <= daysInMonth; d += step) {
        generatedSlots.push({
          date: new Date(year, month, d),
          label: `${d}`, 
          index: generatedSlots.length
        });
      }
    } else {
      const count = Math.max(1, Math.min(value, daysInMonth));
      const step = daysInMonth / count;
      for (let i = 0; i < count; i++) {
        const day = Math.floor(1 + (i * step));
        generatedSlots.push({
          date: new Date(year, month, day),
          label: `${day}`,
          index: i
        });
      }
    }
    return generatedSlots;
  }, [content.config, tempConfig]);

  // Display slots in reverse order (latest date first) for Instagram-style feed
  const displaySlots = useMemo(() => [...slots].reverse(), [slots]);

  // Dynamic Height Calculation
  useEffect(() => {
    if (!onResize) return;

    const colCount = 3;
    const gap = 12; // gap-3
    const paddingX = 40; // px-5 * 2
    const availableWidth = card.width - paddingX;
    const colWidth = (availableWidth - (gap * (colCount - 1))) / colCount;
    const rowHeight = colWidth * (5/4); // aspect 4/5

    const rowCount = Math.ceil(slots.length / colCount);

    // Height Breakdown:
    // BaseCard Header: ~52px (approx 20+20+8+padding)
    // Grid Top Padding: 16px (pt-4)
    // Grid Bottom Padding: 8px (pb-2)
    // Grid Row Content: rowCount * rowHeight
    // Grid Gaps: (rowCount - 1) * gap
    // Footer: 69px (border 1 + padding 32 + height 36)

    const headerHeight = 52;
    const footerHeight = 69;
    const containerPadding = 24;
    const gridGaps = Math.max(0, rowCount - 1) * gap;
    const gridContent = rowCount * rowHeight;
    const buffer = 10; // little extra breathing room

    const totalHeight = headerHeight + containerPadding + gridContent + gridGaps + footerHeight + buffer;

    // Ensure we don't shrink below a usable size for the Settings view
    const minHeight = 500;
    const finalHeight = Math.max(minHeight, totalHeight);

    if (Math.abs(card.height - finalHeight) > 1) {
        onResize(card.id, card.width, finalHeight);
    }
  }, [slots.length, card.width, card.height, onResize]);

  const renderFront = () => (
    <div className="flex flex-col h-full bg-white relative">
        {/* Grid Scroll Area */}
        <div className="flex-1 overflow-y-auto px-5 pt-4 pb-2 no-scrollbar min-h-0 relative">
            <div className="grid grid-cols-3 gap-3 auto-rows-min pb-4">
                {displaySlots.map((slot) => {
                // Use slot.index (logical index) for lookups
                const connectedCardId = content.connections?.[slot.index];
                const connectedCard = connectedCardId ? allCards.find(c => c.id === connectedCardId) : null;

                let previewMedia: MediaItem | undefined;
                if (connectedCard && connectedCard.content.finalAssets?.length > 0) {
                    previewMedia = connectedCard.content.finalAssets[0];
                }

                const isHovered = hoveredSlotIndex === slot.index;

                return (
                    <div 
                    key={slot.index}
                    className={`
                        aspect-[4/5] rounded-xl relative group transition-all duration-200 ease-out
                        ${connectedCard 
                            ? 'bg-white shadow-sm ring-1 ring-black/5' 
                            : 'bg-white border border-dashed border-gray-300 hover:border-[#007AFF] hover:bg-blue-50'
                        }
                        ${isHovered ? 'ring-2 ring-[#007AFF] border-transparent scale-[1.02] z-20 shadow-lg' : ''}
                    `}
                    >
                        {connectedCard ? (
                            <>
                                {previewMedia?.type === 'image' && (
                                    <img src={previewMedia.url} className="w-full h-full object-cover rounded-xl select-none pointer-events-none" />
                                )}
                                {previewMedia?.type === 'video' && (
                                    <video src={previewMedia.url} className="w-full h-full object-cover rounded-xl select-none pointer-events-none" />
                                )}
                                {!previewMedia && (
                                    <div className="w-full h-full flex flex-col items-center justify-center p-2 text-center bg-gray-50 rounded-xl">
                                        <LayoutGrid size={20} className="text-gray-300 mb-1" />
                                        <span className="text-[9px] font-semibold text-gray-500 line-clamp-2 leading-tight">
                                            {connectedCard.content.title || "Untitled"}
                                        </span>
                                    </div>
                                )}

                                <div className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onUnlink(card.id, slot.index, connectedCard.id); }}
                                        className="w-5 h-5 bg-white/90 backdrop-blur rounded-full text-red-500 shadow-sm flex items-center justify-center hover:scale-110 active:scale-95 transition-transform"
                                    >
                                        <X size={10} strokeWidth={3} />
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="w-full h-full flex flex-col items-center justify-center">
                                {/* Link Button */}
                                <button 
                                    onClick={(e) => { e.stopPropagation(); setLinkingSlotIndex(slot.index); }}
                                    className="w-8 h-8 rounded-full bg-white border border-gray-200 shadow-sm flex items-center justify-center text-gray-400 hover:text-[#007AFF] hover:scale-110 active:scale-95 transition-all"
                                    title="Link to existing post"
                                >
                                    <Link size={14} />
                                </button>

                                {isHovered && <div className="absolute bottom-2 text-[#007AFF] font-bold text-[10px] animate-pulse pointer-events-none">DROP</div>}
                            </div>
                        )}

                        <div className={`
                            absolute top-1 left-1 px-1.5 py-0.5 rounded-md text-[9px] font-bold tracking-tight shadow-sm pointer-events-none
                            ${connectedCard ? 'bg-black/60 text-white backdrop-blur-md' : 'bg-white text-gray-400 ring-1 ring-black/5'}
                        `}>
                            {slot.label}
                        </div>
                    </div>
                );
                })}
            </div>

            {/* Post Selection Overlay */}
            {linkingSlotIndex !== null && (
                <div className="absolute inset-0 bg-white/95 backdrop-blur-sm z-30 animate-in fade-in duration-200 flex flex-col p-4">
                    <div className="flex items-center justify-between mb-4">
                        <span className="text-[13px] font-semibold text-gray-900">
                             Link Post to {slots[linkingSlotIndex]?.date.getDate()}, {MONTHS[slots[linkingSlotIndex]?.date.getMonth()]} Slot
                        </span>
                        <button 
                            onClick={() => setLinkingSlotIndex(null)}
                            className="w-6 h-6 rounded-full bg-gray-100 flex items-center justify-center text-gray-500 hover:text-gray-900 hover:bg-gray-200"
                        >
                            <X size={14} />
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto space-y-2 no-scrollbar">
                        {availablePosts.length === 0 ? (
                            <div className="h-32 flex flex-col items-center justify-center text-gray-400 text-center">
                                <FileImage size={24} className="mb-2 opacity-30" />
                                <span className="text-[12px]">No unlinked posts found on the board.</span>
                            </div>
                        ) : (
                            availablePosts.map(post => (
                                <button
                                    key={post.id}
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        onLinkPost(card.id, linkingSlotIndex, post.id);
                                        setLinkingSlotIndex(null);
                                    }}
                                    className="w-full p-3 rounded-xl border border-gray-100 bg-white hover:border-blue-200 hover:bg-blue-50 transition-all flex items-center gap-3 group text-left shadow-sm"
                                >
                                    <div className="w-10 h-10 rounded-lg bg-gray-100 flex-shrink-0 flex items-center justify-center text-gray-400 overflow-hidden">
                                        {post.content.finalAssets?.[0]?.url ? (
                                            post.content.finalAssets[0].type === 'image' ? (
                                                <img src={post.content.finalAssets[0].url} className="w-full h-full object-cover" />
                                            ) : (
                                                <video src={post.content.finalAssets[0].url} className="w-full h-full object-cover" />
                                            )
                                        ) : (
                                            <FileImage size={16} />
                                        )}
                                    </div>
                                    <div className="min-w-0">
                                        <div className="text-[13px] font-semibold text-gray-900 truncate group-hover:text-blue-600">
                                            {post.content.title || "Untitled Post"}
                                        </div>
                                        <div className="text-[11px] text-gray-400 truncate">
                                            {post.content.sku || "No SKU"}
                                        </div>
                                    </div>
                                    <div className="ml-auto opacity-0 group-hover:opacity-100 text-blue-500 transition-opacity">
                                        <Check size={16} />
                                    </div>
                                </button>
                            ))
                        )}
                    </div>
                </div>
            )}
        </div>

        {/* Footer / Action Bar */}
        <div className="mt-auto px-5 py-4 border-t border-gray-100 flex items-center justify-between bg-white shrink-0">
            <div className="flex items-center gap-2">
                 <div className="h-8 px-3 rounded-full bg-gray-100 border border-white flex items-center justify-center text-[13px] font-semibold text-gray-600 shadow-sm gap-2">
                    <Calendar size={13} className="text-gray-400"/>
                    <span className="uppercase tracking-wide">{MONTHS[content.config?.month || 0]} {content.config?.year}</span>
                 </div>

                 <div className="h-8 px-3 rounded-full bg-gray-100 border border-white flex items-center justify-center text-[13px] font-semibold text-gray-600 shadow-sm">
                    {slots.length} Posts
                 </div>
            </div>

            <div className="flex items-center gap-2">
                <button 
                    onClick={(e) => { e.stopPropagation(); setIsFlipped(true); setTempConfig(content.config || defaultConfig); }}
                    className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center active:scale-95"
                >
                    <Settings size={18} />
                </button>
            </div>
        </div>
    </div>
  );

  const renderBack = () => (
    <div className="flex flex-col h-full bg-white relative">
        {/* Settings Form */}
        <div className="flex-1 overflow-y-auto px-5 py-6 space-y-8 no-scrollbar">

            {/* Timeframe Section */}
            <div>
                <span className="text-[13px] font-semibold text-gray-400 block mb-3 uppercase tracking-wide">Timeframe</span>
                <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-1">
                        <label className="text-[11px] font-medium text-gray-400 ml-1">Month</label>
                        <div className="relative">
                            <select 
                                className="w-full bg-gray-50 border-none rounded-xl py-2.5 px-3 text-[14px] font-semibold text-gray-900 outline-none focus:ring-2 focus:ring-blue-100 appearance-none cursor-pointer"
                                value={tempConfig.month}
                                onChange={e => setTempConfig({...tempConfig, month: parseInt(e.target.value)})}
                            >
                                {MONTHS.map((m, i) => <option key={i} value={i}>{m}</option>)}
                            </select>
                            <ChevronRight size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                        </div>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[11px] font-medium text-gray-400 ml-1">Year</label>
                        <input 
                            type="number"
                            className="w-full bg-gray-50 border-none rounded-xl py-2.5 px-3 text-[14px] font-semibold text-gray-900 outline-none focus:ring-2 focus:ring-blue-100 placeholder-gray-400"
                            value={tempConfig.year}
                            onChange={e => setTempConfig({...tempConfig, year: parseInt(e.target.value)})}
                        />
                    </div>
                </div>
            </div>

            {/* Cadence Section */}
            <div>
                <span className="text-[13px] font-semibold text-gray-400 block mb-3 uppercase tracking-wide">Cadence</span>

                {/* Switcher */}
                <div className="bg-gray-100 p-1 rounded-xl flex mb-4">
                    <button 
                        className={`flex-1 py-1.5 text-[13px] font-semibold rounded-lg transition-all ${tempConfig.logicType === 'frequency' ? 'bg-white text-gray-900 shadow-sm' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
                        onClick={() => setTempConfig({...tempConfig, logicType: 'frequency'})}
                    >
                        Frequency
                    </button>
                    <button 
                        className={`flex-1 py-1.5 text-[13px] font-semibold rounded-lg transition-all ${tempConfig.logicType === 'count' ? 'bg-white text-gray-900 shadow-sm' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
                        onClick={() => setTempConfig({...tempConfig, logicType: 'count'})}
                    >
                        Total Count
                    </button>
                </div>

                {/* Counter Control */}
                <div className="flex items-center justify-between p-1">
                    <span className="text-[15px] font-medium text-gray-700">
                         {tempConfig.logicType === 'frequency' ? 'Every X Days' : 'Total Posts'}
                    </span>
                    <div className="flex items-center gap-3">
                        <button 
                            className="w-8 h-8 rounded-full bg-gray-50 border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-100 active:scale-95 transition-all"
                            onClick={() => setTempConfig({...tempConfig, value: Math.max(1, tempConfig.value - 1)})}
                        >
                            <Minus size={14} strokeWidth={2.5} />
                        </button>
                        <span className="w-8 text-center font-bold text-[17px] text-gray-900 tabular-nums">{tempConfig.value}</span>
                        <button 
                            className="w-8 h-8 rounded-full bg-gray-50 border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-100 active:scale-95 transition-all"
                            onClick={() => setTempConfig({...tempConfig, value: tempConfig.value + 1})}
                        >
                            <Plus size={14} strokeWidth={2.5} />
                        </button>
                    </div>
                </div>
                 <p className="text-[12px] text-gray-400 mt-3 leading-relaxed border-t border-gray-50 pt-3">
                    {tempConfig.logicType === 'frequency' 
                        ? `This will automatically create a post slot every ${tempConfig.value} days starting from the 1st.` 
                        : `This will distribute ${tempConfig.value} post slots evenly across the selected month.`}
                </p>
            </div>
        </div>

        {/* Footer / Action Bar (Identical to Front) */}
        <div className="mt-auto px-5 py-4 border-t border-gray-100 flex items-center justify-between bg-white shrink-0">
             {/* Left - Status */}
             <div className="flex items-center gap-2">
                 <div className="w-2 h-2 rounded-full bg-green-500"></div>
                 <span className="text-[13px] font-medium text-gray-400">Changes Saved</span>
             </div>

            {/* Right - Toggle Button (Flip Back) */}
            <div className="flex items-center gap-2">
                <button 
                    onClick={(e) => { e.stopPropagation(); handleSaveSettings(); }}
                    className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center active:scale-95"
                >
                    <LayoutGrid size={18} />
                </button>
            </div>
        </div>
    </div>
  );

  return (
    <BaseCard 
      {...props} 
      title={content.title || "Feed Planner"} 
      icon={<LayoutGrid size={16} className="text-[#007AFF]"/>}
    >
      <div 
        className="relative w-full h-full group/card"
        style={{ perspective: '1000px' }}
      >
        <div 
          className="w-full h-full transition-transform duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] relative"
          style={{ 
            transformStyle: 'preserve-3d',
            transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)' 
          }}
        >
          {/* Front Face */}
          <div 
            className="absolute inset-0 w-full h-full"
            style={{ backfaceVisibility: 'hidden' }}
          >
             {renderFront()}
          </div>

          {/* Back Face */}
          <div 
            className="absolute inset-0 w-full h-full"
            style={{ 
              transform: 'rotateY(180deg)',
              backfaceVisibility: 'hidden' 
            }}
          >
             {renderBack()}
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

import React, { useState, useEffect } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Search,
  X,
  ChevronDown,
  Check,
  Globe,
  MessageSquare,
  HardDrive,
  LayoutGrid
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'My Board',
    color: '#007AFF',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      // Position: centered horizontally relative to button, above the button
      setColorPickerState({
        id,
        x: rect.left + rect.width / 2,
        y: rect.top
      });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : (type === CardType.GRID_PLANNER ? 320 : 360),
      height: type === CardType.GRID_PLANNER ? 500 : 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  // --- Menu Data Configuration ---

  const frequentTools = [
    { 
      id: 'ai', 
      label: 'Ask AI', 
      desc: 'Prompt an AI language model', 
      icon: <Sparkles size={24} />, 
      iconColor: 'text-pink-600',
      bg: 'bg-pink-50',
      action: () => addCard(CardType.STRATEGY_AI)
    },
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create social content', 
      icon: <FileImage size={24} />, 
      iconColor: 'text-purple-600',
      bg: 'bg-purple-50',
      action: () => addCard(CardType.POST)
    },
    { 
      id: 'grid', 
      label: 'Feed Planner', 
      desc: 'Visual monthly calendar', 
      icon: <LayoutGrid size={24} />, 
      iconColor: 'text-blue-600',
      bg: 'bg-blue-50',
      action: () => addCard(CardType.GRID_PLANNER)
    },
  ];

  const integrationTools = [
    { 
      id: 'analytics', 
      label: 'Analytics', 
      desc: 'Visualize live performance data', 
      icon: <BarChart2 size={20} />, 
      color: 'bg-emerald-100 text-emerald-600',
      tag: 'DATA',
      action: () => addCard(CardType.ANALYTICS)
    },
    { 
      id: 'persona', 
      label: 'Persona', 
      desc: 'Target audience profile card', 
      icon: <Users size={20} />, 
      color: 'bg-orange-100 text-orange-600',
      tag: 'STRATEGY',
      action: () => addCard(CardType.PERSONA)
    },
    // Mock Integrations for visual completeness
    { id: 'drive', label: 'Google Drive', desc: 'Manage files in Drive', icon: <HardDrive size={20} />, color: 'bg-blue-100 text-blue-600', tag: 'MCP', action: () => {} },
    { id: 'slack', label: 'Slack', desc: 'Send channel messages', icon: <MessageSquare size={20} />, color: 'bg-purple-100 text-purple-600', tag: 'MCP', action: () => {} },
    { id: 'web', label: 'Browser', desc: 'Embed web content', icon: <Globe size={20} />, color: 'bg-gray-100 text-gray-600', tag: 'MCP', action: () => {} },
  ];

  const filterItem = (item: any) => 
    item.label.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.desc.toLowerCase().includes(searchTerm.toLowerCase());

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Main Canvas Area */}
