                                        <div className="text-[11px] text-gray-400 truncate">
                                            {post.content.sku || "No SKU"}
                                        </div>
                                    </div>
                                    <div className="ml-auto opacity-0 group-hover:opacity-100 text-blue-500 transition-opacity">
                                        <Check size={16} />
                                    </div>
                                </button>
                            ))
                        )}
                    </div>
                </div>
            )}
        </div>

        {/* Footer / Action Bar */}
        <div className="mt-auto px-5 py-4 border-t border-gray-100 flex items-center justify-between bg-white shrink-0">
            <div className="flex items-center gap-2">
                 <div className="h-8 px-3 rounded-full bg-gray-100 border border-white flex items-center justify-center text-[13px] font-semibold text-gray-600 shadow-sm gap-2">
                    <Calendar size={13} className="text-gray-400"/>
                    <span className="uppercase tracking-wide">{MONTHS[content.config?.month || 0]} {content.config?.year}</span>
                 </div>

                 <div className="h-8 px-3 rounded-full bg-gray-100 border border-white flex items-center justify-center text-[13px] font-semibold text-gray-600 shadow-sm">
                    {slots.length} Posts
                 </div>
            </div>

            <div className="flex items-center gap-2">
                <button 
                    onClick={(e) => { e.stopPropagation(); setTempConfig(content.config || defaultConfig); setViewMode('settings'); }}
                    className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center active:scale-95"
                >
                    <Settings size={18} />
                </button>
            </div>
        </div>
    </div>
  );

  const renderSettingsView = () => (
    <div className="flex flex-col h-full bg-white relative animate-in slide-in-from-right-8 duration-300 ease-out">
        {/* Settings Form */}
        <div className="flex-1 overflow-y-auto px-5 py-6 space-y-8 no-scrollbar">

            {/* Timeframe Section */}
            <div>
                <span className="text-[13px] font-semibold text-gray-400 block mb-3 uppercase tracking-wide">Timeframe</span>
                <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-1">
                        <label className="text-[11px] font-medium text-gray-400 ml-1">Month</label>
                        <div className="relative">
                            <select 
                                className="w-full bg-gray-50 border-none rounded-xl py-2.5 px-3 text-[14px] font-semibold text-gray-900 outline-none focus:ring-2 focus:ring-blue-100 appearance-none cursor-pointer"
                                value={tempConfig.month}
                                onChange={e => setTempConfig({...tempConfig, month: parseInt(e.target.value)})}
                            >
                                {MONTHS.map((m, i) => <option key={i} value={i}>{m}</option>)}
                            </select>
                            <ChevronRight size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                        </div>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[11px] font-medium text-gray-400 ml-1">Year</label>
                        <input 
                            type="number"
                            className="w-full bg-gray-50 border-none rounded-xl py-2.5 px-3 text-[14px] font-semibold text-gray-900 outline-none focus:ring-2 focus:ring-blue-100 placeholder-gray-400"
                            value={tempConfig.year}
                            onChange={e => setTempConfig({...tempConfig, year: parseInt(e.target.value)})}
                        />
                    </div>
                </div>
            </div>

            {/* Cadence Section */}
            <div>
                <span className="text-[13px] font-semibold text-gray-400 block mb-3 uppercase tracking-wide">Cadence</span>

                {/* Switcher */}
                <div className="bg-gray-100 p-1 rounded-xl flex mb-4">
                    <button 
                        className={`flex-1 py-1.5 text-[13px] font-semibold rounded-lg transition-all ${tempConfig.logicType === 'frequency' ? 'bg-white text-gray-900 shadow-sm' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
                        onClick={() => setTempConfig({...tempConfig, logicType: 'frequency'})}
                    >
                        Frequency
                    </button>
                    <button 
                        className={`flex-1 py-1.5 text-[13px] font-semibold rounded-lg transition-all ${tempConfig.logicType === 'count' ? 'bg-white text-gray-900 shadow-sm' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
                        onClick={() => setTempConfig({...tempConfig, logicType: 'count'})}
                    >
                        Total Count
                    </button>
                </div>

                {/* Counter Control */}
                <div className="flex items-center justify-between p-1">
                    <span className="text-[15px] font-medium text-gray-700">
                         {tempConfig.logicType === 'frequency' ? 'Every X Days' : 'Total Posts'}
                    </span>
                    <div className="flex items-center gap-3">
                        <button 
                            className="w-8 h-8 rounded-full bg-gray-50 border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-100 active:scale-95 transition-all"
                            onClick={() => setTempConfig({...tempConfig, value: Math.max(1, tempConfig.value - 1)})}
                        >
                            <Minus size={14} strokeWidth={2.5} />
                        </button>
                        <span className="w-8 text-center font-bold text-[17px] text-gray-900 tabular-nums">{tempConfig.value}</span>
                        <button 
                            className="w-8 h-8 rounded-full bg-gray-50 border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-100 active:scale-95 transition-all"
                            onClick={() => setTempConfig({...tempConfig, value: tempConfig.value + 1})}
                        >
                            <Plus size={14} strokeWidth={2.5} />
                        </button>
                    </div>
                </div>
                 <p className="text-[12px] text-gray-400 mt-3 leading-relaxed border-t border-gray-50 pt-3">
                    {tempConfig.logicType === 'frequency' 
                        ? `This will automatically create a post slot every ${tempConfig.value} days starting from the 1st.` 
                        : `This will distribute ${tempConfig.value} post slots evenly across the selected month.`}
                </p>
            </div>
        </div>

        {/* Footer / Action Bar (Identical to Front) */}
        <div className="mt-auto px-5 py-4 border-t border-gray-100 flex items-center justify-between bg-white shrink-0">
             {/* Left - Status */}
             <div className="flex items-center gap-2">
                 <div className="w-2 h-2 rounded-full bg-green-500"></div>
                 <span className="text-[13px] font-medium text-gray-400">Changes Saved</span>
             </div>

            {/* Right - Toggle Button (Back) */}
            <div className="flex items-center gap-2">
                <button 
                    onClick={(e) => { e.stopPropagation(); handleSaveSettings(); }}
                    className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center active:scale-95"
                >
                    <LayoutGrid size={18} />
                </button>
            </div>
        </div>
    </div>
  );

  return (
    <BaseCard 
      {...props} 
      title={content.title || "Feed Planner"} 
      icon={<LayoutGrid size={16} className="text-[#007AFF]"/>}
    >
      {viewMode === 'grid' ? renderGridView() : renderSettingsView()}
    </BaseCard>
  );
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateMarketingStrategy = async (
  topic: string, 
  audience: string, 
  tone: string
): Promise<string> => {
  try {
    const prompt = `
      Act as a world-class creative director. 
      I need 5 distinct marketing hooks/angles for the following context:
      Topic/Product: ${topic}
      Target Audience: ${audience}
      Tone: ${tone}

      Format the output as a clean HTML list (<ul><li>...</li></ul>) without markdown backticks. 
      Keep each hook punchy and under 20 words.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Failed to generate strategy. Please try again.";
  }
};

import React, { useState, useEffect } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Search,
  X,
  ChevronDown,
  Check,
  Globe,
  MessageSquare,
  HardDrive,
  LayoutGrid
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'My Board',
    color: '#007AFF',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      // Position: centered horizontally relative to button, above the button
      setColorPickerState({
        id,
        x: rect.left + rect.width / 2,
        y: rect.top
      });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : (type === CardType.GRID_PLANNER ? 320 : 360),
      height: type === CardType.GRID_PLANNER ? 500 : 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  // --- Menu Data Configuration ---

  const frequentTools = [
    { 
      id: 'ai', 
      label: 'Ask AI', 
      desc: 'Prompt an AI language model', 
      icon: <Sparkles size={24} />, 
      iconColor: 'text-pink-600',
      bg: 'bg-pink-50',
      action: () => addCard(CardType.STRATEGY_AI)
    },
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create social content', 
      icon: <FileImage size={24} />, 
      iconColor: 'text-purple-600',
      bg: 'bg-purple-50',
      action: () => addCard(CardType.POST)
    },
    { 
      id: 'grid', 
      label: 'Feed Planner', 
      desc: 'Visual monthly calendar', 
      icon: <LayoutGrid size={24} />, 
      iconColor: 'text-blue-600',
      bg: 'bg-blue-50',
      action: () => addCard(CardType.GRID_PLANNER)
    },
  ];

  const integrationTools = [
    { 
      id: 'analytics', 
      label: 'Analytics', 
      desc: 'Visualize live performance data', 
      icon: <BarChart2 size={20} />, 
      color: 'bg-emerald-100 text-emerald-600',
      tag: 'DATA',
      action: () => addCard(CardType.ANALYTICS)
    },
    { 
      id: 'persona', 
      label: 'Persona', 
      desc: 'Target audience profile card', 
      icon: <Users size={20} />, 
      color: 'bg-orange-100 text-orange-600',
      tag: 'STRATEGY',
      action: () => addCard(CardType.PERSONA)
    },
    // Mock Integrations for visual completeness
    { id: 'drive', label: 'Google Drive', desc: 'Manage files in Drive', icon: <HardDrive size={20} />, color: 'bg-blue-100 text-blue-600', tag: 'MCP', action: () => {} },
    { id: 'slack', label: 'Slack', desc: 'Send channel messages', icon: <MessageSquare size={20} />, color: 'bg-purple-100 text-purple-600', tag: 'MCP', action: () => {} },
    { id: 'web', label: 'Browser', desc: 'Embed web content', icon: <Globe size={20} />, color: 'bg-gray-100 text-gray-600', tag: 'MCP', action: () => {} },
  ];

  const filterItem = (item: any) => 
    item.label.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.desc.toLowerCase().includes(searchTerm.toLowerCase());

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Main Canvas Area */}
      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />
      </div>

      {/* Trigger Zone (Top Left) with Auto-Open on Hover */}
      <div 
        className={`fixed top-0 left-0 z-40 w-32 h-32 flex items-start justify-start p-6 transition-all duration-300 ${isDrawerOpen ? '-translate-x-full opacity-0 pointer-events-none' : 'translate-x-0 opacity-100'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
      >
        <button 
          onClick={() => setIsDrawerOpen(true)}
          className="relative w-14 h-14 rounded-full group transition-all duration-500 hover:scale-110 active:scale-95 shadow-2xl"
        >
           {/* Shimmering Perimeter - Rotating Light Beam */}
           <div className="absolute -inset-[2px] rounded-full overflow-hidden z-0">
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300%] h-[300%] bg-[conic-gradient(from_0deg,transparent_0_340deg,rgba(255,255,255,1)_360deg)] animate-[spin_4s_linear_infinite] opacity-60" />
           </div>

           {/* Liquid Glass Body */}
           <div className="absolute inset-[1px] rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-md border border-white/60 flex items-center justify-center z-10 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9)]">
              <Plus size={26} strokeWidth={1} className="text-gray-600 group-hover:text-gray-900 transition-colors duration-300" />
           </div>
        </button>
      </div>

      {/* Side Drawer Overlay (Left Side) - Auto close on mouse leave */}
      <div 
        className={`fixed inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`}
        onMouseLeave={() => setIsDrawerOpen(false)}
      >

        {/* Drawer Content */}
        <div className="w-[340px] h-full bg-white shadow-2xl flex flex-col border-r border-gray-200">

          {/* Header & Search */}
          <div className="p-5 border-b border-gray-100 bg-white z-10">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                autoFocus={isDrawerOpen}
                type="text" 
                placeholder="Search all nodes" 
                className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2.5 text-[15px] focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none placeholder-gray-400"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          {/* Scrollable List */}
          <div className="flex-1 overflow-y-auto overflow-x-hidden">
            <div className="p-5 space-y-8">

              {/* Frequently Used Section */}
              {(!searchTerm || frequentTools.some(filterItem)) && (
                <div className="space-y-3">
                  <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Frequently Used</h3>
                  <div className="grid grid-cols-2 gap-3">
                    {frequentTools.filter(filterItem).map(tool => (
                      <button 
                        key={tool.id}
                        onClick={tool.action}
                        className="flex flex-col items-start p-4 rounded-2xl bg-white border border-gray-200 hover:border-gray-300 hover:shadow-md transition-all active:scale-[0.98] text-left group"
                      >
                        <div className={`w-10 h-10 rounded-xl ${tool.bg} ${tool.iconColor} flex items-center justify-center mb-3 group-hover:scale-110 transition-transform`}>
                          {tool.icon}
                        </div>
