        </div>
      </div>

      {/* Fixed Color Picker Menu */}
      {colorPickerState && (
        <div 
          onClick={(e) => e.stopPropagation()}
          className="fixed bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] grid grid-cols-4 gap-2 w-36 animate-in fade-in zoom-in-95 duration-200 z-[100]"
          style={{
            left: colorPickerState.x,
            top: colorPickerState.y - 12,
            transform: 'translate(-50%, -100%)' // Center horizontally, place above
