                            value={date}
                            onChange={(e) => setDate(e.target.value)}
                            onClick={(e) => e.stopPropagation()}
                        />

                        {isLinked && (
                            <div className="flex items-center gap-1.5 px-2 py-1 bg-[#007AFF]/10 text-[#007AFF] rounded-md border border-[#007AFF]/20 animate-in fade-in zoom-in-95 select-none">
                                <LinkIcon size={10} strokeWidth={2.5} />
                                <span className="text-[10px] font-bold tracking-tight">SYNCED</span>
                            </div>
                        )}
                    </div>
                  </div>

                  {/* References */}
                  <div>
                    <div className="flex items-center justify-between mb-3">
                      <span className="text-[13px] font-semibold text-gray-400">References</span>
                    </div>
