                  {/* Checklists */}
                  <div>
                    {taskLists.map(list => (
                        <TaskListBlock 
                          key={list.id} 
                          list={list} 
                          onUpdate={(updated) => setTaskLists(taskLists.map(l => l.id === list.id ? updated : l))}
                          onDelete={() => setTaskLists(taskLists.filter(l => l.id !== list.id))}
