                    <UserPlus size={14} />
                  </button>
                </div>

                {/* Right: Tools (Drive + Comments) */}
                <div className="flex items-center gap-2">
                  {/* Drive Integration */}
                  <DriveSyncButton 
                      sku={sku}
                      title={title}
