                      onClick={(e) => { e.stopPropagation(); setViewMode('comments'); }}
                      className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center relative"
                    >
                      <MessageSquare size={18} />
