const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);
export const auth = getAuth(app);
const googleProvider = new GoogleAuthProvider();

// --- AUTH FUNCTIONS ---

export const signInWithGoogle = async () => {
  try {
    await signInWithPopup(auth, googleProvider);
  } catch (error) {
    console.error("Error signing in with Google", error);
    throw error;
  }
};

export const logout = async () => {
  try {
    await firebaseSignOut(auth);
  } catch (error) {
    console.error("Error signing out", error);
  }
};

// --- DATABASE FUNCTIONS (USER SCOPED) ---

const getUserDocRef = (userId: string) => doc(db, "users", userId);

export const saveWorkspacesToFirestore = async (userId: string, workspaces: Workspace[]) => {
  if (!userId) return;
  try {
    const docRef = getUserDocRef(userId);
    // Merge true allows us to save other user preferences later without overwriting
    await setDoc(docRef, { workspaces, lastUpdated: new Date().toISOString() }, { merge: true });
    console.log("Saved to Firebase for user:", userId);
  } catch (e) {
    console.error("Error adding document: ", e);
  }
};

export const loadWorkspacesFromFirestore = async (userId: string): Promise<Workspace[] | null> => {
  if (!userId) return null;
  try {
    const docRef = getUserDocRef(userId);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists() && docSnap.data().workspaces) {
      return docSnap.data().workspaces as Workspace[];
    } else {
      return null;
    }
  } catch (e) {
    console.error("Error loading document: ", e);
    return null;
  }
};

