import React, { useState } from 'react';
import { BaseCard } from './BaseCard';
import { CardData } from '../../types';
import { Sparkles, Bot, Loader2, ArrowRight } from 'lucide-react';
import { Button } from '../ui/button';
import { generateMarketingStrategy } from '../../services/geminiService';

interface AiStrategyCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
}

export const AiStrategyCard: React.FC<AiStrategyCardProps> = (props) => {
  const [topic, setTopic] = useState("");
  const [audience, setAudience] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!topic) return;
    setLoading(true);
    const strategy = await generateMarketingStrategy(topic, audience, "Professional yet punchy");
    setResult(strategy);
    setLoading(false);
  };

  return (
    <BaseCard {...props} title="Oracle AI" icon={<Sparkles size={16} className="text-indigo-500"/>}>
      <div className="space-y-6">
        <div className="bg-[#F2F2F7] p-4 rounded-2xl">
          <p className="text-[13px] font-semibold text-indigo-600 mb-3">Input Parameters</p>
          <div className="space-y-3">
            <input 
              className="w-full text-[15px] bg-white px-3 py-2.5 rounded-xl border-none shadow-sm focus:ring-2 focus:ring-indigo-100 transition-shadow placeholder-gray-400" 
              placeholder="What are we promoting?"
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
            />
            <input 
              className="w-full text-[15px] bg-white px-3 py-2.5 rounded-xl border-none shadow-sm focus:ring-2 focus:ring-indigo-100 transition-shadow placeholder-gray-400" 
              placeholder="Target Audience?"
              value={audience}
              onChange={(e) => setAudience(e.target.value)}
            />
            <button 
              className="w-full bg-indigo-500 hover:bg-indigo-600 text-white font-medium py-2.5 rounded-xl flex items-center justify-center gap-2 active:scale-[0.98] transition-all shadow-sm"
              onClick={handleGenerate}
              disabled={loading || !topic}
            >
              {loading ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
              <span>Generate Ideas</span>
            </button>
          </div>
        </div>

        {result && (
          <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
             <div className="text-[13px] font-semibold text-gray-400 mb-3">Results</div>
             <div 
               className="text-[15px] leading-relaxed text-gray-800 space-y-2 prose prose-p:my-1 prose-ul:my-2 prose-li:my-0.5"
               dangerouslySetInnerHTML={{ __html: result }}
             />
             <Button variant="ghost" size="sm" className="w-full mt-4 text-gray-400 hover:text-gray-600" onClick={() => setResult(null)}>
               Clear Results
             </Button>
          </div>
        )}
      </div>
    </BaseCard>
  );
};

